/* Auto-generated from assets/dashboard.html — run: npm run sync:html */
export const DASHBOARD_HTML = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>All-in-One Dashboard</title>\n<style>\n  :root{\n    --primary:#FFCD3C; --primary-dark:#F5B700; --bg:#F6F6F8; --card:#FFFFFF;\n    --ink:#1A1A1A; --muted:#8A8A8E; --line:#ECECEE; --green:#2E9E5B; --red:#D64545;\n    --radius:16px; --radius-sm:10px; --shadow:0 2px 14px rgba(20,20,20,0.07);\n  }\n  *{box-sizing:border-box;}\n  body{margin:0;font-family:-apple-system,BlinkMacSystemFont,\"Segoe UI\",Roboto,Helvetica,Arial,sans-serif;background:var(--bg);color:var(--ink);transition:background .2s ease,color .2s ease;}\n  button,input,select,textarea{font-family:inherit;}\n  a{color:inherit;}\n  ::-webkit-scrollbar{width:8px;height:8px;}\n  ::-webkit-scrollbar-thumb{background:var(--line);border-radius:8px;}\n\n  /* ---------- TOPBAR ---------- */\n  #topbar{\n    display:flex;align-items:center;justify-content:space-between;\n    padding:14px 32px;background:var(--card);border-bottom:1px solid var(--line);\n    position:sticky;top:0;z-index:50;\n  }\n  .tb-left{display:flex;align-items:center;gap:10px;cursor:pointer;font-weight:800;font-size:18px;}\n  .tb-logo{width:34px;height:34px;border-radius:10px;background:var(--primary);display:flex;align-items:center;justify-content:center;font-size:17px;}\n  .tb-right{display:flex;gap:10px;}\n  .tb-btn{background:none;border:1.5px solid var(--line);padding:9px 16px;border-radius:9px;font-weight:700;font-size:13.5px;color:var(--ink);}\n  .tb-btn:hover{border-color:var(--primary-dark);}\n  .tb-btn.admin-btn{background:var(--ink);color:var(--primary);border-color:var(--ink);}\n\n  #app-root{padding:0;min-height:calc(100vh - 64px);}\n  .view{display:none;}\n  .view.active{display:block;}\n\n  /* ---------- DASHBOARD ---------- */\n  .dash-wrap{max-width:1000px;margin:0 auto;padding:60px 24px;text-align:center;}\n  .dash-wrap h1{font-size:30px;font-weight:800;margin-bottom:6px;}\n  .dash-wrap p.sub{color:var(--muted);margin-bottom:44px;font-size:15px;}\n  .dash-cards{display:flex;gap:28px;justify-content:center;flex-wrap:wrap;}\n  .dash-card{\n    width:300px;max-width:100%;padding:36px 28px;border-radius:20px;background:var(--card);box-shadow:var(--shadow);\n    cursor:pointer;border:1.5px solid var(--line);transition:transform .15s ease, box-shadow .15s ease;text-align:left;\n  }\n  .dash-card:hover{transform:translateY(-4px);box-shadow:0 8px 26px rgba(20,20,20,0.12);border-color:var(--primary);}\n  .dash-card .dc-ic{width:52px;height:52px;border-radius:14px;background:var(--primary);display:flex;align-items:center;justify-content:center;font-size:26px;margin-bottom:18px;}\n  .dash-card h2{margin:0 0 6px 0;font-size:19px;font-weight:800;}\n  .dash-card p{margin:0;color:var(--muted);font-size:13.5px;line-height:1.5;}\n  .dash-empty{max-width:520px;margin:60px auto;text-align:center;color:var(--muted);}\n\n  .back-btn{background:none;border:none;color:var(--muted);font-weight:700;font-size:14px;padding:14px 28px 0 28px;cursor:pointer;}\n  .back-btn:hover{color:var(--ink);}\n  .sub-title-row{padding:6px 28px 26px 28px;}\n  .sub-title-row h1{margin:0;font-size:24px;font-weight:800;}\n\n  /* ---------- FINANCE SHELL (desktop) ---------- */\n  .fin-shell{display:grid;grid-template-columns:220px 1fr;gap:0;padding:0 28px 40px 28px;max-width:1300px;margin:0 auto;}\n  .fin-sidebar{padding-top:6px;}\n  .fin-nav-btn{\n    display:flex;align-items:center;gap:10px;width:100%;text-align:left;background:none;border:none;\n    padding:12px 14px;border-radius:10px;font-weight:700;font-size:14.5px;color:var(--muted);margin-bottom:4px;\n  }\n  .fin-nav-btn .ic{font-size:17px;}\n  .fin-nav-btn:hover{background:var(--line);}\n  .fin-nav-btn.active{background:var(--primary);color:var(--ink);}\n  .fin-add-btn{\n    width:100%;margin-top:14px;padding:13px 0;border-radius:10px;background:var(--ink);color:var(--primary);\n    border:none;font-weight:800;font-size:14px;\n  }\n  .fin-add-btn:hover{opacity:0.9;}\n  .fin-main{padding-left:26px;border-left:1px solid var(--line);min-height:70vh;}\n\n  .fin-topbar{display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:16px;margin-bottom:22px;}\n  .month-nav{display:flex;align-items:center;gap:10px;font-weight:800;font-size:18px;}\n  .month-nav button{background:var(--card);border:1.5px solid var(--line);width:32px;height:32px;border-radius:50%;font-size:15px;}\n  .stat-pill-row{display:flex;gap:10px;}\n  .stat-pill{background:var(--card);border:1.5px solid var(--line);border-radius:12px;padding:10px 18px;text-align:center;}\n  .stat-pill .lbl{font-size:10.5px;color:var(--muted);font-weight:700;text-transform:uppercase;letter-spacing:.3px;}\n  .stat-pill .val{font-size:16px;font-weight:800;}\n  .fin-tools{display:flex;gap:8px;}\n  .fin-tools button{background:var(--card);border:1.5px solid var(--line);width:36px;height:36px;border-radius:10px;font-size:15px;}\n\n  .card{background:var(--card);border-radius:var(--radius);padding:20px;box-shadow:var(--shadow);margin-bottom:18px;border:1px solid var(--line);}\n  .card-head{display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;}\n  .card-head h3{margin:0;font-size:16px;font-weight:800;}\n  .grid-2{display:grid;grid-template-columns:1fr 1fr;gap:18px;}\n  @media(max-width:900px){ .grid-2{grid-template-columns:1fr;} .fin-shell{grid-template-columns:1fr;} .fin-main{border-left:none;padding-left:0;} }\n\n  .day-group-head{display:flex;justify-content:space-between;padding:14px 4px 6px 4px;color:var(--muted);font-size:12.5px;font-weight:700;}\n  .txn-row{display:flex;align-items:center;gap:14px;background:var(--card);padding:13px 16px;border-bottom:1px solid var(--line);border-radius:10px;margin-bottom:2px;}\n  .txn-row:hover{background:var(--bg);}\n  .cat-circle{width:42px;height:42px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:20px;flex-shrink:0;color:#fff;}\n  .txn-info{flex:1;min-width:0;}\n  .txn-info .cat{font-weight:700;font-size:15px;}\n  .txn-info .note{font-size:12.5px;color:var(--muted);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;}\n  .txn-amt{font-weight:800;font-size:15px;}\n  .txn-amt.expense{color:var(--ink);}\n  .txn-amt.income{color:var(--green);}\n\n  .empty-state{display:flex;flex-direction:column;align-items:center;justify-content:center;padding:70px 30px;color:var(--muted);text-align:center;}\n  .empty-state .em-icon{font-size:48px;margin-bottom:14px;opacity:.5;}\n  .empty-state .em-title{font-weight:700;font-size:16px;color:var(--ink);margin-bottom:4px;}\n\n  .donut-wrap{display:flex;align-items:center;gap:22px;flex-wrap:wrap;}\n  .donut-canvas-holder{position:relative;width:150px;height:150px;flex-shrink:0;}\n  .donut-center{position:absolute;inset:0;display:flex;align-items:center;justify-content:center;font-weight:800;font-size:17px;flex-direction:column;}\n  .donut-center small{font-size:10px;color:var(--muted);font-weight:600;}\n  .legend{flex:1;display:flex;flex-direction:column;gap:9px;min-width:150px;}\n  .legend-item{display:flex;align-items:center;gap:8px;font-size:13px;}\n  .legend-dot{width:10px;height:10px;border-radius:50%;flex-shrink:0;}\n  .legend-item .lname{flex:1;font-weight:600;}\n  .legend-item .lpct{color:var(--muted);font-weight:700;}\n\n  .cat-bar-row{margin-bottom:14px;}\n  .cat-bar-top{display:flex;align-items:center;gap:10px;margin-bottom:6px;}\n  .cat-bar-top .ic{width:30px;height:30px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:14px;color:#fff;flex-shrink:0;}\n  .cat-bar-top .nm{flex:1;font-weight:700;font-size:13.5px;}\n  .cat-bar-top .pc{color:var(--muted);font-size:12.5px;font-weight:600;margin-right:8px;}\n  .cat-bar-top .am{font-weight:800;font-size:13.5px;}\n  .cat-bar-track{height:7px;background:var(--line);border-radius:6px;overflow:hidden;}\n  .cat-bar-fill{height:100%;border-radius:6px;}\n\n  .stat-grid{display:flex;justify-content:space-between;text-align:center;}\n  .stat-grid>div{flex:1;}\n  .stat-grid .lbl{font-size:12px;color:var(--muted);font-weight:600;margin-bottom:4px;}\n  .stat-grid .val{font-size:17px;font-weight:800;}\n  .row-between{display:flex;align-items:center;justify-content:space-between;}\n\n  .acc-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(230px,1fr));gap:16px;}\n  .account-card{display:flex;align-items:center;gap:14px;background:var(--card);border-radius:var(--radius);padding:16px;box-shadow:var(--shadow);border:1px solid var(--line);cursor:pointer;}\n  .account-card:hover{border-color:var(--primary);}\n  .account-card .aic{width:44px;height:44px;border-radius:50%;background:var(--primary);display:flex;align-items:center;justify-content:center;font-size:20px;flex-shrink:0;}\n  .account-card .atxt{flex:1;}\n  .account-card .aname{font-weight:800;font-size:15px;}\n  .account-card .atype{font-size:12px;color:var(--muted);}\n  .account-card .aamt{font-weight:800;font-size:15px;}\n  .add-account-card{display:flex;align-items:center;justify-content:center;border:1.5px dashed var(--line);border-radius:var(--radius);padding:16px;cursor:pointer;color:var(--muted);font-weight:700;}\n  .add-account-card:hover{border-color:var(--primary-dark);color:var(--ink);}\n\n  /* ---------- REMINDERS ---------- */\n  .rem-shell{max-width:900px;margin:0 auto;padding:0 28px 50px 28px;}\n  .rem-form{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:12px;margin-bottom:22px;}\n  .field{margin-bottom:14px;}\n  .field label{display:block;font-size:12px;font-weight:700;color:var(--muted);text-transform:uppercase;letter-spacing:.3px;margin-bottom:6px;}\n  .field input,.field select,.field textarea{width:100%;padding:11px 13px;border-radius:var(--radius-sm);border:1.5px solid var(--line);background:var(--card);font-size:14.5px;color:var(--ink);}\n  .field input:focus,.field select:focus{outline:none;border-color:var(--primary-dark);}\n  .primary-btn{background:var(--ink);color:var(--primary);border:none;padding:13px 22px;border-radius:var(--radius-sm);font-weight:800;font-size:14.5px;cursor:pointer;}\n  .primary-btn:hover{opacity:.9;}\n  .status-on{background:#FBD8D8;color:#8f2b2b;padding:7px 14px;margin:3px;border:none;cursor:pointer;border-radius:8px;font-weight:700;font-size:12.5px;}\n  .status-off{background:#D6F0DF;color:#1f6b3c;padding:7px 14px;margin:3px;border:none;cursor:pointer;border-radius:8px;font-weight:700;font-size:12.5px;}\n  .hidden{display:none;}\n  .day-check-row{display:flex;flex-wrap:wrap;gap:12px;margin:8px 0 16px;font-size:13.5px;}\n  .day-check-row label{display:flex;align-items:center;gap:5px;font-weight:600;}\n  .rem-item{background:var(--card);border:1px solid var(--line);border-radius:12px;padding:14px 16px;margin-bottom:10px;}\n  .rem-item .ri-top{display:flex;justify-content:space-between;align-items:center;}\n  .rem-item .ri-name{font-weight:800;font-size:15px;}\n  .rem-item .ri-meta{font-size:12.5px;color:var(--muted);margin-top:2px;}\n  .rem-item .ri-amt{font-weight:800;font-size:15px;}\n\n  /* ---------- GROCERY EXPIRY REMINDER ---------- */\n  .groc-cat-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(130px,1fr));gap:16px;}\n  .groc-cat-tile{background:var(--card);border:1.5px solid var(--line);border-radius:16px;padding:20px 10px;display:flex;flex-direction:column;align-items:center;gap:10px;cursor:pointer;text-align:center;}\n  .groc-cat-tile:hover{border-color:var(--primary-dark);transform:translateY(-2px);}\n  .groc-cat-tile .gc-img{width:64px;height:64px;border-radius:50%;background:var(--bg);display:flex;align-items:center;justify-content:center;font-size:32px;}\n  .groc-cat-tile .gc-name{font-weight:700;font-size:13.5px;}\n  .groc-cat-tile .gc-count{font-size:11px;color:var(--muted);}\n  .exp-badge{display:inline-block;padding:3px 10px;border-radius:20px;font-size:11px;font-weight:800;}\n  .exp-badge.expired{background:#FBD8D8;color:#8f2b2b;}\n  .exp-badge.soon{background:#FDEBC8;color:#8a5a06;}\n  .exp-badge.fresh{background:#D6F0DF;color:#1f6b3c;}\n  .groc-section-title{font-size:12.5px;font-weight:800;color:var(--muted);text-transform:uppercase;letter-spacing:.4px;margin:20px 0 8px 2px;}\n  .groc-section-title:first-child{margin-top:0;}\n  .rem-actions{display:flex;gap:8px;margin-top:8px;}\n  .icon-x{background:none;border:none;color:var(--muted);font-size:15px;cursor:pointer;}\n  .icon-x:hover{color:var(--red);}\n\n  /* ---------- REMINDER TIMING (default vs customize) ---------- */\n  .segmented{display:flex;border:1.5px solid var(--ink);border-radius:10px;overflow:hidden;}\n  .segmented button, .mode-btn{flex:1;padding:9px 0;background:var(--card);border:none;font-weight:700;font-size:13px;color:var(--ink);cursor:pointer;}\n  .segmented button:not(:last-child), .mode-btn:not(:last-child){border-right:1.5px solid var(--ink);}\n  .segmented button.active, .mode-btn.active{background:var(--primary);color:var(--ink);}\n  .hint-box{background:var(--bg);border:1px dashed var(--line);border-radius:10px;padding:10px 12px;font-size:12.5px;color:var(--muted);margin-bottom:14px;}\n  .mode-tag{display:inline-block;font-size:10.5px;font-weight:800;padding:2px 8px;border-radius:10px;background:#EFE3FF;color:#6B3FA0;margin-left:6px;vertical-align:middle;}\n  .mode-tag.default{background:var(--line);color:var(--muted);}\n  .offset-check-row{display:flex;flex-wrap:wrap;gap:10px;margin:8px 0 14px;font-size:13px;}\n  .offset-check-row label{display:flex;align-items:center;gap:5px;font-weight:600;background:var(--bg);padding:6px 10px;border-radius:8px;}\n\n  /* ---------- LIST TO BUY (shopping list) ---------- */\n  .shop-add-row{display:grid;grid-template-columns:1.6fr 0.9fr 0.8fr 1fr 1.1fr auto;gap:10px;align-items:end;}\n  @media(max-width:900px){ .shop-add-row{grid-template-columns:1fr 1fr; margin-bottom:6px;} }\n  .shop-table{width:100%;border-collapse:collapse;margin-top:6px;}\n  .shop-table th{text-align:left;font-size:11.5px;color:var(--muted);text-transform:uppercase;letter-spacing:.3px;padding:8px 10px;border-bottom:1.5px solid var(--line);}\n  .shop-row td{padding:12px 10px;border-bottom:1px solid var(--line);font-size:14.5px;}\n  .shop-row.bought{background:#E4F6EA;}\n  .shop-row .shop-name{font-weight:700;}\n  .shop-row .shop-bought-btn{width:24px;height:24px;border-radius:6px;border:1.5px solid var(--line);background:var(--card);cursor:pointer;display:inline-flex;align-items:center;justify-content:center;font-size:14px;color:#fff;}\n  .shop-row.bought .shop-bought-btn{background:var(--green);border-color:var(--green);}\n  .shop-linked-tag{font-size:10.5px;font-weight:800;padding:2px 8px;border-radius:10px;background:#FDEBC8;color:#8a5a06;margin-left:6px;}\n  .shop-inline-input{width:100px;padding:6px 8px;border:1.5px solid var(--line);border-radius:7px;background:var(--card);font-size:13px;color:var(--ink);}\n  .shop-act-btn{border:1.5px solid var(--line);background:var(--card);border-radius:8px;padding:6px 9px;font-size:13px;cursor:pointer;white-space:nowrap;}\n  .shop-act-btn.done{background:#E4F6EA;border-color:var(--green);color:#1f6b3c;font-weight:700;}\n\n  /* ---------- PERISHABLE ITEMS (Groceries transactions) ---------- */\n  .perishable-add-row{display:grid;grid-template-columns:1.4fr 1.1fr 1fr auto;gap:8px;margin-bottom:12px;}\n  @media(max-width:640px){ .perishable-add-row{grid-template-columns:1fr 1fr;} }\n  .perishable-add-row input, .perishable-add-row select{padding:10px 11px;border-radius:8px;border:1.5px solid var(--line);background:var(--card);font-size:13.5px;color:var(--ink);}\n  .grocery-item-expiry-row{display:grid;grid-template-columns:1fr auto;gap:8px;align-items:end;}\n  .perishable-chip-list{display:flex;flex-wrap:wrap;gap:8px;}\n  .perishable-chip{display:inline-flex;align-items:center;gap:6px;background:var(--bg);border:1.5px solid var(--line);border-radius:20px;padding:6px 6px 6px 12px;font-size:12.5px;font-weight:600;}\n  .perishable-chip small{color:var(--muted);font-weight:600;}\n  .perishable-chip button{background:none;border:none;color:var(--muted);font-size:13px;cursor:pointer;padding:2px 6px;}\n  .perishable-chip button:hover{color:#D64545;}\n  .perishable-total-box{background:var(--bg);border:1.5px solid var(--line);border-radius:10px;padding:12px 16px;font-size:15px;font-weight:700;text-align:center;}\n  .shop-act-btn:hover{border-color:var(--primary-dark);}\n\n  /* ---------- ADMIN ---------- */\n  .admin-shell{max-width:1000px;margin:0 auto;padding:0 28px 60px 28px;}\n  .admin-grid{display:grid;grid-template-columns:1fr 1fr;gap:20px;}\n  @media(max-width:800px){.admin-grid{grid-template-columns:1fr;}}\n  .toggle-row{display:flex;align-items:center;justify-content:space-between;padding:11px 0;border-bottom:1px solid var(--line);}\n  .toggle-row:last-child{border-bottom:none;}\n  .toggle-row .tr-txt{font-weight:600;font-size:14px;}\n  .toggle-row .tr-sub{font-size:12px;color:var(--muted);}\n  .toggle{position:relative;width:44px;height:25px;background:#e2e2e5;border-radius:20px;border:none;flex-shrink:0;cursor:pointer;}\n  .toggle::after{content:'';position:absolute;top:2px;left:2px;width:21px;height:21px;background:#fff;border-radius:50%;transition:transform .15s ease;box-shadow:0 1px 3px rgba(0,0,0,.3);}\n  .toggle.on{background:var(--primary);}\n  .toggle.on::after{transform:translateX(19px);}\n  .theme-swatches{display:flex;gap:12px;flex-wrap:wrap;}\n  .swatch{width:64px;height:64px;border-radius:14px;cursor:pointer;border:2.5px solid transparent;display:flex;align-items:flex-end;justify-content:center;padding-bottom:6px;font-size:10px;font-weight:800;color:#fff;text-shadow:0 1px 2px rgba(0,0,0,.4);}\n  .swatch.selected{border-color:var(--ink);}\n  .admin-danger{border:1.5px solid var(--red);border-radius:12px;padding:16px;}\n  .admin-danger h4{color:var(--red);margin:0 0 6px 0;}\n  .btn-outline{background:none;border:1.5px solid var(--line);padding:10px 16px;border-radius:var(--radius-sm);font-weight:700;font-size:13.5px;cursor:pointer;}\n  .btn-outline:hover{border-color:var(--primary-dark);}\n  .btn-danger-outline{background:none;border:1.5px solid var(--red);color:var(--red);padding:10px 16px;border-radius:var(--radius-sm);font-weight:700;font-size:13.5px;cursor:pointer;}\n  .btn-danger-outline:hover{background:var(--red);color:#fff;}\n  .admin-actions{display:flex;gap:10px;flex-wrap:wrap;margin-top:8px;}\n  input[type=file]{padding:8px;}\n\n  /* ---------- MODAL (centered dialog for desktop) ---------- */\n  .overlay{position:fixed;inset:0;background:rgba(0,0,0,.45);z-index:200;display:flex;align-items:center;justify-content:center;opacity:0;pointer-events:none;transition:opacity .18s ease;padding:20px;}\n  .overlay.show{opacity:1;pointer-events:auto;}\n  .dialog{background:var(--bg);width:440px;max-width:100%;border-radius:18px;max-height:90vh;overflow-y:auto;transform:scale(.96);transition:transform .18s ease;box-shadow:0 20px 60px rgba(0,0,0,.3);}\n  .overlay.show .dialog{transform:scale(1);}\n  .dialog-header{background:var(--primary);padding:16px 18px;display:flex;align-items:center;justify-content:space-between;position:sticky;top:0;z-index:5;border-radius:18px 18px 0 0;flex-shrink:0;}\n  .dialog-header h2{margin:0;font-size:16.5px;font-weight:800;}\n  .dialog-header .txt-btn{background:none;border:none;font-size:14.5px;font-weight:700;color:var(--ink);cursor:pointer;padding:4px 6px;}\n\n  /* Add Expense/Income/Transfer sheet — keep a stable height so shorter\n     Income/Transfer views don't sink to the bottom of the screen. */\n  .dialog.sheet{display:flex;flex-direction:column;overflow:hidden;min-height:min(680px, 90vh);}\n  .dialog.sheet .kind-tabs{flex-shrink:0;}\n  .dialog.sheet .dialog-scroll{flex:1 1 auto;overflow-y:auto;-webkit-overflow-scrolling:touch;min-height:0;}\n  .transfer-form{padding:16px 16px 8px 16px;}\n\n  .cat-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:16px 6px;padding:18px 14px;}\n  .cat-cell{display:flex;flex-direction:column;align-items:center;gap:6px;background:none;border:none;cursor:pointer;}\n  .cat-cell .cc-ic{width:50px;height:50px;border-radius:50%;background:var(--line);display:flex;align-items:center;justify-content:center;font-size:22px;}\n  .cat-cell .cc-lbl{font-size:11.5px;font-weight:600;text-align:center;color:var(--ink);line-height:1.2;}\n  .cat-cell:hover .cc-ic{outline:2px solid var(--primary-dark);}\n\n  .amount-display{text-align:center;padding:22px 16px 6px 16px;}\n  .amount-display .cat-tag{display:inline-flex;align-items:center;gap:8px;background:var(--card);padding:6px 14px 6px 6px;border-radius:20px;font-weight:700;font-size:13px;margin-bottom:14px;box-shadow:var(--shadow);}\n  .amount-display .cat-tag .tag-ic{width:24px;height:24px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:13px;color:#fff;}\n  .amount-display .num{font-size:38px;font-weight:800;letter-spacing:-1px;word-break:break-all;}\n  .keypad{display:grid;grid-template-columns:repeat(3,1fr);gap:1px;background:var(--line);margin:14px 0 0 0;}\n  .keypad button{background:var(--card);border:none;padding:15px 0;font-size:19px;font-weight:600;color:var(--ink);cursor:pointer;}\n  .keypad button:hover{background:var(--bg);}\n  .keypad button.op{color:var(--primary-dark);font-size:17px;}\n\n  .icon-picker{display:grid;grid-template-columns:repeat(6,1fr);gap:9px;padding:0 16px;}\n  .icon-picker .ip-cell{aspect-ratio:1;border-radius:10px;background:var(--line);display:flex;align-items:center;justify-content:center;font-size:18px;border:none;cursor:pointer;}\n  .icon-picker .ip-cell.selected{background:var(--primary);}\n\n  .save-btn{margin:18px 16px 24px 16px;background:var(--ink);color:var(--primary);border:none;padding:14px 0;border-radius:var(--radius-sm);font-size:15px;font-weight:800;cursor:pointer;width:calc(100% - 32px);}\n  .save-btn:hover{opacity:.9;}\n  .danger-btn{background:#fff;color:var(--red);border:1.5px solid var(--red);}\n  .two-btn{display:flex;gap:10px;margin:18px 16px 24px;}\n  .two-btn button{flex:1;padding:13px 0;border-radius:var(--radius-sm);font-weight:800;font-size:14.5px;border:none;cursor:pointer;}\n  .btn-edit{background:var(--primary);color:var(--ink);}\n  .btn-delete{background:#fff;color:var(--red);border:1.5px solid var(--red) !important;}\n  .detail-row{display:flex;justify-content:space-between;padding:12px 20px;border-bottom:1px solid var(--line);}\n  .detail-row .dk{color:var(--muted);font-size:13.5px;}\n  .detail-row .dv{font-weight:700;font-size:14.5px;}\n  .details-hero{display:flex;flex-direction:column;align-items:center;padding:26px 16px 8px;}\n  .details-hero .dh-ic{width:58px;height:58px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:26px;color:#fff;margin-bottom:8px;}\n  .details-hero .dh-name{font-size:17px;font-weight:800;}\n\n  .cal-grid{display:grid;grid-template-columns:repeat(7,1fr);gap:4px;padding:12px;}\n  .cal-dow{text-align:center;font-size:11px;font-weight:700;color:var(--muted);padding-bottom:4px;}\n  .cal-cell{aspect-ratio:1;border-radius:8px;background:var(--bg);display:flex;flex-direction:column;align-items:center;justify-content:center;font-size:13px;font-weight:600;border:none;cursor:pointer;}\n  .cal-cell .amt{font-size:9px;color:#c0392b;font-weight:700;margin-top:2px;}\n  .cal-cell.empty{background:none;cursor:default;}\n  .cal-cell.today{background:#DFF3E6;}\n\n  .toast{position:fixed;bottom:26px;left:50%;transform:translateX(-50%);background:var(--ink);color:#fff;padding:11px 22px;border-radius:24px;font-size:13.5px;font-weight:600;z-index:400;opacity:0;transition:opacity .2s ease;pointer-events:none;}\n  .toast.show{opacity:1;}\n\n  /* ---------- MOBILE ---------- */\n  @media(max-width:640px){\n    #topbar{padding:12px 14px;flex-wrap:wrap;gap:8px;}\n    .tb-left{font-size:15px;}\n    .tb-logo{width:28px;height:28px;font-size:14px;}\n    .tb-right{gap:6px;}\n    .tb-btn{padding:8px 10px;font-size:12px;}\n    .dash-wrap{padding:36px 16px;}\n    .dash-wrap h1{font-size:23px;}\n    .dash-cards{gap:16px;}\n    .sub-title-row{padding:6px 16px 18px 16px;}\n    .sub-title-row h1{font-size:20px;}\n    .back-btn{padding:14px 16px 0 16px;}\n    .fin-shell{padding:0 14px 30px 14px;}\n    .fin-topbar{flex-direction:column;align-items:stretch;gap:10px;}\n    .stat-pill-row{overflow-x:auto;}\n    .card{padding:16px;margin:0 0 14px 0;}\n    .rem-shell, .admin-shell{padding:0 14px 40px 14px;}\n    .cat-grid{grid-template-columns:repeat(3,1fr);gap:14px 4px;}\n    .groc-cat-grid{grid-template-columns:repeat(2,1fr);}\n    .dialog{width:100%;border-radius:18px;}\n    .overlay{padding:0;align-items:flex-end;}\n    .overlay .dialog{border-radius:18px 18px 0 0;max-height:94vh;}\n    .overlay.sheet-overlay{align-items:flex-end;}\n    .overlay.sheet-overlay .dialog.sheet{\n      height:90vh; min-height:90vh; max-height:94vh;\n      border-radius:18px 18px 0 0;\n    }\n    .acc-grid{grid-template-columns:1fr;}\n    .alarm-banner{flex-wrap:wrap;padding:12px 14px;}\n    .alarm-banner .ab-actions{width:100%;justify-content:flex-end;}\n  }\n\n  /* ---------- ALARM BANNER ---------- */\n  .alarm-banner{\n    position:fixed;top:0;left:0;right:0;z-index:500;background:#1A1A1A;color:#fff;\n    display:flex;align-items:center;gap:16px;padding:14px 24px;box-shadow:0 4px 18px rgba(0,0,0,.35);\n    animation:alarmSlide .25s ease;\n  }\n  @keyframes alarmSlide{from{transform:translateY(-100%);}to{transform:translateY(0);}}\n  .alarm-banner .ab-ic{font-size:26px;animation:alarmPulse 1s infinite;flex-shrink:0;}\n  @keyframes alarmPulse{0%,100%{transform:scale(1);}50%{transform:scale(1.18);}}\n  .alarm-banner .ab-body{flex:1;min-width:0;}\n  .alarm-banner .ab-title{font-weight:800;font-size:14.5px;}\n  .alarm-banner .ab-sub{font-size:12.5px;opacity:.75;}\n  .alarm-banner .ab-actions{display:flex;gap:8px;flex-shrink:0;}\n  .alarm-banner button{border:none;border-radius:8px;padding:9px 14px;font-weight:700;font-size:13px;cursor:pointer;}\n  .ab-btn-done{background:var(--primary);color:#1A1A1A;}\n  .ab-btn-snooze{background:#3a3a3d;color:#fff;}\n  .ab-btn-used{background:#D64545;color:#fff;}\n  #bellBtn.on{background:var(--primary);color:var(--ink);border-color:var(--primary-dark);}\n\n  /* ---------- VOICE ASSISTANT ---------- */\n  .voice-fab{\n    position:fixed; right:22px; bottom:22px; width:58px; height:58px; border-radius:50%;\n    background:var(--ink); color:var(--primary); border:none; font-size:25px; cursor:pointer;\n    box-shadow:0 6px 18px rgba(0,0,0,.28); z-index:250; display:flex; align-items:center; justify-content:center;\n  }\n  .voice-fab:hover{opacity:.92;}\n  .voice-fab.listening{background:#D64545; animation:micPulse 1s infinite;}\n  @keyframes micPulse{0%,100%{transform:scale(1);}50%{transform:scale(1.14);}}\n  .voice-transcript{\n    position:fixed; right:22px; bottom:90px; max-width:280px; background:var(--card); color:var(--ink);\n    border:1.5px solid var(--line); border-radius:12px; padding:11px 15px; font-size:12.5px; line-height:1.4;\n    box-shadow:var(--shadow); z-index:250;\n  }\n  .voice-transcript.hidden{display:none;}\n  @media(max-width:640px){ .voice-fab{right:16px;bottom:16px;width:52px;height:52px;font-size:22px;} .voice-transcript{right:16px;bottom:78px;max-width:220px;} }\n\n  /* ---------- AUTH (Login / Sign up) ---------- */\n  #auth-screen{\n    position:fixed; inset:0; z-index:9000; background:var(--bg);\n    display:flex; align-items:center; justify-content:center; padding:24px;\n  }\n  #auth-screen.hidden{display:none;}\n  .auth-card{\n    width:100%; max-width:420px; background:var(--card); border:1.5px solid var(--line);\n    border-radius:20px; padding:28px 22px; box-shadow:var(--shadow);\n  }\n  .auth-brand{display:flex;align-items:center;gap:10px;margin-bottom:18px;font-weight:800;font-size:18px;}\n  .auth-brand .logo{width:40px;height:40px;border-radius:12px;background:var(--primary);display:flex;align-items:center;justify-content:center;font-size:20px;}\n  .auth-card h1{margin:0 0 6px;font-size:26px;font-weight:800;}\n  .auth-card .auth-sub{color:var(--muted);margin:0 0 18px;font-size:14px;line-height:1.45;}\n  .auth-tabs{display:flex;border:1.5px solid var(--ink);border-radius:10px;overflow:hidden;margin-bottom:16px;}\n  .auth-tabs button{flex:1;padding:10px 0;border:none;background:var(--card);font-weight:700;font-size:14px;cursor:pointer;color:var(--ink);}\n  .auth-tabs button.active{background:var(--primary);}\n  .auth-error{color:var(--red);font-weight:600;font-size:13px;margin:0 0 10px;}\n  .auth-info{color:var(--green);font-weight:600;font-size:13px;margin:0 0 10px;}\n  #auth-screen .primary-btn{width:100%;margin-top:4px;}\n  #topbar .user-chip{font-size:12px;color:var(--muted);font-weight:700;max-width:140px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;align-self:center;}\n</style>\n</head>\n<body>\n\n<div id=\"auth-screen\">\n  <div class=\"auth-card\">\n    <div class=\"auth-brand\"><div class=\"logo\">💠</div>Finance Tracker</div>\n    <h1 id=\"authTitle\">Welcome back</h1>\n    <p class=\"auth-sub\" id=\"authSub\">Sign in to open your dashboard</p>\n    <div class=\"auth-tabs\">\n      <button type=\"button\" id=\"tabLogin\" class=\"active\" onclick=\"setAuthMode('login')\">Login</button>\n      <button type=\"button\" id=\"tabSignup\" onclick=\"setAuthMode('signup')\">Sign up</button>\n    </div>\n    <div class=\"field\" id=\"authNameField\" style=\"display:none;\">\n      <label>Full name</label>\n      <input id=\"authName\" type=\"text\" placeholder=\"Your name\" autocomplete=\"name\">\n    </div>\n    <div class=\"field\">\n      <label>Email</label>\n      <input id=\"authEmail\" type=\"email\" placeholder=\"you@email.com\" autocomplete=\"email\">\n    </div>\n    <div class=\"field\">\n      <label>Password</label>\n      <input id=\"authPassword\" type=\"password\" placeholder=\"••••••••\" autocomplete=\"current-password\">\n    </div>\n    <p class=\"auth-error hidden\" id=\"authError\"></p>\n    <p class=\"auth-info hidden\" id=\"authInfo\"></p>\n    <button class=\"primary-btn\" id=\"authSubmitBtn\" onclick=\"submitAuth()\">Login</button>\n  </div>\n</div>\n\n<div id=\"topbar\">\n  <div class=\"tb-left\" onclick=\"goDashboard()\"><span class=\"tb-logo\">💠</span><span id=\"appNameLabel\">All-in-One Dashboard</span></div>\n  <div class=\"tb-right\">\n    <span class=\"user-chip\" id=\"userChip\"></span>\n    <button class=\"tb-btn\" id=\"bellBtn\" onclick=\"enableAlerts()\" title=\"Enable alarm sound & notifications\">🔔 Alerts</button>\n    <button class=\"tb-btn\" onclick=\"goDashboard()\">Dashboard</button>\n    <button class=\"tb-btn admin-btn\" id=\"adminBtn\" onclick=\"enterAdmin()\">⚙ Admin</button>\n    <button class=\"tb-btn\" id=\"logoutBtn\" onclick=\"logoutAuth()\">Logout</button>\n  </div>\n</div>\n\n<div id=\"alarm-banner-root\"></div>\n\n<div id=\"app-root\">\n  <div id=\"view-dashboard\" class=\"view active\"></div>\n  <div id=\"view-finance\" class=\"view\"></div>\n  <div id=\"view-reminderDashboard\" class=\"view\"></div>\n  <div id=\"view-expenseRem\" class=\"view\"></div>\n  <div id=\"view-medicineRem\" class=\"view\"></div>\n  <div id=\"view-groceryRem\" class=\"view\"></div>\n  <div id=\"view-shoppingList\" class=\"view\"></div>\n  <div id=\"view-generalRem\" class=\"view\"></div>\n  <div id=\"view-admin\" class=\"view\"></div>\n</div>\n\n<div id=\"modal-root\"></div>\n<div class=\"toast\" id=\"toast\"></div>\n<audio id=\"alarmAudio\" src=\"data:audio/wav;base64,\" loop preload=\"auto\"></audio>\n<button id=\"voiceFab\" class=\"voice-fab\" onclick=\"toggleVoiceListening()\" title=\"Voice Assistant\">🎤</button>\n<div id=\"voiceTranscriptBubble\" class=\"voice-transcript hidden\"></div>\n\n\n<script>\n/* ============================================================\n   GLOBAL ERROR SAFETY NET\n   If anything throws (e.g. a blocked resource, an unusual browser\n   setting), show a small visible banner instead of silently\n   leaving the page half-rendered — this makes problems easy to\n   spot and report instead of just \"some features are missing\".\n   ============================================================ */\nwindow.addEventListener('error', function(e){\n  try{\n    let bar = document.getElementById('fatalErrorBar');\n    if(!bar){\n      bar = document.createElement('div');\n      bar.id = 'fatalErrorBar';\n      bar.style.cssText = 'position:fixed;bottom:0;left:0;right:0;background:#D64545;color:#fff;padding:10px 16px;font:13px -apple-system,Segoe UI,sans-serif;z-index:9999;';\n      document.body.appendChild(bar);\n    }\n    bar.textContent = 'A script error occurred: ' + (e.message||'unknown error') + ' — try reloading the page.';\n  }catch(err){ /* ignore */ }\n});\n\n/* ============================================================\n   CONFIG / THEMES / CONSTANTS\n   ============================================================ */\nconst THEMES = {\n  yellow:{label:'Classic Yellow', primary:'#FFCD3C', primaryDark:'#F5B700', bg:'#F6F6F8', card:'#FFFFFF', ink:'#1A1A1A', muted:'#8A8A8E', line:'#ECECEE'},\n  dark:{label:'Midnight', primary:'#F5B700', primaryDark:'#D89C00', bg:'#121212', card:'#1E1E1E', ink:'#F2F2F2', muted:'#A0A0A5', line:'#2A2A2E'},\n  blue:{label:'Ocean Blue', primary:'#4C8DFF', primaryDark:'#2F6FE0', bg:'#F2F6FC', card:'#FFFFFF', ink:'#16233F', muted:'#6C7A93', line:'#E3E9F3'},\n  green:{label:'Fresh Green', primary:'#3DBE7B', primaryDark:'#289A5E', bg:'#F2FBF6', card:'#FFFFFF', ink:'#103322', muted:'#6B8E7C', line:'#DFF1E7'},\n  rose:{label:'Rose', primary:'#FF7A9C', primaryDark:'#E14D6E', bg:'#FFF5F7', card:'#FFFFFF', ink:'#3A1420', muted:'#A4818C', line:'#FBE3E9'}\n};\nconst DEFAULT_CONFIG = {\n  appName:'All-in-One Dashboard',\n  theme:'yellow',\n  adminPassword:'admin123',\n  currency:'USD',\n  alarmsEnabled:true,\n  medicineTimes:{Morning:'08:00', Afternoon:'13:00', Evening:'19:00'},\n  alertTime:'09:00',\n  expenseOffsets:[1,0],\n  groceryOffsets:[2,1,0],\n  alarmDurationSec:60,\n  features:{\n    finance:true, reminders:true, expenseReminder:true, medicineReminder:true, groceryExpiryReminder:true, generalReminder:true,\n    financeCharts:true, financeReports:true, financeAccounts:true, shoppingList:true, voiceAssistant:true\n  }\n};\nconst EXPENSE_CATS = [\n  {name:'Groceries', icon:'🛍️'}, {name:'Shopping', icon:'🛒'}, {name:'Food', icon:'🍔'}, {name:'Phone', icon:'📱'}, {name:'Entertainment', icon:'🎮'},\n  {name:'Education', icon:'🎓'}, {name:'Beauty', icon:'💄'}, {name:'Sports', icon:'🏃'}, {name:'Social', icon:'🥂'},\n  {name:'Transportation', icon:'🚌'}, {name:'Clothing', icon:'👕'}, {name:'Car', icon:'🚗'}, {name:'Alcohol', icon:'🍷'},\n  {name:'Cigarettes', icon:'🚬'}, {name:'Electronics', icon:'💻'}, {name:'Travel', icon:'✈️'}, {name:'Health', icon:'💊'},\n  {name:'Pets', icon:'🐶'}, {name:'Repairs', icon:'🔧'}, {name:'Housing', icon:'🏠'}, {name:'Home', icon:'🛋️'},\n  {name:'Gifts', icon:'🎁'}, {name:'Donations', icon:'🤲'}, {name:'Lottery', icon:'🎲'}, {name:'Snacks', icon:'🍿'},\n  {name:'Kids', icon:'🍼'}, {name:'Vegetables', icon:'🥕'}, {name:'Fruits', icon:'🍒'}, {name:'Others', icon:'🪙'}\n];\nconst INCOME_CATS = [\n  {name:'Salary', icon:'💼'}, {name:'Investments', icon:'📈'}, {name:'Part-Time', icon:'🤝'},\n  {name:'Bonus', icon:'🏆'}, {name:'Gift', icon:'🎁'}, {name:'Others', icon:'🪙'}\n];\nconst ACCOUNT_ICONS = ['💵','💳','🏦','💰','👛','🐷','🔒','₿','📊','📱','$','€'];\nconst PALETTE = ['#F5B700','#FF7A5C','#FF5C7C','#B06DFF','#5C8DFF','#26C6DA','#26D0A0','#8BC34A','#D4A94C','#A9745B','#FF6B6B','#845EC2','#4A8FE7','#E8A33D'];\nconst CURRENCIES = [\n  {code:'USD', sym:'$', name:'United States Dollar'}, {code:'EUR', sym:'€', name:'Euro'},\n  {code:'GBP', sym:'£', name:'British Pound'}, {code:'INR', sym:'₹', name:'Indian Rupee'},\n  {code:'JPY', sym:'¥', name:'Japanese Yen'}, {code:'AUD', sym:'A$', name:'Australian Dollar'},\n];\n/* Grocery categories with images (emoji tiles) and their common items.\n   Every category ends with an \"Others\" entry so the customer can type\n   in an item name that isn't already listed. */\nconst GROCERY_CATEGORIES = [\n  {name:'Vegetables', icon:'🥦', items:[\n    {name:'Tomato', icon:'🍅'},{name:'Potato', icon:'🥔'},{name:'Onion', icon:'🧅'},{name:'Carrot', icon:'🥕'},\n    {name:'Cucumber', icon:'🥒'},{name:'Spinach', icon:'🥬'},{name:'Cabbage', icon:'🥬'},{name:'Cauliflower', icon:'🥦'},\n    {name:'Broccoli', icon:'🥦'},{name:'Bell Pepper', icon:'🫑'},{name:'Garlic', icon:'🧄'},{name:'Ginger', icon:'🫚'},\n    {name:'Green Peas', icon:'🟢'},{name:'Corn', icon:'🌽'},{name:'Beans', icon:'🫘'}\n  ]},\n  {name:'Fruits', icon:'🍎', items:[\n    {name:'Apple', icon:'🍎'},{name:'Banana', icon:'🍌'},{name:'Orange', icon:'🍊'},{name:'Grapes', icon:'🍇'},\n    {name:'Mango', icon:'🥭'},{name:'Watermelon', icon:'🍉'},{name:'Strawberry', icon:'🍓'},{name:'Pineapple', icon:'🍍'},\n    {name:'Pear', icon:'🍐'},{name:'Lemon', icon:'🍋'},{name:'Papaya', icon:'🟠'},{name:'Kiwi', icon:'🥝'},\n    {name:'Peach', icon:'🍑'},{name:'Avocado', icon:'🥑'}\n  ]},\n  {name:'Pulses & Lentils', icon:'🫘', items:[\n    {name:'Toor Dal', icon:'🫘'},{name:'Moong Dal', icon:'🫘'},{name:'Chana Dal', icon:'🫘'},{name:'Masoor Dal', icon:'🫘'},\n    {name:'Urad Dal', icon:'🫘'},{name:'Rajma (Kidney Beans)', icon:'🫘'},{name:'Chickpeas (Chana)', icon:'🫘'},\n    {name:'Black-eyed Peas', icon:'🫘'},{name:'Soybeans', icon:'🫘'}\n  ]},\n  {name:'Dairy & Eggs', icon:'🥛', items:[\n    {name:'Milk', icon:'🥛'},{name:'Curd / Yogurt', icon:'🥣'},{name:'Cheese', icon:'🧀'},{name:'Butter', icon:'🧈'},\n    {name:'Paneer', icon:'🧊'},{name:'Eggs', icon:'🥚'},{name:'Cream', icon:'🥛'}\n  ]},\n  {name:'Meat & Seafood', icon:'🍗', items:[\n    {name:'Chicken', icon:'🍗'},{name:'Mutton', icon:'🥩'},{name:'Fish', icon:'🐟'},{name:'Shrimp', icon:'🦐'},\n    {name:'Beef', icon:'🥩'}\n  ]},\n  {name:'Grains & Cereals', icon:'🌾', items:[\n    {name:'Rice', icon:'🍚'},{name:'Wheat Flour', icon:'🌾'},{name:'Oats', icon:'🌾'},{name:'Quinoa', icon:'🌾'},\n    {name:'Semolina (Suji)', icon:'🌾'},{name:'Poha', icon:'🌾'},{name:'Pasta', icon:'🍝'}\n  ]},\n  {name:'Bakery', icon:'🍞', items:[\n    {name:'Bread', icon:'🍞'},{name:'Buns', icon:'🥯'},{name:'Cookies', icon:'🍪'},{name:'Cake', icon:'🎂'}\n  ]},\n  {name:'Spices & Condiments', icon:'🧂', items:[\n    {name:'Salt', icon:'🧂'},{name:'Turmeric', icon:'🧂'},{name:'Chili Powder', icon:'🌶️'},{name:'Cumin', icon:'🧂'},\n    {name:'Coriander Powder', icon:'🧂'},{name:'Garam Masala', icon:'🧂'},{name:'Black Pepper', icon:'🧂'},\n    {name:'Mustard Seeds', icon:'🧂'},{name:'Ketchup', icon:'🍅'},{name:'Cooking Oil', icon:'🛢️'}\n  ]},\n  {name:'Beverages', icon:'🧃', items:[\n    {name:'Juice', icon:'🧃'},{name:'Soft Drinks', icon:'🥤'},{name:'Tea', icon:'🍵'},{name:'Coffee', icon:'☕'},\n    {name:'Water Bottles', icon:'💧'}\n  ]},\n  {name:'Frozen Foods', icon:'🧊', items:[\n    {name:'Frozen Vegetables', icon:'🧊'},{name:'Ice Cream', icon:'🍦'},{name:'Frozen Peas', icon:'🧊'},\n    {name:'Frozen Fries', icon:'🍟'}\n  ]},\n  {name:'Snacks', icon:'🍿', items:[\n    {name:'Chips', icon:'🍟'},{name:'Biscuits', icon:'🍪'},{name:'Namkeen', icon:'🥨'},{name:'Popcorn', icon:'🍿'}\n  ]}\n];\nconst GROCERY_OTHERS = {name:'Others', icon:'➕'};\n/* Some GROCERY_CATEGORIES entries (Vegetables, Fruits, Snacks) duplicate a\n   top-level EXPENSE_CATS entry of the same name. Rather than showing\n   \"Vegetables\" as both its own expense category AND a sub-category choice\n   nested under \"Groceries\", these three get picked directly at the\n   top level — so item-tagging shows their items immediately with no\n   extra category step. Everything else without its own top-level\n   expense category (Pulses & Lentils, Dairy & Eggs, Meat & Seafood,\n   Grains & Cereals, Bakery, Spices & Condiments, Beverages, Frozen\n   Foods) stays nested as a sub-category choice under \"Groceries\". */\nconst GROCERY_DIRECT_EXPENSE_CATS = ['Vegetables','Fruits','Snacks'];\nconst GROCERY_FAMILY_CATS = ['Groceries', ...GROCERY_DIRECT_EXPENSE_CATS];\nfunction getGroceryItemScope(category){\n  if(GROCERY_DIRECT_EXPENSE_CATS.includes(category)){\n    const cat = GROCERY_CATEGORIES.find(c=>c.name===category);\n    return cat ? {mode:'direct', items:cat.items, icon:cat.icon, categoryName:cat.name} : null;\n  }\n  if(category==='Groceries'){\n    const subcats = GROCERY_CATEGORIES.filter(c=>!GROCERY_DIRECT_EXPENSE_CATS.includes(c.name));\n    return {mode:'subcategory', subcats};\n  }\n  return null;\n}\n/* Categories whose contents spoil quickly enough to be worth an expiry\n   reminder. Used to auto-flag likely perishable items when importing\n   or scanning a document for the Personal Finance Tracker. */\nconst PERISHABLE_CATEGORY_NAMES = ['Vegetables','Fruits','Dairy & Eggs','Meat & Seafood'];\nfunction findPerishableMatch(text){\n  const lower = (text||'').toLowerCase();\n  if(!lower.trim()) return null;\n  for(const catName of PERISHABLE_CATEGORY_NAMES){\n    const cat = GROCERY_CATEGORIES.find(c=>c.name===catName);\n    if(!cat) continue;\n    for(const it of cat.items){\n      const escaped = it.name.toLowerCase().replace(/[.*+?^${}()|[\\]\\\\]/g,'\\\\$&');\n      const re = new RegExp('\\\\b'+escaped+'\\\\b','i');\n      if(re.test(lower)) return {category:cat.name, icon:it.icon, matchedName:it.name};\n    }\n  }\n  return null;\n}\n/* Reads the list of tagged grocery/vegetable/fruit/snack items on a\n   transaction. Newer transactions store one unified `groceryItems`\n   array (name/category/icon, with expiryDate set only for items also\n   tracked in Grocery Expiry Reminder). Older transactions saved before\n   this merge may instead have a single `groceryCategory`/`groceryItem`\n   tag and/or a separate `perishableItems` array — this reconstructs an\n   equivalent list from those so old data keeps displaying correctly. */\nfunction getTxnGroceryItems(t){\n  if(Array.isArray(t.groceryItems)) return t.groceryItems;\n  const list = [];\n  if(t.groceryItem){\n    list.push({id:'legacy-tag', name:t.groceryItem, category:t.groceryCategory||'', icon:'', expiryDate:'', groceryReminderId:null});\n  }\n  if(Array.isArray(t.perishableItems)){\n    t.perishableItems.forEach(p=>list.push({id:p.id, name:p.name, category:p.category, icon:p.icon, expiryDate:p.expiryDate||'', groceryReminderId:p.groceryReminderId||null}));\n  }\n  return list;\n}\n\n/* ============================================================\n   STATE (persisted to localStorage — this file is meant to be\n   hosted on your own site; note: in an in-chat artifact preview\n   browser storage is sandboxed, so use \"Export/Import Data\" in\n   the Admin Panel to move data between sessions there)\n   ============================================================ */\nfunction readRawJSON(key){\n  try{ const raw = localStorage.getItem(key); return raw ? JSON.parse(raw) : null; }\n  catch(e){ return null; }\n}\n/* Config needs a DEEP merge, not a shallow one: a config saved by an\n   older version of this file won't have newer keys inside nested\n   objects like `features` or `medicineTimes` (e.g. groceryExpiryReminder\n   was added later). A shallow Object.assign would let the old,\n   incomplete `features` object silently replace the new defaults,\n   making newer features vanish even though the code supports them. */\nfunction mergeConfig(saved){\n  const merged = Object.assign({}, DEFAULT_CONFIG, saved||{});\n  merged.features = Object.assign({}, DEFAULT_CONFIG.features, (saved && saved.features) || {});\n  merged.medicineTimes = Object.assign({}, DEFAULT_CONFIG.medicineTimes, (saved && saved.medicineTimes) || {});\n  merged.expenseOffsets = (saved && Array.isArray(saved.expenseOffsets) && saved.expenseOffsets.length) ? saved.expenseOffsets : DEFAULT_CONFIG.expenseOffsets;\n  merged.groceryOffsets = (saved && Array.isArray(saved.groceryOffsets) && saved.groceryOffsets.length) ? saved.groceryOffsets : DEFAULT_CONFIG.groceryOffsets;\n  merged.alarmDurationSec = (saved && typeof saved.alarmDurationSec==='number') ? saved.alarmDurationSec : DEFAULT_CONFIG.alarmDurationSec;\n  return merged;\n}\nlet config = mergeConfig(readRawJSON('aio_config'));\nlet financeState = loadJSON('aio_finance', {\n  accounts:[{id:uid(), name:'Cash', type:'Default', currency: config.currency, amount:0, icon:'💵', excluded:false}],\n  transactions: [], budget:0\n});\nfinanceState.accounts = asArray(financeState.accounts);\nif(financeState.accounts.length===0) financeState.accounts.push({id:uid(), name:'Cash', type:'Default', currency:config.currency, amount:0, icon:'💵', excluded:false});\nfinanceState.transactions = asArray(financeState.transactions);\nif(typeof financeState.budget!=='number' || isNaN(financeState.budget)) financeState.budget = 0;\nlet expenseReminders = asArray(loadJSON('aio_expreminders', []));\nlet medReminders = asArray(loadJSON('aio_medreminders', []));\nlet groceryReminders = asArray(loadJSON('aio_groceryreminders', []));\nlet shoppingList = asArray(loadJSON('aio_shoppinglist', []));\nlet generalReminders = asArray(loadJSON('aio_generalreminders', []));\nlet dismissedAlarms = (function(){ try{ const p=JSON.parse(localStorage.getItem('aio_dismissed')); return Array.isArray(p)?p:[]; }catch(e){ return []; } })();\nfunction saveDismissed(){ try{ localStorage.setItem('aio_dismissed', JSON.stringify(dismissedAlarms)); }catch(e){} }\nlet alarmQueue = [];\nlet currentAlarm = null;\nlet snoozeMap = {};\nlet audioUnlocked = false;\nlet notifyPermissionGranted = (typeof Notification!=='undefined' && Notification.permission==='granted');\n\nlet financeSubview = 'home';\nlet chartsRange = 'month';\nlet currentMonth = monthKey(new Date());\nlet adminAuthed = false;\n\nfunction loadJSON(key, fallback){\n  try{\n    const raw = localStorage.getItem(key);\n    if(!raw) return fallback;\n    const parsed = JSON.parse(raw);\n    if(Array.isArray(fallback)){\n      if(Array.isArray(parsed)) return parsed;\n      // Recovery path: earlier versions of this file could corrupt an\n      // array into a plain object (e.g. {\"0\":{...},\"1\":{...}}) via an\n      // unsafe merge. If that happened, rebuild the array from it\n      // instead of losing the saved data.\n      if(parsed && typeof parsed==='object') return Object.values(parsed);\n      return fallback;\n    }\n    return (parsed && typeof parsed==='object') ? Object.assign({}, fallback, parsed) : fallback;\n  }catch(e){ return fallback; }\n}\nfunction asArray(v){ return Array.isArray(v) ? v : []; }\nfunction persist(key, val){ try{ localStorage.setItem(key, JSON.stringify(val)); }catch(e){ console.error('save failed',e); } }\nfunction saveConfig(){ persist('aio_config', config); }\nfunction saveFinance(){ persist('aio_finance', financeState); }\nfunction saveExpRem(){ persist('aio_expreminders', expenseReminders); }\nfunction saveMedRemState(){ persist('aio_medreminders', medReminders); }\nfunction saveGroceryRem(){ persist('aio_groceryreminders', groceryReminders); }\nfunction saveShoppingList(){ persist('aio_shoppinglist', shoppingList); }\nfunction saveGeneralRem(){ persist('aio_generalreminders', generalReminders); }\n\nfunction uid(){ return 'id_'+Date.now().toString(36)+Math.random().toString(36).slice(2,8); }\nfunction monthKey(d){ return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0'); }\nfunction todayStr(){ return new Date().toISOString().slice(0,10); }\nfunction escapeHtml(s){ const d=document.createElement('div'); d.innerText=s||''; return d.innerHTML; }\nfunction currencySymbol(){ const c = CURRENCIES.find(c=>c.code===config.currency); return c?c.sym:'$'; }\nfunction fmt(n){ const s = Math.abs(n).toLocaleString(undefined,{minimumFractionDigits:n%1===0?0:2,maximumFractionDigits:2}); return currencySymbol()+s; }\nfunction catColor(name){ const all=EXPENSE_CATS.concat(INCOME_CATS); let i=all.findIndex(c=>c.name===name); if(i<0)i=0; return PALETTE[i%PALETTE.length]; }\nfunction findIcon(list,name){ const f=list.find(c=>c.name===name); return f?f.icon:'💰'; }\nfunction showToast(msg){ const t=document.getElementById('toast'); t.textContent=msg; t.classList.add('show'); clearTimeout(t._timer); t._timer=setTimeout(()=>t.classList.remove('show'),1800); }\n\n/* ============================================================\n   THEME\n   ============================================================ */\nfunction applyTheme(name){\n  const t = THEMES[name] || THEMES.yellow;\n  const r = document.documentElement.style;\n  r.setProperty('--primary', t.primary);\n  r.setProperty('--primary-dark', t.primaryDark);\n  r.setProperty('--bg', t.bg);\n  r.setProperty('--card', t.card);\n  r.setProperty('--ink', t.ink);\n  r.setProperty('--muted', t.muted);\n  r.setProperty('--line', t.line);\n}\n\n/* ============================================================\n   NAVIGATION\n   ============================================================ */\nfunction showView(id){\n  document.querySelectorAll('.view').forEach(v=>v.classList.remove('active'));\n  document.getElementById('view-'+id).classList.add('active');\n}\nfunction goDashboard(){ renderDashboard(); showView('dashboard'); }\nfunction enterFinance(){ if(!config.features.finance){ return; } financeSubview='home'; renderFinance(); showView('finance'); }\nfunction enterReminderDashboard(){ if(!config.features.reminders){ return; } renderReminderDashboard(); showView('reminderDashboard'); }\nfunction enterExpenseRem(){ renderExpenseRem(); showView('expenseRem'); }\nfunction enterMedicineRem(){ renderMeds(); showView('medicineRem'); }\nfunction enterGroceryRem(){ renderGroceryRem(); showView('groceryRem'); }\nfunction enterShoppingList(){ if(!config.features.shoppingList){ return; } renderShoppingList(); showView('shoppingList'); }\nfunction enterGeneralRem(){ renderGeneralRem(); showView('generalRem'); }\nfunction enterAdmin(){\n  if(!(authState.user && authState.isAdmin)){\n    alert('Admin access only. Ask an admin to promote your account.');\n    return;\n  }\n  if(!adminAuthed){\n    const pw = prompt('Enter admin password:');\n    if(pw === null) return;\n    if(pw !== config.adminPassword){ alert('Incorrect password.'); return; }\n    adminAuthed = true;\n  }\n  renderAdmin();\n  showView('admin');\n}\n\n/* ============================================================\n   DASHBOARD\n   ============================================================ */\nfunction renderDashboard(){\n  document.getElementById('appNameLabel').textContent = config.appName;\n  document.title = config.appName;\n  const v = document.getElementById('view-dashboard');\n  let cards = '';\n  if(config.features.finance){\n    cards += `<div class=\"dash-card\" onclick=\"enterFinance()\">\n      <div class=\"dc-ic\">💰</div><h2>Personal Finance Tracker</h2>\n      <p>Track expenses, income, accounts, budgets and spending charts.</p>\n    </div>`;\n  }\n  if(config.features.reminders){\n    cards += `<div class=\"dash-card\" onclick=\"enterReminderDashboard()\">\n      <div class=\"dc-ic\">⏰</div><h2>Reminder & Tracking</h2>\n      <p>Stay on top of upcoming bills and medicine schedules.</p>\n    </div>`;\n  }\n  if(config.features.shoppingList){\n    cards += `<div class=\"dash-card\" onclick=\"enterShoppingList()\">\n      <div class=\"dc-ic\">📝</div><h2>List to Buy</h2>\n      <p>Plan what to shop for next, and see what's already tracked in your grocery reminders.</p>\n    </div>`;\n  }\n  if(!cards){\n    v.innerHTML = `<div class=\"dash-wrap\"><h1>${escapeHtml(config.appName)}</h1>\n      <div class=\"dash-empty\"><p>All features are currently disabled. Open the Admin Panel to turn features back on.</p>\n      <button class=\"primary-btn\" onclick=\"enterAdmin()\">⚙ Open Admin Panel</button></div></div>`;\n    return;\n  }\n  v.innerHTML = `<div class=\"dash-wrap\">\n      <h1>${escapeHtml(config.appName)}</h1>\n      <p class=\"sub\">Choose a workspace to get started</p>\n      <div class=\"dash-cards\">${cards}</div>\n    </div>`;\n}\n\n/* ============================================================\n   ================  FINANCE (Personal Finance Tracker)  ======\n   ============================================================ */\nfunction txnsForMonth(mkey){ return financeState.transactions.filter(t=>t.date.slice(0,7)===mkey); }\nfunction monthLabel(mkey){ const [y,m]=mkey.split('-'); const d=new Date(parseInt(y),parseInt(m)-1,1); return d.toLocaleDateString(undefined,{month:'long'}); }\nfunction shiftMonth(mkey,delta){ const [y,m]=mkey.split('-').map(Number); const d=new Date(y,m-1+delta,1); return monthKey(d); }\nfunction monthSummary(mkey){\n  const txns = txnsForMonth(mkey); let expenses=0, income=0;\n  txns.forEach(t=>{ if(t.kind==='expense') expenses+=t.amount; if(t.kind==='income') income+=t.amount; });\n  return {expenses, income, balance: income-expenses};\n}\n\nfunction renderFinance(){\n  const v = document.getElementById('view-finance');\n  v.innerHTML = `\n    <button class=\"back-btn\" onclick=\"goDashboard()\">← Back to Menu</button>\n    <div class=\"sub-title-row\"><h1>Personal Finance Tracker</h1></div>\n    <div class=\"fin-shell\">\n      <aside class=\"fin-sidebar\" id=\"finSidebar\"></aside>\n      <main class=\"fin-main\">\n        <div class=\"fin-topbar\">\n          <div class=\"month-nav\">\n            <button onclick=\"finShiftMonth(-1)\">‹</button>\n            <span id=\"finMonthLabel\"></span>\n            <button onclick=\"finShiftMonth(1)\">›</button>\n          </div>\n          <div class=\"stat-pill-row\" id=\"finStats\"></div>\n          <div class=\"fin-tools\">\n            <button title=\"Search\" onclick=\"openSearch()\">🔍</button>\n            <button title=\"Calendar\" onclick=\"openCalendar()\">📅</button>\n            <button title=\"Import Transactions (PDF/Excel/CSV/Image)\" onclick=\"triggerFinImportFile()\">📄</button>\n            <button title=\"Scan Receipt or Document\" onclick=\"triggerFinScanFile()\">📷</button>\n          </div>\n        </div>\n        <input type=\"file\" id=\"finImportInput\" accept=\".txt,.csv,.pdf,.xlsx,.xls,.png,.jpg,.jpeg,.webp\" style=\"display:none\" onchange=\"handleFinImportFile(this.files[0])\">\n        <input type=\"file\" id=\"finScanInput\" accept=\"image/*\" capture=\"environment\" style=\"display:none\" onchange=\"handleFinScanFile(this.files[0])\">\n        <div id=\"fin-content\"></div>\n      </main>\n    </div>\n  `;\n  renderFinSidebar();\n  renderFinTopbar();\n  renderFinContent();\n}\nfunction finShiftMonth(delta){ currentMonth = shiftMonth(currentMonth, delta); renderFinTopbar(); renderFinContent(); }\nfunction renderFinTopbar(){\n  document.getElementById('finMonthLabel').textContent = monthLabel(currentMonth)+' '+currentMonth.slice(0,4);\n  const sum = monthSummary(currentMonth);\n  document.getElementById('finStats').innerHTML = `\n    <div class=\"stat-pill\"><div class=\"lbl\">Expenses</div><div class=\"val\">${sum.expenses.toLocaleString()}</div></div>\n    <div class=\"stat-pill\"><div class=\"lbl\">Income</div><div class=\"val\">${sum.income.toLocaleString()}</div></div>\n    <div class=\"stat-pill\"><div class=\"lbl\">Balance</div><div class=\"val\">${sum.balance.toLocaleString()}</div></div>\n  `;\n}\nfunction renderFinSidebar(){\n  const items = [{id:'home', label:'Home', icon:'🏠', on:true}];\n  if(config.features.financeCharts) items.push({id:'charts', label:'Charts', icon:'📊', on:true});\n  if(config.features.financeReports) items.push({id:'reports', label:'Reports', icon:'🧾', on:true});\n  if(config.features.financeAccounts) items.push({id:'accounts', label:'Accounts', icon:'💳', on:true});\n  document.getElementById('finSidebar').innerHTML = items.map(it=>\n    `<button class=\"fin-nav-btn ${financeSubview===it.id?'active':''}\" onclick=\"setFinSubview('${it.id}')\"><span class=\"ic\">${it.icon}</span>${it.label}</button>`\n  ).join('') + `<button class=\"fin-add-btn\" onclick=\"openAddTransaction('expense')\">+ Add Transaction</button>`;\n}\nfunction setFinSubview(id){ financeSubview = id; renderFinSidebar(); renderFinContent(); }\n\nfunction renderFinContent(){\n  const c = document.getElementById('fin-content');\n  if(financeSubview==='home') return renderFinHome(c);\n  if(financeSubview==='charts') return renderFinCharts(c);\n  if(financeSubview==='reports') return renderFinReports(c);\n  if(financeSubview==='accounts') return renderFinAccounts(c);\n}\n\nfunction renderFinHome(c){\n  const txns = txnsForMonth(currentMonth).slice().sort((a,b)=>(b.date+b.time).localeCompare(a.date+a.time));\n  if(txns.length===0){\n    c.innerHTML = `<div class=\"card\"><div class=\"empty-state\"><div class=\"em-icon\">🧾</div><div class=\"em-title\">No transactions yet</div><div>Click \"+ Add Transaction\" to log your first expense or income.</div></div></div>`;\n    return;\n  }\n  const groups = {}; txns.forEach(t=>{ (groups[t.date]=groups[t.date]||[]).push(t); });\n  const dates = Object.keys(groups).sort().reverse();\n  let html = '<div class=\"card\">';\n  dates.forEach(date=>{\n    const dayTxns = groups[date];\n    const dExp = dayTxns.filter(t=>t.kind==='expense').reduce((s,t)=>s+t.amount,0);\n    const dInc = dayTxns.filter(t=>t.kind==='income').reduce((s,t)=>s+t.amount,0);\n    const d = new Date(date+'T00:00:00');\n    const dLabel = d.toLocaleDateString(undefined,{day:'2-digit',month:'short'})+' '+d.toLocaleDateString(undefined,{weekday:'long'});\n    let sub=[]; if(dExp) sub.push('Expenses: '+dExp.toLocaleString()); if(dInc) sub.push('Income: '+dInc.toLocaleString());\n    html += `<div class=\"day-group-head\"><span>${dLabel}</span><span>${sub.join('   ')}</span></div>`;\n    dayTxns.forEach(t=>{\n      const isTransfer = t.kind==='transfer';\n      const icon = isTransfer?'🔁':findIcon(t.kind==='expense'?EXPENSE_CATS:INCOME_CATS, t.category);\n      const color = isTransfer?'#8A8A8E':catColor(t.category);\n      const amtClass = t.kind==='income'?'income':'expense';\n      const sign = t.kind==='income'?'+':(isTransfer?'':'-');\n      const taggedItems = getTxnGroceryItems(t);\n      const itemsLine = taggedItems.length ? `<div class=\"note\" style=\"color:#8a5a06;font-weight:600;\">🛒 Items: ${taggedItems.map(p=>escapeHtml(p.name)+(p.expiryDate?' 🔔':'')).join(', ')}</div>` : '';\n      html += `<div class=\"txn-row\" onclick=\"openDetails('${t.id}')\">\n        <div class=\"cat-circle\" style=\"background:${color}\">${icon}</div>\n        <div class=\"txn-info\"><div class=\"cat\">${isTransfer?'Transfer':t.category}</div><div class=\"note\">${escapeHtml(t.note||'')}</div>${itemsLine}</div>\n        <div class=\"txn-amt ${amtClass}\">${sign}${fmt(t.amount)}</div>\n      </div>`;\n    });\n  });\n  html += '</div>';\n  c.innerHTML = html;\n}\n\n/* Lightweight dependency-free donut chart renderer (native Canvas 2D —\n   no external charting library required, so this works fully offline). */\nfunction drawDonut(canvasId, values, colors, cutout){\n  const canvas = document.getElementById(canvasId);\n  if(!canvas) return;\n  const holder = canvas.parentElement;\n  const size = Math.max(60, holder.clientWidth || 150);\n  const dpr = window.devicePixelRatio || 1;\n  canvas.width = size*dpr; canvas.height = size*dpr;\n  canvas.style.width = size+'px'; canvas.style.height = size+'px';\n  const ctx = canvas.getContext('2d');\n  ctx.setTransform(dpr,0,0,dpr,0,0);\n  ctx.clearRect(0,0,size,size);\n  const cx=size/2, cy=size/2, radius=size/2 - 1;\n  const innerRadius = radius*(cutout||0.72);\n  const total = values.reduce((s,v)=>s+v,0) || 1;\n  let start = -Math.PI/2;\n  values.forEach((val,i)=>{\n    if(val<=0) return;\n    const angle = (val/total)*Math.PI*2;\n    ctx.beginPath();\n    ctx.moveTo(cx,cy);\n    ctx.arc(cx,cy,radius,start,start+angle);\n    ctx.closePath();\n    ctx.fillStyle = colors[i]||'#ccc';\n    ctx.fill();\n    start += angle;\n  });\n  ctx.globalCompositeOperation = 'destination-out';\n  ctx.beginPath();\n  ctx.arc(cx,cy,innerRadius,0,Math.PI*2);\n  ctx.fill();\n  ctx.globalCompositeOperation = 'source-over';\n}\n\nfunction rangeStartEnd(){\n  if(chartsRange==='week'){ const d=new Date(); const day=d.getDay(); const start=new Date(d); start.setDate(d.getDate()-day); const end=new Date(start); end.setDate(start.getDate()+6); return [start.toISOString().slice(0,10), end.toISOString().slice(0,10)]; }\n  if(chartsRange==='year'){ const y=currentMonth.slice(0,4); return [y+'-01-01', y+'-12-31']; }\n  const [y,mo]=currentMonth.split('-').map(Number); const start=new Date(y,mo-1,1), end=new Date(y,mo,0);\n  return [start.toISOString().slice(0,10), end.toISOString().slice(0,10)];\n}\nfunction renderFinCharts(c){\n  const [start,end] = rangeStartEnd();\n  const txns = financeState.transactions.filter(t=>t.kind==='expense' && t.date>=start && t.date<=end);\n  const total = txns.reduce((s,t)=>s+t.amount,0);\n  const byCat = {}; txns.forEach(t=>{ byCat[t.category]=(byCat[t.category]||0)+t.amount; });\n  const cats = Object.keys(byCat).sort((a,b)=>byCat[b]-byCat[a]);\n  c.innerHTML = `<div class=\"card\">\n      <div class=\"card-head\"><h3>Expenses</h3>\n        <div style=\"display:flex;gap:6px;\">\n          ${['week','month','year'].map(r=>`<button class=\"btn-outline\" style=\"${chartsRange===r?'background:var(--primary);border-color:var(--primary-dark);':''}\" onclick=\"setChartsRange('${r}')\">${r[0].toUpperCase()+r.slice(1)}</button>`).join('')}\n        </div>\n      </div>\n      <div id=\"chartsBody\"></div>\n    </div>`;\n  const body = document.getElementById('chartsBody');\n  if(cats.length===0){\n    body.innerHTML = `<div class=\"empty-state\"><div class=\"em-icon\">📊</div><div class=\"em-title\">Nothing to chart</div><div>Add expenses to see your breakdown.</div></div>`;\n    return;\n  }\n  const legendHtml = cats.map(cat=>{ const pct=total?Math.round(byCat[cat]/total*100):0; return `<div class=\"legend-item\"><span class=\"legend-dot\" style=\"background:${catColor(cat)}\"></span><span class=\"lname\">${cat}</span><span class=\"lpct\">${pct}%</span></div>`; }).join('');\n  const barsHtml = cats.map(cat=>{\n    const pct = total?(byCat[cat]/total*100):0; const icon=findIcon(EXPENSE_CATS,cat);\n    return `<div class=\"cat-bar-row\"><div class=\"cat-bar-top\"><div class=\"ic\" style=\"background:${catColor(cat)}\">${icon}</div><div class=\"nm\">${cat}</div><div class=\"pc\">${Math.round(pct)}%</div><div class=\"am\">${byCat[cat].toLocaleString()}</div></div><div class=\"cat-bar-track\"><div class=\"cat-bar-fill\" style=\"width:${pct}%;background:${catColor(cat)}\"></div></div></div>`;\n  }).join('');\n  body.innerHTML = `<div class=\"donut-wrap\" style=\"margin-bottom:10px;\">\n      <div class=\"donut-canvas-holder\"><canvas id=\"donutCanvas\"></canvas><div class=\"donut-center\">${total.toLocaleString()}<small>TOTAL</small></div></div>\n      <div class=\"legend\">${legendHtml}</div>\n    </div><div>${barsHtml}</div>`;\n  drawDonut('donutCanvas', cats.map(cat=>byCat[cat]), cats.map(cat=>catColor(cat)), 0.72);\n}\nfunction setChartsRange(r){ chartsRange=r; renderFinContent(); }\n\nfunction renderFinReports(c){\n  const sum = monthSummary(currentMonth);\n  const remaining = financeState.budget - sum.expenses;\n  const pct = financeState.budget>0 ? Math.min(100, Math.round(sum.expenses/financeState.budget*100)) : null;\n  c.innerHTML = `\n    <div class=\"grid-2\">\n      <div class=\"card\">\n        <div class=\"card-head\"><h3>Monthly Statistics — ${monthLabel(currentMonth)}</h3></div>\n        <div class=\"stat-grid\">\n          <div><div class=\"lbl\">Expenses</div><div class=\"val\">${sum.expenses.toLocaleString()}</div></div>\n          <div><div class=\"lbl\">Income</div><div class=\"val\">${sum.income.toLocaleString()}</div></div>\n          <div><div class=\"lbl\">Balance</div><div class=\"val\">${sum.balance.toLocaleString()}</div></div>\n        </div>\n      </div>\n      <div class=\"card\" style=\"cursor:pointer;\" onclick=\"openBudgetEditor()\">\n        <div class=\"card-head\"><h3>Monthly Budget</h3><span>›</span></div>\n        <div class=\"donut-wrap\">\n          <div class=\"donut-canvas-holder\" style=\"width:100px;height:100px;\"><canvas id=\"budgetCanvas\"></canvas><div class=\"donut-center\" style=\"font-size:13px;\">${pct===null?'--':pct+'%'}</div></div>\n          <div style=\"flex:1;\">\n            <div class=\"row-between\" style=\"padding:5px 0;border-bottom:1px solid var(--line);\"><span style=\"color:var(--muted);font-size:13px;\">Remaining</span><b>${remaining.toLocaleString()}</b></div>\n            <div class=\"row-between\" style=\"padding:5px 0;border-bottom:1px solid var(--line);\"><span style=\"color:var(--muted);font-size:13px;\">Budget</span><b>${financeState.budget.toLocaleString()}</b></div>\n            <div class=\"row-between\" style=\"padding:5px 0;\"><span style=\"color:var(--muted);font-size:13px;\">Expenses</span><b>${sum.expenses.toLocaleString()}</b></div>\n          </div>\n        </div>\n      </div>\n    </div>`;\n  const used = financeState.budget>0 ? Math.min(sum.expenses, financeState.budget) : 0;\n  const left = financeState.budget>0 ? Math.max(0, financeState.budget-sum.expenses) : 1;\n  if(financeState.budget>0){\n    drawDonut('budgetCanvas', [used,left], [sum.expenses>financeState.budget?'#D64545':THEMES[config.theme].primary, THEMES[config.theme].line], 0.75);\n  } else {\n    drawDonut('budgetCanvas', [1], [THEMES[config.theme].line], 0.75);\n  }\n}\n\nfunction renderFinAccounts(c){\n  let cards = financeState.accounts.map(a=>`\n    <div class=\"account-card\" onclick=\"editAccount('${a.id}')\">\n      <div class=\"aic\">${a.icon}</div>\n      <div class=\"atxt\"><div class=\"aname\">${escapeHtml(a.name)}</div><div class=\"atype\">${a.type} · ${a.currency}</div></div>\n      <div class=\"aamt\">${fmt(a.amount)}</div>\n    </div>`).join('');\n  cards += `<div class=\"add-account-card\" onclick=\"openAccountForm()\">+ Add Account</div>`;\n  c.innerHTML = `<div class=\"card\"><div class=\"card-head\"><h3>Accounts</h3></div><div class=\"acc-grid\">${cards}</div></div>`;\n}\n\n/* ---------- Add / Edit Transaction (modal) ---------- */\nlet addCtx = {kind:'expense', category:null, amountStr:'0', date:todayStr(), note:'', accountId:null, toAccountId:null, editingId:null, groceryItems:[]};\nlet kpKeyHandler = null;\n\nfunction openAddTransaction(kind){\n  addCtx = {kind, category:null, amountStr:'0', date:todayStr(), note:'', accountId: financeState.accounts[0]?.id||null, toAccountId:null, editingId:null, groceryItems:[]};\n  const wrap = openModal('');\n  drawAddStep1(wrap);\n}\nfunction drawAddStep1(wrap){\n  const dlg = wrap.querySelector('.dialog');\n  wrap.classList.add('sheet-overlay');\n  dlg.classList.add('sheet');\n  const isTransfer = addCtx.kind==='transfer';\n  let body;\n  if(isTransfer){\n    body = `<div class=\"transfer-form\">\n      <div class=\"field\"><label>From Account</label><select id=\"fromAcc\">${financeState.accounts.map(a=>`<option value=\"${a.id}\">${escapeHtml(a.name)}</option>`).join('')}</select></div>\n      <div class=\"field\"><label>To Account</label><select id=\"toAcc\">${financeState.accounts.map(a=>`<option value=\"${a.id}\">${escapeHtml(a.name)}</option>`).join('')}</select></div>\n      <button class=\"save-btn\" onclick=\"proceedTransferAmount()\">Continue</button>\n    </div>`;\n  } else {\n    const cats = addCtx.kind==='expense' ? EXPENSE_CATS : INCOME_CATS;\n    body = `<div class=\"cat-grid\">${cats.map(cat=>`<button class=\"cat-cell\" onclick=\"pickCategory('${cat.name}')\"><div class=\"cc-ic\" style=\"background:${catColor(cat.name)}22;\">${cat.icon}</div><div class=\"cc-lbl\">${cat.name}</div></button>`).join('')}</div>`;\n  }\n  dlg.innerHTML = `\n    <div class=\"dialog-header\"><button class=\"txt-btn\" onclick=\"closeTopModal()\">Cancel</button><h2>Add</h2><div style=\"width:50px\"></div></div>\n    <div class=\"kind-tabs\" style=\"display:flex;border:1.5px solid var(--ink);border-radius:10px;overflow:hidden;margin:14px 16px 10px 16px;\">\n      ${['expense','income','transfer'].map(k=>`<button style=\"flex:1;padding:10px 0;border:none;font-weight:700;font-size:13.5px;cursor:pointer;background:${addCtx.kind===k?'var(--ink)':'var(--primary)'};color:${addCtx.kind===k?'var(--primary)':'var(--ink)'};\" onclick=\"switchAddKind('${k}')\">${k[0].toUpperCase()+k.slice(1)}</button>`).join('')}\n    </div>\n    <div class=\"dialog-scroll\">${body}</div>\n  `;\n}\nfunction switchAddKind(kind){ addCtx.kind=kind; addCtx.category=null; drawAddStep1(document.querySelector('#modal-root .overlay')); }\nfunction pickCategory(name){ addCtx.category = name; if(!GROCERY_FAMILY_CATS.includes(name)){ addCtx.groceryItems=[]; } renderAddStep2(); }\nfunction proceedTransferAmount(){\n  const wrap = document.querySelector('#modal-root .overlay');\n  addCtx.accountId = wrap.querySelector('#fromAcc').value;\n  addCtx.toAccountId = wrap.querySelector('#toAcc').value;\n  if(addCtx.accountId===addCtx.toAccountId){ showToast('Choose two different accounts'); return; }\n  renderAddStep2();\n}\nfunction renderAddStep2(){\n  const wrap = document.querySelector('#modal-root .overlay');\n  const dlg = wrap.querySelector('.dialog');\n  wrap.classList.add('sheet-overlay');\n  dlg.classList.add('sheet');\n  const isTransfer = addCtx.kind==='transfer';\n  const cats = addCtx.kind==='expense'?EXPENSE_CATS:INCOME_CATS;\n  const icon = isTransfer?'🔁':findIcon(cats, addCtx.category);\n  const color = isTransfer?'#8A8A8E':catColor(addCtx.category);\n  const accOptions = financeState.accounts.map(a=>`<option value=\"${a.id}\" ${a.id===addCtx.accountId?'selected':''}>${escapeHtml(a.name)}</option>`).join('');\n  dlg.innerHTML = `\n    <div class=\"dialog-header\"><button class=\"txt-btn\" onclick=\"drawAddStep1(document.querySelector('#modal-root .overlay'))\">‹ Back</button><h2>${isTransfer?'Transfer':(addCtx.category||'')}</h2><button class=\"txt-btn\" style=\"font-weight:800;\" onclick=\"saveTransaction()\">Save</button></div>\n    <div class=\"dialog-scroll\">\n      <div class=\"amount-display\">\n        <div class=\"cat-tag\"><span class=\"tag-ic\" style=\"background:${color}\">${icon}</span>${isTransfer?'Transfer':addCtx.category}</div>\n        <div class=\"num\" id=\"amountNum\">${currencySymbol()}${addCtx.amountStr}</div>\n      </div>\n      <div class=\"keypad\" id=\"keypad\"></div>\n      <div class=\"field\" style=\"margin:16px 16px 0 16px;\"><label>Date</label><input type=\"date\" id=\"txnDate\" value=\"${addCtx.date}\"></div>\n      ${!isTransfer ? `<div class=\"field\" style=\"margin:14px 16px;\"><label>Account</label><select id=\"txnAccount\">${accOptions}</select></div>` : ''}\n      <div class=\"field\" style=\"margin:14px 16px;\"><label>Note</label><input type=\"text\" id=\"txnNote\" placeholder=\"Add a note\" value=\"${escapeHtml(addCtx.note)}\"></div>\n      ${(!isTransfer && GROCERY_FAMILY_CATS.includes(addCtx.category)) ? buildGroceryItemsSectionHtml() : ''}\n    </div>\n  `;\n  buildKeypad();\n  dlg.querySelector('#txnDate').addEventListener('change', e=>addCtx.date=e.target.value);\n  dlg.querySelector('#txnNote').addEventListener('input', e=>addCtx.note=e.target.value);\n  const accSel = dlg.querySelector('#txnAccount');\n  if(accSel) accSel.addEventListener('change', e=>addCtx.accountId=e.target.value);\n  if(GROCERY_FAMILY_CATS.includes(addCtx.category)){ initGroceryItemPicker(); renderGroceryItemChips(); }\n\n  document.removeEventListener('keydown', kpKeyHandler);\n  kpKeyHandler = (e)=>{\n    if(document.activeElement && ['INPUT','SELECT','TEXTAREA'].includes(document.activeElement.tagName)) return;\n    if(/^[0-9]$/.test(e.key)) kpPress(e.key);\n    else if(e.key==='.') kpPress('.');\n    else if(e.key==='Backspace') kpPress('⌫');\n    else if(e.key==='Enter') saveTransaction();\n  };\n  document.addEventListener('keydown', kpKeyHandler);\n}\n/* Builds the single, unified \"Add Items\" section shown for Groceries,\n   Vegetables, Fruits, and Snacks transactions. Combines what used to be\n   two separate optional sections (a grocery category/item tag, and a\n   perishable-goods list) into one: pick an item, optionally give it an\n   expiry date. Items with a date are also tracked in Grocery Expiry\n   Reminder; items left without a date are just a label on the purchase. */\nfunction buildGroceryItemsSectionHtml(){\n  const scope = getGroceryItemScope(addCtx.category);\n  if(!scope) return '';\n  const subcatPicker = scope.mode==='subcategory' ? `\n    <div class=\"field\" style=\"margin:0 0 10px;\"><label>Category</label>\n      <select id=\"grocSubcatSelect\" onchange=\"onGrocSubcatChange()\">\n        <option value=\"\">— Select a category —</option>\n        ${scope.subcats.map(c=>`<option value=\"${c.name}\">${c.icon} ${c.name}</option>`).join('')}\n      </select>\n    </div>` : '';\n  const initialItemOptions = scope.mode==='direct'\n    ? buildGrocItemSelectOptions(scope.items)\n    : `<option value=\"\">— Select a category first —</option>`;\n  return `\n    <div class=\"card\" style=\"margin:16px;padding:14px 16px;\">\n      <div style=\"font-weight:800;font-size:13.5px;margin-bottom:2px;\">🛒 Add Items (optional)</div>\n      <div style=\"font-size:12px;color:var(--muted);margin-bottom:12px;\">Tag specific items from this purchase. Give an item an expiry date to also track it in Grocery Expiry Reminder — leave the date blank to just label the purchase.</div>\n      ${subcatPicker}\n      <div class=\"field\" style=\"margin:0 0 10px;\"><label>Item</label>\n        <select id=\"grocItemSelect\" onchange=\"onGrocItemPickChange()\">${initialItemOptions}</select>\n      </div>\n      <div class=\"field hidden\" id=\"grocItemCustomWrap\" style=\"margin:0 0 10px;\"><input type=\"text\" id=\"grocItemCustomName\" placeholder=\"Item name\"></div>\n      <div class=\"perishable-add-row grocery-item-expiry-row\">\n        <div class=\"field\" style=\"margin:0;\"><label>Expiry Date (optional)</label><input type=\"date\" id=\"grocItemExpiry\"></div>\n        <button type=\"button\" class=\"btn-outline\" style=\"align-self:end;\" onclick=\"addGroceryItemChip()\">+ Add</button>\n      </div>\n      <div id=\"groceryItemChips\" class=\"perishable-chip-list\" style=\"margin-top:12px;\"></div>\n    </div>`;\n}\nfunction buildGrocItemSelectOptions(items){\n  let opts = items.map(it=>`<option value=\"${it.name}\">${it.icon} ${it.name}</option>`).join('');\n  opts += `<option value=\"__others__\">➕ Others (type below)</option>`;\n  return opts;\n}\nfunction initGroceryItemPicker(){\n  const scope = getGroceryItemScope(addCtx.category);\n  if(!scope || scope.mode!=='subcategory') return;\n  const subSel = document.getElementById('grocSubcatSelect');\n  if(subSel) subSel.value = '';\n  const itemSel = document.getElementById('grocItemSelect');\n  if(itemSel) itemSel.innerHTML = `<option value=\"\">— Select a category first —</option>`;\n}\nfunction onGrocSubcatChange(){\n  const subSel = document.getElementById('grocSubcatSelect');\n  const itemSel = document.getElementById('grocItemSelect');\n  if(!subSel || !itemSel) return;\n  const cat = GROCERY_CATEGORIES.find(c=>c.name===subSel.value);\n  itemSel.innerHTML = cat ? buildGrocItemSelectOptions(cat.items) : `<option value=\"\">— Select a category first —</option>`;\n  onGrocItemPickChange();\n}\nfunction onGrocItemPickChange(){\n  const itemSel = document.getElementById('grocItemSelect');\n  const customWrap = document.getElementById('grocItemCustomWrap');\n  if(!itemSel || !customWrap) return;\n  customWrap.classList.toggle('hidden', itemSel.value!=='__others__');\n}\nfunction addGroceryItemChip(){\n  const scope = getGroceryItemScope(addCtx.category);\n  if(!scope) return;\n  const itemSel = document.getElementById('grocItemSelect');\n  const customEl = document.getElementById('grocItemCustomName');\n  const expEl = document.getElementById('grocItemExpiry');\n  let category, name, icon;\n  if(scope.mode==='subcategory'){\n    const subSel = document.getElementById('grocSubcatSelect');\n    category = subSel ? subSel.value : '';\n    if(!category){ showToast('Choose a category first'); return; }\n    const cat = GROCERY_CATEGORIES.find(c=>c.name===category);\n    if(itemSel.value==='__others__'){\n      name = customEl.value.trim(); icon = '🥡';\n    } else {\n      const it = cat ? cat.items.find(i=>i.name===itemSel.value) : null;\n      name = itemSel.value; icon = it ? it.icon : '🥡';\n    }\n  } else {\n    category = scope.categoryName;\n    if(itemSel.value==='__others__'){\n      name = customEl.value.trim(); icon = '🥡';\n    } else {\n      const it = scope.items.find(i=>i.name===itemSel.value);\n      name = itemSel.value; icon = it ? it.icon : scope.icon;\n    }\n  }\n  if(!name){ showToast('Choose or type an item name'); return; }\n  const expiryDate = expEl.value || '';\n  addCtx.groceryItems.push({id:uid(), name, category, icon, expiryDate, groceryReminderId:null});\n  if(customEl) customEl.value='';\n  if(expEl) expEl.value='';\n  renderGroceryItemChips();\n}\nfunction removeGroceryItemChip(id){\n  const idx = addCtx.groceryItems.findIndex(p=>p.id===id);\n  if(idx<0) return;\n  const item = addCtx.groceryItems[idx];\n  if(item.groceryReminderId){\n    groceryReminders = groceryReminders.filter(g=>g.id!==item.groceryReminderId);\n    saveGroceryRem();\n  }\n  addCtx.groceryItems.splice(idx,1);\n  renderGroceryItemChips();\n}\nfunction renderGroceryItemChips(){\n  const el = document.getElementById('groceryItemChips');\n  if(!el) return;\n  if(!addCtx.groceryItems || addCtx.groceryItems.length===0){\n    el.innerHTML = '<div style=\"font-size:12px;color:var(--muted);\">No items added yet.</div>';\n    return;\n  }\n  el.innerHTML = addCtx.groceryItems.map(p=>{\n    const expiryLabel = p.expiryDate ? `<small>🔔 ${new Date(p.expiryDate+'T00:00:00').toLocaleDateString(undefined,{day:'2-digit',month:'short'})}</small>` : '';\n    return `<span class=\"perishable-chip\">${p.icon||'🥡'} ${escapeHtml(p.name)} ${expiryLabel} <button type=\"button\" onclick=\"removeGroceryItemChip('${p.id}')\">✕</button></span>`;\n  }).join('');\n}\nfunction buildKeypad(){\n  const kp = document.getElementById('keypad');\n  const keys = ['1','2','3','4','5','6','7','8','9','.','0','⌫'];\n  kp.innerHTML = keys.map(k=>`<button class=\"${k==='⌫'?'op':''}\" onclick=\"kpPress('${k}')\">${k}</button>`).join('');\n}\nfunction kpPress(k){\n  if(k==='⌫') addCtx.amountStr = addCtx.amountStr.length>1 ? addCtx.amountStr.slice(0,-1) : '0';\n  else if(k==='.'){ if(!addCtx.amountStr.includes('.')) addCtx.amountStr += '.'; }\n  else { addCtx.amountStr = (addCtx.amountStr==='0')?k:addCtx.amountStr+k; if(addCtx.amountStr.length>12) addCtx.amountStr=addCtx.amountStr.slice(0,12); }\n  const el = document.getElementById('amountNum');\n  if(el) el.textContent = currencySymbol()+addCtx.amountStr;\n}\nfunction saveTransaction(){\n  const amount = parseFloat(addCtx.amountStr)||0;\n  if(amount<=0){ showToast('Enter an amount greater than 0'); return; }\n  let txnRef = null;\n  if(addCtx.kind==='transfer'){\n    const fromAcc = financeState.accounts.find(a=>a.id===addCtx.accountId);\n    const toAcc = financeState.accounts.find(a=>a.id===addCtx.toAccountId);\n    if(fromAcc) fromAcc.amount -= amount;\n    if(toAcc) toAcc.amount += amount;\n    financeState.transactions.push({id:addCtx.editingId||uid(), kind:'transfer', category:'Transfer', amount, date:addCtx.date, time:new Date().toTimeString().slice(0,8), note:addCtx.note, accountId:addCtx.accountId, toAccountId:addCtx.toAccountId});\n  } else {\n    if(addCtx.editingId){\n      const t = financeState.transactions.find(x=>x.id===addCtx.editingId);\n      const oldAcc = financeState.accounts.find(a=>a.id===t.accountId);\n      if(oldAcc) oldAcc.amount += (t.kind==='expense'?t.amount:-t.amount);\n      Object.assign(t, {kind:addCtx.kind, category:addCtx.category, amount, date:addCtx.date, note:addCtx.note, accountId:addCtx.accountId});\n      const newAcc = financeState.accounts.find(a=>a.id===t.accountId);\n      if(newAcc) newAcc.amount += (t.kind==='expense'?-t.amount:t.amount);\n      txnRef = t;\n    } else {\n      const newTxn = {id:uid(), kind:addCtx.kind, category:addCtx.category, amount, date:addCtx.date, time:new Date().toTimeString().slice(0,8), note:addCtx.note, accountId:addCtx.accountId};\n      financeState.transactions.push(newTxn);\n      const acc = financeState.accounts.find(a=>a.id===addCtx.accountId);\n      if(acc) acc.amount += (addCtx.kind==='expense'?-amount:amount);\n      txnRef = newTxn;\n    }\n  }\n\n  if(txnRef){\n    if(addCtx.kind==='expense' && GROCERY_FAMILY_CATS.includes(addCtx.category) && addCtx.groceryItems && addCtx.groceryItems.length>0){\n      // Create a Grocery Expiry Reminder entry for any tagged item that has\n      // an expiry date and doesn't already have one (new additions this\n      // session); items edited from an existing transaction that already\n      // have a groceryReminderId are left as-is to avoid duplicates. Items\n      // without an expiry date are just a label — no reminder created.\n      addCtx.groceryItems.forEach(p=>{\n        if(!p.expiryDate || p.groceryReminderId) return;\n        const groc = {id:uid(), category:p.category||GROCERY_OTHERS.name, item:p.name, icon:p.icon||'🥡', expiryDate:p.expiryDate, quantity:'', note:'', timingMode:'default', customAlertTime:null, customOffsets:null, alarmDurationSec:null, addedDate:todayStr(), fromTransactionId:txnRef.id};\n        groceryReminders.push(groc);\n        p.groceryReminderId = groc.id;\n      });\n      txnRef.groceryItems = addCtx.groceryItems.map(p=>({id:p.id, name:p.name, category:p.category, icon:p.icon, expiryDate:p.expiryDate, groceryReminderId:p.groceryReminderId}));\n      delete txnRef.groceryCategory; delete txnRef.groceryItem; delete txnRef.perishableItems;\n      saveGroceryRem();\n    } else {\n      const existing = getTxnGroceryItems(txnRef);\n      if(existing.length){\n        // Category was changed away from the grocery family (or all items\n        // were removed) while editing a transaction that previously had\n        // tagged items — unlink any linked reminders rather than delete\n        // them, so the reminders still stand on their own.\n        const idsToUnlink = existing.map(p=>p.groceryReminderId).filter(Boolean);\n        idsToUnlink.forEach(gid=>{ const g = groceryReminders.find(x=>x.id===gid); if(g) g.fromTransactionId=null; });\n        if(idsToUnlink.length) saveGroceryRem();\n      }\n      delete txnRef.groceryItems; delete txnRef.groceryCategory; delete txnRef.groceryItem; delete txnRef.perishableItems;\n    }\n  }\n\n  saveFinance();\n  document.removeEventListener('keydown', kpKeyHandler);\n  closeAllModals();\n  currentMonth = addCtx.date.slice(0,7);\n  renderFinTopbar(); renderFinContent();\n  showToast('Saved');\n}\n\nfunction openDetails(id){\n  const t = financeState.transactions.find(x=>x.id===id); if(!t) return;\n  const isTransfer = t.kind==='transfer';\n  const icon = isTransfer?'🔁':findIcon(t.kind==='expense'?EXPENSE_CATS:INCOME_CATS, t.category);\n  const color = isTransfer?'#8A8A8E':catColor(t.category);\n  const accName = financeState.accounts.find(a=>a.id===t.accountId)?.name || '—';\n  const taggedItems = getTxnGroceryItems(t);\n  const itemsHtml = taggedItems.length ? taggedItems.map(p=>`${escapeHtml(p.name)}${p.expiryDate?` <span class=\"exp-badge ${expiryStatus(p.expiryDate).cls}\">exp ${new Date(p.expiryDate+'T00:00:00').toLocaleDateString(undefined,{day:'2-digit',month:'short'})}</span>`:''}`).join(', ') : '';\n  openModal(`\n    <div class=\"dialog-header\"><button class=\"txt-btn\" onclick=\"closeTopModal()\">‹ Back</button><h2>Details</h2><div style=\"width:40px\"></div></div>\n    <div class=\"details-hero\"><div class=\"dh-ic\" style=\"background:${color}\">${icon}</div><div class=\"dh-name\">${isTransfer?'Transfer':t.category}</div></div>\n    <div class=\"detail-row\"><span class=\"dk\">Type</span><span class=\"dv\">${t.kind[0].toUpperCase()+t.kind.slice(1)}</span></div>\n    <div class=\"detail-row\"><span class=\"dk\">Amount</span><span class=\"dv\">${fmt(t.amount)}</span></div>\n    <div class=\"detail-row\"><span class=\"dk\">Account</span><span class=\"dv\">${escapeHtml(accName)}</span></div>\n    <div class=\"detail-row\"><span class=\"dk\">Date</span><span class=\"dv\">${new Date(t.date+'T00:00:00').toLocaleDateString(undefined,{day:'2-digit',month:'short',year:'numeric'})}</span></div>\n    ${t.note?`<div class=\"detail-row\"><span class=\"dk\">Note</span><span class=\"dv\">${escapeHtml(t.note)}</span></div>`:''}\n    ${itemsHtml?`<div class=\"detail-row\"><span class=\"dk\">Items</span><span class=\"dv\">${itemsHtml}</span></div>`:''}\n    <div class=\"two-btn\"><button class=\"btn-edit\" onclick=\"editTransaction('${t.id}')\">Edit</button><button class=\"btn-delete\" onclick=\"deleteTransaction('${t.id}')\">Delete</button></div>\n  `);\n}\nfunction editTransaction(id){\n  const t = financeState.transactions.find(x=>x.id===id); if(!t) return;\n  closeAllModals();\n  addCtx = {kind:t.kind, category:t.category, amountStr:String(t.amount), date:t.date, note:t.note||'', accountId:t.accountId, toAccountId:t.toAccountId||null, editingId:t.id, groceryItems: getTxnGroceryItems(t).map(p=>({...p}))};\n  openModal('');\n  renderAddStep2();\n}\nfunction deleteTransaction(id){\n  const t = financeState.transactions.find(x=>x.id===id); if(!t) return;\n  if(t.kind==='transfer'){\n    const fromAcc = financeState.accounts.find(a=>a.id===t.accountId);\n    const toAcc = financeState.accounts.find(a=>a.id===t.toAccountId);\n    if(fromAcc) fromAcc.amount += t.amount;\n    if(toAcc) toAcc.amount -= t.amount;\n  } else {\n    const acc = financeState.accounts.find(a=>a.id===t.accountId);\n    if(acc) acc.amount += (t.kind==='expense'?t.amount:-t.amount);\n  }\n  const taggedItems = getTxnGroceryItems(t);\n  if(taggedItems.length){\n    const idsToRemove = taggedItems.map(p=>p.groceryReminderId).filter(Boolean);\n    if(idsToRemove.length){\n      groceryReminders = groceryReminders.filter(g=>!idsToRemove.includes(g.id));\n      saveGroceryRem();\n    }\n  }\n  if(t.linkedShoppingId){\n    const shopItem = shoppingList.find(s=>s.id===t.linkedShoppingId);\n    if(shopItem) shopItem.linkedTransactionId = null;\n    saveShoppingList();\n  }\n  financeState.transactions = financeState.transactions.filter(x=>x.id!==id);\n  saveFinance(); closeAllModals(); renderFinTopbar(); renderFinContent();\n  showToast('Transaction deleted');\n}\n\n/* ---------- Accounts ---------- */\nfunction openAccountForm(existing){\n  const isEdit = !!existing;\n  const a = existing || {name:'', type:'Default', currency:config.currency, amount:0, icon:ACCOUNT_ICONS[0], excluded:false};\n  openModal(`\n    <div class=\"dialog-header\"><button class=\"txt-btn\" onclick=\"closeTopModal()\">Cancel</button><h2>${isEdit?'Edit Account':'Add Account'}</h2><button class=\"txt-btn\" style=\"font-weight:800;\" onclick=\"saveAccount(${isEdit?`'${a.id}'`:'null'})\">Save</button></div>\n    <div class=\"field\" style=\"margin:16px;\"><label>Account name</label><input id=\"accName\" type=\"text\" placeholder=\"Enter account name\" value=\"${escapeHtml(a.name)}\"></div>\n    <div class=\"field\" style=\"margin:14px 16px;\"><label>Type</label><select id=\"accType\">${['Default','Cash','Bank','Credit Card','Savings','Investment'].map(t=>`<option ${t===a.type?'selected':''}>${t}</option>`).join('')}</select></div>\n    <div class=\"field\" style=\"margin:14px 16px;\"><label>Currency</label><select id=\"accCurrency\">${CURRENCIES.map(c=>`<option value=\"${c.code}\" ${c.code===a.currency?'selected':''}>${c.code} ( ${c.sym} ) ${c.name}</option>`).join('')}</select></div>\n    <div class=\"field\" style=\"margin:14px 16px;\"><label>Amount</label><input id=\"accAmount\" type=\"number\" value=\"${a.amount}\"></div>\n    <div class=\"field\" style=\"margin:14px 16px;\"><label>Icon</label><div class=\"icon-picker\">${ACCOUNT_ICONS.map(ic=>`<button type=\"button\" class=\"ip-cell ${ic===a.icon?'selected':''}\" data-icon=\"${ic}\" onclick=\"selectAccIcon(this)\">${ic}</button>`).join('')}</div></div>\n    ${isEdit?`<div style=\"margin:14px 16px 26px;\"><button class=\"save-btn danger-btn\" style=\"width:100%;margin:0;\" onclick=\"deleteAccount('${a.id}')\">Delete Account</button></div>`:'<div style=\"height:16px\"></div>'}\n  `);\n}\nfunction selectAccIcon(btn){ btn.parentElement.querySelectorAll('.ip-cell').forEach(b=>b.classList.remove('selected')); btn.classList.add('selected'); }\nfunction saveAccount(id){\n  const wrap = document.querySelector('#modal-root .overlay');\n  const name = wrap.querySelector('#accName').value.trim()||'Account';\n  const type = wrap.querySelector('#accType').value;\n  const currency = wrap.querySelector('#accCurrency').value;\n  const amount = parseFloat(wrap.querySelector('#accAmount').value)||0;\n  const icon = wrap.querySelector('.ip-cell.selected')?.dataset.icon || ACCOUNT_ICONS[0];\n  if(id){ Object.assign(financeState.accounts.find(a=>a.id===id), {name,type,currency,amount,icon}); }\n  else { financeState.accounts.push({id:uid(), name, type, currency, amount, icon, excluded:false}); }\n  saveFinance(); closeAllModals(); renderFinContent();\n  showToast('Account saved');\n}\nfunction editAccount(id){ openAccountForm(financeState.accounts.find(a=>a.id===id)); }\nfunction deleteAccount(id){\n  if(financeState.accounts.length<=1){ showToast('You need at least one account'); return; }\n  financeState.accounts = financeState.accounts.filter(a=>a.id!==id);\n  financeState.transactions = financeState.transactions.filter(t=>t.accountId!==id && t.toAccountId!==id);\n  saveFinance(); closeAllModals(); renderFinContent();\n  showToast('Account deleted');\n}\n\n/* ---------- Budget ---------- */\nfunction openBudgetEditor(){\n  openModal(`\n    <div class=\"dialog-header\"><button class=\"txt-btn\" onclick=\"closeTopModal()\">Cancel</button><h2>Monthly Budget</h2><button class=\"txt-btn\" style=\"font-weight:800;\" onclick=\"saveBudget()\">Save</button></div>\n    <div class=\"field\" style=\"margin:18px 16px;\"><label>Budget amount</label><input id=\"budgetInput\" type=\"number\" value=\"${financeState.budget}\"></div>\n  `);\n}\nfunction saveBudget(){\n  const wrap = document.querySelector('#modal-root .overlay');\n  financeState.budget = parseFloat(wrap.querySelector('#budgetInput').value)||0;\n  saveFinance(); closeAllModals(); renderFinContent();\n  showToast('Budget updated');\n}\n\n/* ---------- Search ---------- */\nfunction openSearch(){\n  const wrap = openModal(`\n    <div class=\"dialog-header\"><button class=\"txt-btn\" onclick=\"closeTopModal()\">Close</button><h2>Search</h2><div style=\"width:40px\"></div></div>\n    <div class=\"field\" style=\"margin:16px;\"><input id=\"searchInput\" type=\"text\" placeholder=\"Search by category or note\" autofocus></div>\n    <div id=\"searchResults\" style=\"max-height:340px;overflow-y:auto;padding:0 8px 12px;\"></div>\n  `);\n  wrap.querySelector('#searchInput').addEventListener('input', e=>{\n    const q = e.target.value.trim().toLowerCase();\n    const res = document.getElementById('searchResults');\n    if(!q){ res.innerHTML=''; return; }\n    const matches = financeState.transactions.filter(t=>(t.category||'').toLowerCase().includes(q)||(t.note||'').toLowerCase().includes(q)).sort((a,b)=>(b.date+b.time).localeCompare(a.date+a.time)).slice(0,30);\n    if(matches.length===0){ res.innerHTML = `<div class=\"empty-state\"><div>No matches</div></div>`; return; }\n    res.innerHTML = matches.map(t=>{\n      const icon = t.kind==='transfer'?'🔁':findIcon(t.kind==='expense'?EXPENSE_CATS:INCOME_CATS, t.category);\n      const color = t.kind==='transfer'?'#8A8A8E':catColor(t.category);\n      return `<div class=\"txn-row\" onclick=\"closeAllModals();openDetails('${t.id}')\">\n        <div class=\"cat-circle\" style=\"background:${color}\">${icon}</div>\n        <div class=\"txn-info\"><div class=\"cat\">${t.kind==='transfer'?'Transfer':t.category}</div><div class=\"note\">${t.date} ${t.note?'· '+escapeHtml(t.note):''}</div></div>\n        <div class=\"txn-amt ${t.kind==='income'?'income':'expense'}\">${t.kind==='income'?'+':'-'}${fmt(t.amount)}</div>\n      </div>`;\n    }).join('');\n  });\n}\n\n/* ---------- Calendar ---------- */\nfunction openCalendar(){ const [y,mo]=currentMonth.split('-').map(Number); drawCalendar(y,mo); }\nfunction drawCalendar(y,mo){\n  const first = new Date(y,mo-1,1);\n  const startDow = first.getDay();\n  const daysInMonth = new Date(y,mo,0).getDate();\n  const dayTotals = {};\n  financeState.transactions.forEach(t=>{\n    if(t.kind==='expense' && t.date.slice(0,7)===`${y}-${String(mo).padStart(2,'0')}`){\n      const day = parseInt(t.date.slice(8,10)); dayTotals[day]=(dayTotals[day]||0)+t.amount;\n    }\n  });\n  const dows=['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];\n  let cells = dows.map(d=>`<div class=\"cal-dow\">${d}</div>`).join('');\n  for(let i=0;i<startDow;i++) cells += `<div class=\"cal-cell empty\"></div>`;\n  const isCurMonth = monthKey(new Date())===`${y}-${String(mo).padStart(2,'0')}`;\n  for(let d=1; d<=daysInMonth; d++){\n    const isToday = isCurMonth && d===new Date().getDate();\n    cells += `<div class=\"cal-cell ${isToday?'today':''}\" onclick=\"calDayPick(${y},${mo})\">${d}${dayTotals[d]?`<div class=\"amt\">${dayTotals[d].toLocaleString()}</div>`:''}</div>`;\n  }\n  openModal(`\n    <div class=\"dialog-header\"><button class=\"txt-btn\" onclick=\"shiftCal(${y},${mo},-1)\">‹</button><h2>${first.toLocaleDateString(undefined,{month:'long',year:'numeric'})}</h2><button class=\"txt-btn\" onclick=\"shiftCal(${y},${mo},1)\">›</button></div>\n    <div class=\"cal-grid\">${cells}</div>\n    <div style=\"text-align:center;padding-bottom:20px;\"><button class=\"txt-btn\" style=\"color:var(--primary-dark);font-weight:700;\" onclick=\"closeTopModal()\">Close</button></div>\n  `);\n}\nfunction shiftCal(y,mo,delta){ closeTopModal(); let d=new Date(y,mo-1+delta,1); setTimeout(()=>drawCalendar(d.getFullYear(), d.getMonth()+1), 200); }\nfunction calDayPick(y,mo){ currentMonth = `${y}-${String(mo).padStart(2,'0')}`; closeAllModals(); renderFinTopbar(); renderFinContent(); }\n\n/* ---------- Import / Scan transactions directly into Finance Tracker ---------- */\n/* Reuses the same lazy-loaded Excel/PDF/OCR engines as List to Buy (see\n   ensureXlsxLibLoaded / ensurePdfLibLoaded / ensureOcrLibLoaded below) —\n   CSV/TXT always works offline; Excel, PDF, and photo scans need internet\n   the first time to fetch their reader/recognition engine. */\nfunction normalizeDateStr(s){\n  s = (s||'').trim();\n  if(/^\\d{4}-\\d{2}-\\d{2}$/.test(s)) return s;\n  const m = s.match(/^(\\d{1,2})[\\/\\-.](\\d{1,2})[\\/\\-.](\\d{2,4})$/);\n  if(m){\n    let [,d,mo,y] = m;\n    if(y.length===2) y = (parseInt(y,10)>50?'19':'20')+y;\n    return y+'-'+String(mo).padStart(2,'0')+'-'+String(d).padStart(2,'0');\n  }\n  return null;\n}\nfunction parseTransactionText(text){\n  const lines = text.split(/\\r?\\n/).map(l=>l.trim()).filter(Boolean);\n  const rows = [];\n  lines.forEach(line=>{\n    const lower = line.toLowerCase();\n    if(/^date\\b/.test(lower) && lower.includes('amount')) return; // header row\n    if(/^[A-Z\\s\\/&(),.-]+$/.test(line) && !/\\d/.test(line) && line.replace(/\\s/g,'').length>3) return; // ALL-CAPS section header\n\n    let parts = null;\n    if(line.includes('\\t')) parts = line.split('\\t');\n    else if(line.includes(',')) parts = line.split(',');\n\n    let date=null, kind=null, category='', amount='', note='';\n    if(parts && parts.length>=2){\n      parts = parts.map(p=>p.trim()).filter(p=>p!=='');\n      const leftover = [];\n      parts.forEach(p=>{\n        const d = normalizeDateStr(p);\n        if(d && !date){ date=d; return; }\n        if(/^(expense|debit|dr|spent|paid)$/i.test(p)){ kind='expense'; return; }\n        if(/^(income|credit|cr|received|earned)$/i.test(p)){ kind='income'; return; }\n        if(!amount){\n          const priceInfo = extractPrice(p);\n          if(priceInfo.price){ amount = priceInfo.price; if(priceInfo.rest) leftover.push(priceInfo.rest); return; }\n          if(/^-?\\d+(\\.\\d+)?$/.test(p)){ amount = Math.abs(parseFloat(p)); if(parseFloat(p)<0) kind = kind||'expense'; return; }\n        }\n        leftover.push(p);\n      });\n      if(leftover.length){ category = leftover[0]; note = leftover.slice(1).join(' '); }\n    } else {\n      const priceInfo = extractPrice(line);\n      if(priceInfo.price){ amount = priceInfo.price; note = priceInfo.rest.trim(); }\n    }\n    if(amount){ rows.push({date: date||todayStr(), kind: kind||'expense', category: category||'Others', amount, note}); }\n  });\n  return rows;\n}\nasync function parseTransactionsFromExcel(file){\n  await ensureXlsxLibLoaded();\n  const buf = await file.arrayBuffer();\n  const wb = XLSX.read(buf, {type:'array'});\n  let allText = '';\n  wb.SheetNames.forEach(name=>{ allText += XLSX.utils.sheet_to_csv(wb.Sheets[name]) + '\\n'; });\n  return parseTransactionText(allText);\n}\nasync function parseTransactionsFromPdf(file){\n  await ensurePdfLibLoaded();\n  const buf = await file.arrayBuffer();\n  const doc = await pdfjsLib.getDocument({data:buf}).promise;\n  let allLines = [];\n  for(let i=1;i<=doc.numPages;i++){\n    const page = await doc.getPage(i);\n    const content = await page.getTextContent();\n    const items = content.items.map(it=>({str:it.str, x:it.transform[4], y:it.transform[5]}));\n    items.sort((a,b)=> b.y-a.y || a.x-b.x);\n    let lines=[], currentY=null, currentLine=[];\n    items.forEach(it=>{\n      if(currentY===null || Math.abs(it.y-currentY)>3){ if(currentLine.length) lines.push(currentLine.map(s=>s.str).join(' ')); currentLine=[it]; currentY=it.y; }\n      else currentLine.push(it);\n    });\n    if(currentLine.length) lines.push(currentLine.map(s=>s.str).join(' '));\n    allLines = allLines.concat(lines);\n  }\n  let rows = parseTransactionText(allLines.join('\\n'));\n  if(rows.length===0 && doc.numPages>0){\n    await ensureOcrLibLoaded();\n    const page = await doc.getPage(1);\n    const viewport = page.getViewport({scale:2});\n    const canvas = document.createElement('canvas');\n    canvas.width = viewport.width; canvas.height = viewport.height;\n    const ctx = canvas.getContext('2d');\n    await page.render({canvasContext:ctx, viewport}).promise;\n    const result = await Tesseract.recognize(canvas.toDataURL('image/png'), 'eng');\n    rows = parseTransactionText((result && result.data && result.data.text) || '');\n  }\n  return rows;\n}\nfunction triggerFinImportFile(){ document.getElementById('finImportInput').click(); }\nfunction handleFinImportFile(file){\n  if(!file) return;\n  const name = (file.name||'').toLowerCase();\n  const type = file.type||'';\n  document.getElementById('finImportInput').value = '';\n  if(type.startsWith('image/') || /\\.(png|jpe?g|webp)$/i.test(name)){\n    const reader = new FileReader();\n    reader.onload = (e)=>{ finScanImageDataUrl = e.target.result; openFinScanPreviewModal(); };\n    reader.readAsDataURL(file);\n    return;\n  }\n  if(/\\.(xlsx|xls)$/i.test(name)){\n    showToast('Reading spreadsheet…');\n    parseTransactionsFromExcel(file).then(rows=>{\n      if(rows.length===0){ showToast('No transactions found in that spreadsheet'); return; }\n      openTxnImportReviewModal(rows);\n    }).catch(()=> showToast('Could not read the spreadsheet — needs internet the first time. Try again, or use CSV instead.'));\n    return;\n  }\n  if(/\\.pdf$/i.test(name)){\n    showToast('Reading PDF…');\n    parseTransactionsFromPdf(file).then(rows=>{\n      if(rows.length===0){ showToast('No transactions found in that PDF'); return; }\n      openTxnImportReviewModal(rows);\n    }).catch(()=> showToast('Could not read the PDF — needs internet the first time. Try again, or use CSV instead.'));\n    return;\n  }\n  const reader = new FileReader();\n  reader.onload = (e)=>{\n    const rows = parseTransactionText(String(e.target.result||''));\n    if(rows.length===0){ showToast('No transactions found in that file'); return; }\n    openTxnImportReviewModal(rows);\n  };\n  reader.readAsText(file);\n}\nlet finScanImageDataUrl = null;\nfunction triggerFinScanFile(){ document.getElementById('finScanInput').click(); }\nfunction handleFinScanFile(file){\n  if(!file) return;\n  const reader = new FileReader();\n  reader.onload = (e)=>{ finScanImageDataUrl = e.target.result; document.getElementById('finScanInput').value=''; openFinScanPreviewModal(); };\n  reader.readAsDataURL(file);\n}\nfunction openFinScanPreviewModal(){\n  openModal(`\n    <div class=\"dialog-header\"><button class=\"txt-btn\" onclick=\"closeTopModal()\">Cancel</button><h2>Scan Receipt / Document</h2><div style=\"width:40px\"></div></div>\n    <div style=\"padding:16px;\">\n      <img src=\"${finScanImageDataUrl}\" style=\"width:100%;max-height:280px;object-fit:contain;background:#000;border-radius:10px;margin-bottom:12px;\" />\n      <p style=\"font-size:12.5px;color:var(--muted);margin:0 0 12px;\">Text recognition needs internet the first time to load its engine. Works best on printed receipts/statements — handwriting accuracy is limited, so review the amounts before adding.</p>\n      <div id=\"finScanStatus\" style=\"font-size:13px;color:var(--muted);margin-bottom:10px;min-height:18px;\"></div>\n      <button class=\"save-btn\" style=\"margin:0;width:100%;\" id=\"finScanExtractBtn\" onclick=\"runOcrForFinance()\">🔎 Extract Transactions</button>\n    </div>\n  `);\n}\nasync function runOcrForFinance(){\n  const statusEl = document.getElementById('finScanStatus');\n  const btn = document.getElementById('finScanExtractBtn');\n  if(btn) btn.disabled = true;\n  if(statusEl) statusEl.textContent = 'Loading recognition engine…';\n  try{\n    await ensureOcrLibLoaded();\n    if(statusEl) statusEl.textContent = 'Reading text from the image… this can take a moment.';\n    const result = await Tesseract.recognize(finScanImageDataUrl, 'eng');\n    const text = (result && result.data && result.data.text) ? result.data.text : '';\n    const rows = parseTransactionText(text);\n    closeAllModals();\n    if(rows.length===0){ showToast('No transactions recognized — try Import Transactions instead, or add manually'); return; }\n    openTxnImportReviewModal(rows);\n  }catch(err){\n    if(statusEl) statusEl.textContent = '';\n    showToast('Could not load text recognition (no internet?) — try Import Transactions instead.');\n    if(btn) btn.disabled = false;\n  }\n}\n\n/* ---------- Review step before committing imported/scanned transactions ---------- */\nlet txnReviewRows = [];\nfunction openTxnImportReviewModal(rows){\n  txnReviewRows = rows.map(r=>{\n    const kind = r.kind==='income' ? 'income' : 'expense';\n    const cats = kind==='income' ? INCOME_CATS : EXPENSE_CATS;\n    const guessedCat = cats.find(c=>c.name.toLowerCase()===String(r.category||'').toLowerCase());\n    const note = guessedCat ? (r.note||'') : [r.category, r.note].filter(Boolean).join(' ').trim();\n    return { id:uid(), date: normalizeDateStr(r.date)||r.date||todayStr(), kind, category: guessedCat?guessedCat.name:cats[cats.length-1].name, amount:r.amount||'', note };\n  });\n  openModal('');\n  drawTxnImportReviewModal();\n}\nfunction drawTxnImportReviewModal(){\n  const wrap = document.querySelector('#modal-root .overlay');\n  const dlg = wrap.querySelector('.dialog');\n  const rowsHtml = txnReviewRows.map(r=>{\n    const cats = r.kind==='income' ? INCOME_CATS : EXPENSE_CATS;\n    return `<tr>\n      <td><input type=\"date\" value=\"${r.date}\" style=\"width:130px;\" onchange=\"updateTxnReviewRow('${r.id}','date',this.value)\"></td>\n      <td><select onchange=\"updateTxnReviewRow('${r.id}','kind',this.value)\">\n        <option value=\"expense\" ${r.kind==='expense'?'selected':''}>Expense</option>\n        <option value=\"income\" ${r.kind==='income'?'selected':''}>Income</option>\n      </select></td>\n      <td><select onchange=\"updateTxnReviewRow('${r.id}','category',this.value)\">${cats.map(c=>`<option value=\"${c.name}\" ${c.name===r.category?'selected':''}>${c.icon} ${c.name}</option>`).join('')}</select></td>\n      <td><input type=\"number\" step=\"0.01\" value=\"${escapeHtml(String(r.amount))}\" style=\"width:85px;\" onchange=\"updateTxnReviewRow('${r.id}','amount',this.value)\"></td>\n      <td><input type=\"text\" value=\"${escapeHtml(r.note)}\" style=\"width:140px;\" onchange=\"updateTxnReviewRow('${r.id}','note',this.value)\"></td>\n      <td><button class=\"icon-x\" onclick=\"removeTxnReviewRow('${r.id}')\">✕</button></td>\n    </tr>`;\n  }).join('');\n  dlg.innerHTML = `\n    <div class=\"dialog-header\"><button class=\"txt-btn\" onclick=\"closeTopModal()\">Cancel</button><h2>Review Transactions</h2><button class=\"txt-btn\" style=\"font-weight:800;\" onclick=\"proceedFromTxnReview()\">Add All (${txnReviewRows.length})</button></div>\n    <div style=\"padding:14px 16px;overflow-x:auto;\">\n      <p style=\"font-size:12.5px;color:var(--muted);margin:0 0 10px;\">Review and fix anything before adding — dates, categories, and amounts are all editable.</p>\n      <table class=\"shop-table\" style=\"min-width:640px;\">\n        <thead><tr><th>Date</th><th>Type</th><th>Category</th><th>Amount</th><th>Note</th><th></th></tr></thead>\n        <tbody>${rowsHtml || '<tr><td colspan=\"6\" style=\"text-align:center;color:var(--muted);padding:20px;\">No rows left</td></tr>'}</tbody>\n      </table>\n    </div>\n  `;\n}\nfunction updateTxnReviewRow(id, field, val){\n  const r=txnReviewRows.find(x=>x.id===id); if(!r) return;\n  r[field]=val;\n  if(field==='kind'){\n    const cats = val==='income' ? INCOME_CATS : EXPENSE_CATS;\n    if(!cats.find(c=>c.name===r.category)) r.category = cats[cats.length-1].name;\n    drawTxnImportReviewModal();\n  }\n}\nfunction removeTxnReviewRow(id){ txnReviewRows = txnReviewRows.filter(x=>x.id!==id); drawTxnImportReviewModal(); }\n\n/* Before actually committing the reviewed rows, scan each one for a likely\n   perishable item (matched against the same grocery category data used\n   elsewhere) and, if any are found, ask the customer whether to also track\n   them in Grocery Expiry Reminder — showing the total expense amount for\n   context. If nothing perishable is detected, skip straight to saving. */\nlet pendingPerishableMatches = [];\nfunction proceedFromTxnReview(){\n  const matches = [];\n  txnReviewRows.forEach(r=>{\n    const amount = parseFloat(r.amount)||0;\n    if(amount<=0) return;\n    const combined = (r.category||'') + ' ' + (r.note||'');\n    const m = findPerishableMatch(combined);\n    if(m) matches.push({rowId:r.id, matchedName:m.matchedName, category:m.category, icon:m.icon, checked:true, expiryDate: addDays(todayStr(),3)});\n  });\n  if(matches.length===0){ confirmTxnImportRows(); return; }\n  pendingPerishableMatches = matches;\n  openPerishableImportReviewModal();\n}\nfunction openPerishableImportReviewModal(){\n  openModal('');\n  drawPerishableImportReviewModal();\n}\nfunction drawPerishableImportReviewModal(){\n  const wrap = document.querySelector('#modal-root .overlay');\n  const dlg = wrap.querySelector('.dialog');\n  const total = txnReviewRows.reduce((s,r)=>s+(parseFloat(r.amount)||0),0);\n  const rowsHtml = pendingPerishableMatches.map(m=>`\n    <tr>\n      <td><input type=\"checkbox\" ${m.checked?'checked':''} onchange=\"togglePerishableMatch('${m.rowId}', this.checked)\"></td>\n      <td>${m.icon} ${escapeHtml(m.matchedName)}</td>\n      <td>${escapeHtml(m.category)}</td>\n      <td><input type=\"date\" value=\"${m.expiryDate}\" ${m.checked?'':'disabled'} onchange=\"updatePerishableMatchExpiry('${m.rowId}', this.value)\"></td>\n    </tr>`).join('');\n  dlg.innerHTML = `\n    <div class=\"dialog-header\"><h2>Perishable Items Found</h2><div style=\"width:1px\"></div></div>\n    <div style=\"padding:16px;\">\n      <div class=\"perishable-total-box\">Total Expense: ${fmt(total)}</div>\n      <p style=\"font-size:12.5px;color:var(--muted);margin:12px 0;\">We noticed some perishable items in what you imported. Check the ones you'd like tracked in Grocery Expiry Reminder, and confirm an expiry date for each. Anything left unchecked will still be added to Finance Tracker as a normal expense.</p>\n      <div style=\"overflow-x:auto;\">\n      <table class=\"shop-table\">\n        <thead><tr><th></th><th>Item</th><th>Category</th><th>Expiry Date</th></tr></thead>\n        <tbody>${rowsHtml}</tbody>\n      </table>\n      </div>\n    </div>\n    <div class=\"two-btn\">\n      <button class=\"btn-delete\" onclick=\"skipPerishableAndCommit()\">Skip — Just Add Expenses</button>\n      <button class=\"btn-edit\" onclick=\"confirmPerishableAndCommit()\">Add Checked & Save</button>\n    </div>\n  `;\n}\nfunction togglePerishableMatch(rowId, checked){\n  const m = pendingPerishableMatches.find(x=>x.rowId===rowId);\n  if(m) m.checked = checked;\n  drawPerishableImportReviewModal();\n}\nfunction updatePerishableMatchExpiry(rowId, val){\n  const m = pendingPerishableMatches.find(x=>x.rowId===rowId);\n  if(m) m.expiryDate = val;\n}\nfunction skipPerishableAndCommit(){\n  closeAllModals();\n  confirmTxnImportRows();\n}\nfunction confirmPerishableAndCommit(){\n  const checked = pendingPerishableMatches.filter(m=>m.checked);\n  for(const m of checked){ if(!m.expiryDate){ showToast('Please set an expiry date for '+m.matchedName); return; } }\n  closeAllModals();\n  confirmTxnImportRows(checked);\n}\nfunction confirmTxnImportRows(perishableSelections){\n  let count = 0;\n  let perishableCount = 0;\n  const accountId = financeState.accounts[0]?.id;\n  txnReviewRows.forEach(r=>{\n    const amount = parseFloat(r.amount)||0;\n    if(amount<=0) return;\n    const kind = r.kind==='income' ? 'income' : 'expense';\n    const txn = {id:uid(), kind, category:r.category||'Others', amount, date:r.date||todayStr(), time:new Date().toTimeString().slice(0,8), note:r.note||'', accountId};\n    financeState.transactions.push(txn);\n    const acc = financeState.accounts.find(a=>a.id===accountId);\n    if(acc) acc.amount += (kind==='expense'?-amount:amount);\n    count++;\n\n    if(perishableSelections && perishableSelections.length){\n      const match = perishableSelections.find(m=>m.rowId===r.id);\n      if(match){\n        const groc = {id:uid(), category:match.category, item:match.matchedName, icon:match.icon, expiryDate:match.expiryDate, quantity:'', note:'', timingMode:'default', customAlertTime:null, customOffsets:null, alarmDurationSec:null, addedDate:todayStr(), fromTransactionId:txn.id};\n        groceryReminders.push(groc);\n        txn.groceryItems = [{id:uid(), name:match.matchedName, category:match.category, icon:match.icon, expiryDate:match.expiryDate, groceryReminderId:groc.id}];\n        perishableCount++;\n      }\n    }\n  });\n  if(perishableCount>0) saveGroceryRem();\n  saveFinance();\n  closeAllModals();\n  renderFinTopbar(); renderFinContent();\n  showToast(count+' transaction(s) added'+(perishableCount?`, ${perishableCount} perishable item(s) added to Grocery Expiry Reminder`:''));\n}\n\n/* ============================================================\n   ================  REMINDER & TRACKING  ======================\n   ============================================================ */\nfunction renderReminderDashboard(){\n  const v = document.getElementById('view-reminderDashboard');\n  let cards = '';\n  if(config.features.expenseReminder) cards += `<div class=\"dash-card\" onclick=\"enterExpenseRem()\"><div class=\"dc-ic\">💳</div><h2>Expense Reminder</h2><p>Never miss a bill — track upcoming and paid expenses.</p></div>`;\n  if(config.features.medicineReminder) cards += `<div class=\"dash-card\" onclick=\"enterMedicineRem()\"><div class=\"dc-ic\">💊</div><h2>Medicine Reminder</h2><p>Set daily or weekly medicine schedules and mark doses taken.</p></div>`;\n  if(config.features.groceryExpiryReminder) cards += `<div class=\"dash-card\" onclick=\"enterGroceryRem()\"><div class=\"dc-ic\">🥦</div><h2>Grocery Expiry Reminder</h2><p>Pick a grocery item by category and track its expiry date.</p></div>`;\n  if(config.features.generalReminder) cards += `<div class=\"dash-card\" onclick=\"enterGeneralRem()\"><div class=\"dc-ic\">⏰</div><h2>General Reminder</h2><p>Wake-up alarms, meetings, or anything else you need to be reminded of.</p></div>`;\n  v.innerHTML = `<button class=\"back-btn\" onclick=\"goDashboard()\">← Back to Menu</button>\n    <div class=\"dash-wrap\"><h1>Reminder & Tracking</h1><p class=\"sub\">Choose a reminder type</p>\n    <div class=\"dash-cards\">${cards || '<p style=\"color:var(--muted)\">No reminder features enabled. Check the Admin Panel.</p>'}</div></div>`;\n}\n\n/* ---------- Expense Reminder ---------- */\nfunction offsetsLabel(offsets, lastLabel){\n  const sorted = offsets.slice().sort((a,b)=>b-a);\n  return sorted.map(o=> o===0 ? (lastLabel||'Due day') : (o===1?'1 day before':o+' days before')).join(', ');\n}\nfunction offsetCheckboxesHtml(selected, cls, lastLabel){\n  const opts = [[3,'3 days before'],[2,'2 days before'],[1,'1 day before'],[0,lastLabel||'Due day']];\n  return opts.map(([val,label])=>`<label><input type=\"checkbox\" class=\"${cls}\" value=\"${val}\" ${selected.includes(val)?'checked':''}>${label}</label>`).join('');\n}\nlet editingExpenseId = null;\nlet expenseSearchTerm = '';\nfunction renderExpenseRem(){\n  const v = document.getElementById('view-expenseRem');\n  v.innerHTML = `\n    <button class=\"back-btn\" onclick=\"enterReminderDashboard()\">← Back</button>\n    <div class=\"rem-shell\">\n      <div class=\"sub-title-row\"><h1>Expense Reminder</h1></div>\n      <div class=\"card\">\n        <div class=\"rem-form\">\n          <div class=\"field\" style=\"margin:0;\"><label>Expense Name</label><input id=\"eName\" type=\"text\" placeholder=\"e.g. Rent\"></div>\n          <div class=\"field\" style=\"margin:0;\"><label>Amount</label><input id=\"eAmt\" type=\"number\" placeholder=\"0\"></div>\n          <div class=\"field\" style=\"margin:0;\"><label>Due Date</label><input id=\"eDate\" type=\"date\"></div>\n        </div>\n\n        <label style=\"display:block;font-size:12px;font-weight:700;color:var(--muted);text-transform:uppercase;margin-bottom:8px;\">Reminder Timing</label>\n        <div class=\"segmented\" style=\"margin-bottom:14px;max-width:280px;\">\n          <button type=\"button\" class=\"mode-btn active\" data-mode=\"default\" onclick=\"setExpTimingMode('default')\">Default</button>\n          <button type=\"button\" class=\"mode-btn\" data-mode=\"custom\" onclick=\"setExpTimingMode('custom')\">Customize</button>\n        </div>\n        <div id=\"expDefaultHint\" class=\"hint-box\">Uses the admin panel's schedule — alerts at ${config.alertTime} on: ${offsetsLabel(config.expenseOffsets)}.</div>\n        <div id=\"expCustomFields\" class=\"hidden\">\n          <div class=\"field\"><label>Alert Time</label><input id=\"eCustomTime\" type=\"time\" value=\"${config.alertTime}\"></div>\n          <label style=\"display:block;font-size:12px;font-weight:700;color:var(--muted);text-transform:uppercase;margin-bottom:6px;\">Remind Me</label>\n          <div class=\"offset-check-row\">${offsetCheckboxesHtml(config.expenseOffsets, 'exp-offset-check')}</div>\n          <div class=\"field\"><label>Alarm Duration (seconds, 0 = ring until dismissed)</label><input id=\"eAlarmDur\" type=\"number\" min=\"0\" value=\"${config.alarmDurationSec}\"></div>\n        </div>\n\n        <div id=\"eFormActions\" style=\"display:flex;gap:10px;margin-top:6px;\">\n          <button class=\"primary-btn\" id=\"eSaveBtn\" onclick=\"saveExpenseRem()\">+ Save Reminder</button>\n        </div>\n      </div>\n      <div class=\"field\" style=\"margin:0 0 4px;\"><input id=\"eSearchInput\" type=\"text\" placeholder=\"🔍 Search expense reminders…\" oninput=\"expenseSearchTerm=this.value; drawExpenseRemList();\"></div>\n      <div id=\"eRemList\"></div>\n    </div>\n  `;\n  editingExpenseId = null;\n  drawExpenseRemList();\n}\nfunction setExpTimingMode(mode){\n  document.querySelectorAll('#view-expenseRem .mode-btn').forEach(b=>b.classList.toggle('active', b.dataset.mode===mode));\n  document.getElementById('expDefaultHint').classList.toggle('hidden', mode!=='default');\n  document.getElementById('expCustomFields').classList.toggle('hidden', mode!=='custom');\n}\nfunction saveExpenseRem(){\n  const name = document.getElementById('eName').value.trim();\n  const amount = parseFloat(document.getElementById('eAmt').value)||0;\n  const date = document.getElementById('eDate').value;\n  if(!name || !date){ showToast('Enter a name and due date'); return; }\n  const timingMode = document.querySelector('#view-expenseRem .mode-btn.active')?.dataset.mode || 'default';\n  let customAlertTime=null, customOffsets=null, alarmDurationSec=null;\n  if(timingMode==='custom'){\n    customAlertTime = document.getElementById('eCustomTime').value || config.alertTime;\n    customOffsets = Array.from(document.querySelectorAll('.exp-offset-check:checked')).map(c=>parseInt(c.value,10));\n    if(customOffsets.length===0) customOffsets = config.expenseOffsets.slice();\n    alarmDurationSec = parseInt(document.getElementById('eAlarmDur').value,10) || 0;\n  }\n  if(editingExpenseId){\n    const r = expenseReminders.find(x=>x.id===editingExpenseId);\n    if(r) Object.assign(r, {name, amount, date, timingMode, customAlertTime, customOffsets, alarmDurationSec});\n    showToast('Expense reminder updated');\n  } else {\n    expenseReminders.push({id:uid(), name, amount, date, paid:false, timingMode, customAlertTime, customOffsets, alarmDurationSec});\n    showToast('Expense reminder saved');\n  }\n  saveExpRem();\n  cancelEditExpense();\n  drawExpenseRemList();\n}\nfunction editExpenseReminder(id){\n  const r = expenseReminders.find(x=>x.id===id); if(!r) return;\n  editingExpenseId = id;\n  document.getElementById('eName').value = r.name;\n  document.getElementById('eAmt').value = r.amount;\n  document.getElementById('eDate').value = r.date;\n  setExpTimingMode(r.timingMode==='custom' ? 'custom' : 'default');\n  if(r.timingMode==='custom'){\n    document.getElementById('eCustomTime').value = r.customAlertTime||config.alertTime;\n    document.querySelectorAll('.exp-offset-check').forEach(c=>{ c.checked = (r.customOffsets||[]).includes(parseInt(c.value,10)); });\n    document.getElementById('eAlarmDur').value = typeof r.alarmDurationSec==='number' ? r.alarmDurationSec : config.alarmDurationSec;\n  }\n  const actions = document.getElementById('eFormActions');\n  actions.innerHTML = `<button class=\"primary-btn\" id=\"eSaveBtn\" onclick=\"saveExpenseRem()\">💾 Update Reminder</button><button class=\"btn-outline\" onclick=\"cancelEditExpense()\">Cancel</button>`;\n  document.getElementById('eName').scrollIntoView({behavior:'smooth', block:'center'});\n}\nfunction cancelEditExpense(){\n  editingExpenseId = null;\n  document.getElementById('eName').value=''; document.getElementById('eAmt').value=''; document.getElementById('eDate').value='';\n  setExpTimingMode('default');\n  const actions = document.getElementById('eFormActions');\n  if(actions) actions.innerHTML = `<button class=\"primary-btn\" id=\"eSaveBtn\" onclick=\"saveExpenseRem()\">+ Save Reminder</button>`;\n}\nfunction drawExpenseRemList(){\n  const term = (expenseSearchTerm||'').trim().toLowerCase();\n  const list = expenseReminders.slice().filter(r=>!term || r.name.toLowerCase().includes(term)).sort((a,b)=>a.date.localeCompare(b.date));\n  const pending = expenseReminders.filter(r=>!r.paid).reduce((s,r)=>s+r.amount,0);\n  let html = `<div class=\"card\"><div class=\"card-head\"><h3>Reminders</h3><span style=\"font-weight:700;font-size:13.5px;color:var(--muted)\">Pending: ${fmt(pending)}</span></div>`;\n  if(list.length===0){ html += `<div class=\"empty-state\"><div class=\"em-icon\">💳</div><div class=\"em-title\">${term?'No matching reminders':'No reminders yet'}</div></div>`; }\n  else {\n    html += list.map(r=>{\n      const modeTag = r.timingMode==='custom' ? '<span class=\"mode-tag\">Custom timing</span>' : '<span class=\"mode-tag default\">Default timing</span>';\n      return `\n      <div class=\"rem-item\">\n        <div class=\"ri-top\">\n          <div><div class=\"ri-name\">${escapeHtml(r.name)}</div><div class=\"ri-meta\">Due ${new Date(r.date+'T00:00:00').toLocaleDateString(undefined,{day:'2-digit',month:'short',year:'numeric'})} ${modeTag}</div></div>\n          <div class=\"ri-amt\">${fmt(r.amount)}</div>\n        </div>\n        <div class=\"rem-actions\">\n          <button class=\"${r.paid?'status-off':'status-on'}\" onclick=\"toggleExpRemPaid('${r.id}')\">${r.paid?'✓ Paid':'Mark as Paid'}</button>\n          <button class=\"btn-outline\" onclick=\"editExpenseReminder('${r.id}')\">✎ Edit</button>\n          <button class=\"icon-x\" onclick=\"deleteExpRem('${r.id}')\" title=\"Delete\">✕</button>\n        </div>\n      </div>`;\n    }).join('');\n  }\n  html += '</div>';\n  document.getElementById('eRemList').innerHTML = html;\n}\nfunction toggleExpRemPaid(id){\n  const r = expenseReminders.find(x=>x.id===id);\n  if(r){\n    r.paid=!r.paid; saveExpRem(); drawExpenseRemList();\n    if(r.paid) syncAlarmIfType('expense', id);\n  }\n}\nfunction deleteExpRem(id){ expenseReminders = expenseReminders.filter(x=>x.id!==id); if(editingExpenseId===id) cancelEditExpense(); saveExpRem(); drawExpenseRemList(); }\n\n/* ---------- Medicine Reminder ---------- */\nlet editingMedId = null;\nlet medSearchTerm = '';\nfunction renderMeds(){\n  const v = document.getElementById('view-medicineRem');\n  v.innerHTML = `\n    <button class=\"back-btn\" onclick=\"enterReminderDashboard()\">← Back</button>\n    <div class=\"rem-shell\">\n      <div class=\"sub-title-row\"><h1>Medicine Reminder</h1></div>\n      <div class=\"card\">\n        <div class=\"field\"><label>Medicine Name</label><input id=\"mName\" type=\"text\" placeholder=\"e.g. Vitamin D\"></div>\n        <div class=\"field\"><label>Frequency</label><select id=\"mFreq\" onchange=\"toggleWeekly()\"><option value=\"daily\">Daily</option><option value=\"weekly\">Weekly</option></select></div>\n        <div id=\"weeklyDays\" class=\"hidden\">\n          <label style=\"display:block;font-size:12px;font-weight:700;color:var(--muted);text-transform:uppercase;margin-bottom:6px;\">Select Days</label>\n          <div class=\"day-check-row\">\n            ${['Mon','Tue','Wed','Thu','Fri','Sat','Sun'].map(d=>`<label><input type=\"checkbox\" class=\"day-check\" value=\"${d}\">${d}</label>`).join('')}\n          </div>\n        </div>\n        <label style=\"display:block;font-size:12px;font-weight:700;color:var(--muted);text-transform:uppercase;margin-bottom:6px;\">Times</label>\n        <div class=\"day-check-row\" style=\"margin-bottom:16px;\">\n          ${['Morning','Afternoon','Evening'].map(t=>`<label><input type=\"checkbox\" class=\"time-check\" value=\"${t}\" onchange=\"toggleMedCustomFields()\">${t}</label>`).join('')}\n        </div>\n\n        <label style=\"display:block;font-size:12px;font-weight:700;color:var(--muted);text-transform:uppercase;margin-bottom:8px;\">Reminder Timing</label>\n        <div class=\"segmented\" style=\"margin-bottom:14px;max-width:280px;\">\n          <button type=\"button\" class=\"mode-btn active\" data-mode=\"default\" onclick=\"setMedTimingMode('default')\">Default</button>\n          <button type=\"button\" class=\"mode-btn\" data-mode=\"custom\" onclick=\"setMedTimingMode('custom')\">Customize</button>\n        </div>\n        <div id=\"medDefaultHint\" class=\"hint-box\">Uses the admin panel's times — Morning ${config.medicineTimes.Morning}, Afternoon ${config.medicineTimes.Afternoon}, Evening ${config.medicineTimes.Evening}.</div>\n        <div id=\"medCustomFields\" class=\"hidden\">\n          <div id=\"medCustomTimeInputs\"></div>\n          <div class=\"field\"><label>Alarm Duration (seconds, 0 = ring until dismissed)</label><input id=\"mAlarmDur\" type=\"number\" min=\"0\" value=\"${config.alarmDurationSec}\"></div>\n        </div>\n\n        <div id=\"mFormActions\" style=\"display:flex;gap:10px;margin-top:14px;\">\n          <button class=\"primary-btn\" id=\"mSaveBtn\" onclick=\"saveMedRem()\">+ Add Medicine</button>\n        </div>\n      </div>\n      <div class=\"field\" style=\"margin:0 0 4px;\"><input id=\"mSearchInput\" type=\"text\" placeholder=\"🔍 Search medicines…\" oninput=\"medSearchTerm=this.value; drawMedList();\"></div>\n      <div id=\"mRemList\"></div>\n    </div>\n  `;\n  editingMedId = null;\n  drawMedList();\n}\nfunction toggleWeekly(){ document.getElementById('weeklyDays').classList.toggle('hidden', document.getElementById('mFreq').value!=='weekly'); }\nfunction setMedTimingMode(mode){\n  document.querySelectorAll('#view-medicineRem .mode-btn').forEach(b=>b.classList.toggle('active', b.dataset.mode===mode));\n  document.getElementById('medDefaultHint').classList.toggle('hidden', mode!=='default');\n  document.getElementById('medCustomFields').classList.toggle('hidden', mode!=='custom');\n  if(mode==='custom') toggleMedCustomFields();\n}\nfunction toggleMedCustomFields(){\n  const mode = document.querySelector('#view-medicineRem .mode-btn.active')?.dataset.mode;\n  if(mode!=='custom') return;\n  const checked = Array.from(document.querySelectorAll('#view-medicineRem .time-check:checked')).map(c=>c.value);\n  const box = document.getElementById('medCustomTimeInputs');\n  const editing = editingMedId ? medReminders.find(x=>x.id===editingMedId) : null;\n  if(checked.length===0){ box.innerHTML = `<p style=\"font-size:12.5px;color:var(--muted);margin:0 0 12px;\">Select at least one time above to set a custom clock time for it.</p>`; return; }\n  box.innerHTML = checked.map(slot=>`<div class=\"field\"><label>${slot} Time</label><input type=\"time\" class=\"med-custom-time\" data-slot=\"${slot}\" value=\"${(editing && editing.customTimes && editing.customTimes[slot]) || config.medicineTimes[slot]||'08:00'}\"></div>`).join('');\n}\nfunction saveMedRem(){\n  const name = document.getElementById('mName').value.trim();\n  const freq = document.getElementById('mFreq').value;\n  const days = Array.from(document.querySelectorAll('.day-check:checked')).map(c=>c.value);\n  const times = Array.from(document.querySelectorAll('.time-check:checked')).map(c=>c.value);\n  if(!name || times.length===0){ showToast('Enter a name and select at least one time'); return; }\n  const timingMode = document.querySelector('#view-medicineRem .mode-btn.active')?.dataset.mode || 'default';\n  const customTimes = {};\n  if(timingMode==='custom'){\n    document.querySelectorAll('.med-custom-time').forEach(inp=>{ customTimes[inp.dataset.slot] = inp.value || config.medicineTimes[inp.dataset.slot]; });\n  }\n  const alarmDurationSec = timingMode==='custom' ? (parseInt(document.getElementById('mAlarmDur').value,10) || 0) : null;\n  if(editingMedId){\n    const m = medReminders.find(x=>x.id===editingMedId);\n    if(m) Object.assign(m, {name, freq, days, times, timingMode, customTimes, alarmDurationSec});\n    showToast('Medicine reminder updated');\n  } else {\n    medReminders.push({id:uid(), name, freq, days, times, timingMode, customTimes, alarmDurationSec, status:{}});\n    showToast('Medicine reminder saved');\n  }\n  saveMedRemState();\n  cancelEditMed();\n  drawMedList();\n}\nfunction editMedicineReminder(id){\n  const m = medReminders.find(x=>x.id===id); if(!m) return;\n  editingMedId = id;\n  document.getElementById('mName').value = m.name;\n  document.getElementById('mFreq').value = m.freq;\n  toggleWeekly();\n  document.querySelectorAll('.day-check').forEach(c=>{ c.checked = (m.days||[]).includes(c.value); });\n  document.querySelectorAll('.time-check').forEach(c=>{ c.checked = (m.times||[]).includes(c.value); });\n  setMedTimingMode(m.timingMode==='custom' ? 'custom' : 'default');\n  if(m.timingMode==='custom') document.getElementById('mAlarmDur').value = typeof m.alarmDurationSec==='number' ? m.alarmDurationSec : config.alarmDurationSec;\n  const actions = document.getElementById('mFormActions');\n  actions.innerHTML = `<button class=\"primary-btn\" id=\"mSaveBtn\" onclick=\"saveMedRem()\">💾 Update Medicine</button><button class=\"btn-outline\" onclick=\"cancelEditMed()\">Cancel</button>`;\n  document.getElementById('mName').scrollIntoView({behavior:'smooth', block:'center'});\n}\nfunction cancelEditMed(){\n  editingMedId = null;\n  document.getElementById('mName').value='';\n  document.querySelectorAll('#view-medicineRem input[type=checkbox]').forEach(c=>c.checked=false);\n  setMedTimingMode('default');\n  const actions = document.getElementById('mFormActions');\n  if(actions) actions.innerHTML = `<button class=\"primary-btn\" id=\"mSaveBtn\" onclick=\"saveMedRem()\">+ Add Medicine</button>`;\n}\nfunction drawMedList(){\n  const today = todayStr();\n  const term = (medSearchTerm||'').trim().toLowerCase();\n  const list = medReminders.filter(m=>!term || m.name.toLowerCase().includes(term));\n  let html = '<div class=\"card\"><div class=\"card-head\"><h3>Your Medicines</h3></div>';\n  if(list.length===0){ html += `<div class=\"empty-state\"><div class=\"em-icon\">💊</div><div class=\"em-title\">${term?'No matching medicines':'No medicines added yet'}</div></div>`; }\n  else {\n    html += list.map(m=>{\n      const doneToday = m.status[today] || {};\n      const timeBtns = m.times.map(t=>{\n        const label = m.timingMode==='custom' && m.customTimes && m.customTimes[t] ? `${t} (${m.customTimes[t]})` : t;\n        return `<button class=\"${doneToday[t]?'status-off':'status-on'}\" onclick=\"markMed('${m.id}','${t}')\">${doneToday[t]?'✓ '+label:label}</button>`;\n      }).join('');\n      const modeTag = m.timingMode==='custom' ? '<span class=\"mode-tag\">Custom timing</span>' : '<span class=\"mode-tag default\">Default timing</span>';\n      return `<div class=\"rem-item\">\n        <div class=\"ri-top\"><div><div class=\"ri-name\">${escapeHtml(m.name)}</div><div class=\"ri-meta\">${m.freq==='weekly' ? 'Weekly · '+m.days.join(', ') : 'Daily'} ${modeTag}</div></div>\n        <div style=\"display:flex;gap:6px;\"><button class=\"btn-outline\" onclick=\"editMedicineReminder('${m.id}')\">✎ Edit</button><button class=\"icon-x\" onclick=\"deleteMed('${m.id}')\" title=\"Delete\">✕</button></div></div>\n        <div class=\"rem-actions\">${timeBtns}</div>\n      </div>`;\n    }).join('');\n  }\n  html += '</div>';\n  document.getElementById('mRemList').innerHTML = html;\n}\nfunction markMed(mIdx, time){\n  const m = medReminders.find(x=>x.id===mIdx); if(!m) return;\n  const today = todayStr();\n  m.status[today] = m.status[today] || {};\n  m.status[today][time] = !m.status[today][time];\n  playQuickBeep();\n  saveMedRemState();\n  drawMedList();\n  syncAlarmIfMatches(`med:${mIdx}:${today}:${time}`);\n}\nfunction deleteMed(id){ medReminders = medReminders.filter(x=>x.id!==id); if(editingMedId===id) cancelEditMed(); saveMedRemState(); drawMedList(); }\n\n/* ---------- General Reminder (alarms, meetings, wake-ups, etc.) ---------- */\nlet editingGeneralId = null;\nlet generalSearchTerm = '';\nfunction renderGeneralRem(){\n  const v = document.getElementById('view-generalRem');\n  v.innerHTML = `\n    <button class=\"back-btn\" onclick=\"enterReminderDashboard()\">← Back</button>\n    <div class=\"rem-shell\">\n      <div class=\"sub-title-row\"><h1>⏰ General Reminder</h1></div>\n      <div class=\"card\">\n        <div class=\"field\"><label>Title</label><input id=\"genTitle\" type=\"text\" placeholder=\"e.g. Wake up, Team meeting, Call mom\"></div>\n        <div class=\"rem-form\">\n          <div class=\"field\" style=\"margin:0;\"><label>Date</label><input id=\"genDate\" type=\"date\" value=\"${todayStr()}\"></div>\n          <div class=\"field\" style=\"margin:0;\"><label>Time</label><input id=\"genTime\" type=\"time\" value=\"08:00\"></div>\n          <div class=\"field\" style=\"margin:0;\"><label>Repeat</label>\n            <select id=\"genRepeat\" onchange=\"toggleGenWeekly()\">\n              <option value=\"none\">Just once</option>\n              <option value=\"daily\">Every day</option>\n              <option value=\"weekly\">Weekly</option>\n            </select>\n          </div>\n        </div>\n        <div id=\"genWeeklyDays\" class=\"hidden\">\n          <label style=\"display:block;font-size:12px;font-weight:700;color:var(--muted);text-transform:uppercase;margin-bottom:6px;\">Select Days</label>\n          <div class=\"day-check-row\">${['Mon','Tue','Wed','Thu','Fri','Sat','Sun'].map(d=>`<label><input type=\"checkbox\" class=\"gen-day-check\" value=\"${d}\">${d}</label>`).join('')}</div>\n        </div>\n        <div class=\"field\"><label>Note (optional)</label><input id=\"genNote\" type=\"text\" placeholder=\"Any extra detail\"></div>\n        <div class=\"field\" style=\"max-width:340px;\"><label>Alarm Duration (seconds, 0 = ring until dismissed)</label><input id=\"genAlarmDur\" type=\"number\" min=\"0\" value=\"${config.alarmDurationSec}\"></div>\n        <div id=\"genFormActions\" style=\"display:flex;gap:10px;\">\n          <button class=\"primary-btn\" id=\"genSaveBtn\" onclick=\"saveGeneralReminder()\">+ Save Reminder</button>\n        </div>\n      </div>\n      <div class=\"field\" style=\"margin:0 0 4px;\"><input id=\"genSearchInput\" type=\"text\" placeholder=\"🔍 Search reminders…\" oninput=\"generalSearchTerm=this.value; drawGeneralRemList();\"></div>\n      <div id=\"genRemList\"></div>\n    </div>\n  `;\n  editingGeneralId = null;\n  drawGeneralRemList();\n}\nfunction toggleGenWeekly(){ document.getElementById('genWeeklyDays').classList.toggle('hidden', document.getElementById('genRepeat').value!=='weekly'); }\nfunction saveGeneralReminder(){\n  const title = document.getElementById('genTitle').value.trim();\n  const date = document.getElementById('genDate').value;\n  const time = document.getElementById('genTime').value;\n  const repeat = document.getElementById('genRepeat').value;\n  const days = Array.from(document.querySelectorAll('.gen-day-check:checked')).map(c=>c.value);\n  const note = document.getElementById('genNote').value.trim();\n  const alarmDurationSec = parseInt(document.getElementById('genAlarmDur').value,10) || 0;\n  if(!title || !date || !time){ showToast('Enter a title, date, and time'); return; }\n  if(repeat==='weekly' && days.length===0){ showToast('Select at least one day for a weekly reminder'); return; }\n  if(editingGeneralId){\n    const r = generalReminders.find(x=>x.id===editingGeneralId);\n    if(r) Object.assign(r, {title, date, time, repeat, days, note, alarmDurationSec});\n    showToast('Reminder updated');\n  } else {\n    generalReminders.push({id:uid(), title, date, time, repeat, days, note, alarmDurationSec, doneOnce:false, status:{}});\n    showToast('Reminder saved');\n  }\n  saveGeneralRem();\n  cancelEditGeneral();\n  drawGeneralRemList();\n}\nfunction editGeneralReminder(id){\n  const r = generalReminders.find(x=>x.id===id); if(!r) return;\n  editingGeneralId = id;\n  document.getElementById('genTitle').value = r.title;\n  document.getElementById('genDate').value = r.date;\n  document.getElementById('genTime').value = r.time;\n  document.getElementById('genRepeat').value = r.repeat;\n  toggleGenWeekly();\n  document.querySelectorAll('.gen-day-check').forEach(c=>{ c.checked = (r.days||[]).includes(c.value); });\n  document.getElementById('genNote').value = r.note||'';\n  document.getElementById('genAlarmDur').value = typeof r.alarmDurationSec==='number' ? r.alarmDurationSec : config.alarmDurationSec;\n  const actions = document.getElementById('genFormActions');\n  actions.innerHTML = `<button class=\"primary-btn\" id=\"genSaveBtn\" onclick=\"saveGeneralReminder()\">💾 Update Reminder</button><button class=\"btn-outline\" onclick=\"cancelEditGeneral()\">Cancel</button>`;\n  document.getElementById('genTitle').scrollIntoView({behavior:'smooth', block:'center'});\n}\nfunction cancelEditGeneral(){\n  editingGeneralId = null;\n  document.getElementById('genTitle').value=''; document.getElementById('genNote').value='';\n  document.getElementById('genDate').value = todayStr();\n  document.getElementById('genTime').value = '08:00';\n  document.getElementById('genRepeat').value = 'none';\n  toggleGenWeekly();\n  document.querySelectorAll('.gen-day-check').forEach(c=>c.checked=false);\n  const actions = document.getElementById('genFormActions');\n  if(actions) actions.innerHTML = `<button class=\"primary-btn\" id=\"genSaveBtn\" onclick=\"saveGeneralReminder()\">+ Save Reminder</button>`;\n}\nfunction drawGeneralRemList(){\n  const today = todayStr();\n  const term = (generalSearchTerm||'').trim().toLowerCase();\n  const list = generalReminders.slice().filter(r=>!term || r.title.toLowerCase().includes(term)).sort((a,b)=> (a.date+a.time).localeCompare(b.date+b.time));\n  let html = '<div class=\"card\"><div class=\"card-head\"><h3>Your Reminders</h3></div>';\n  if(list.length===0){ html += `<div class=\"empty-state\"><div class=\"em-icon\">⏰</div><div class=\"em-title\">${term?'No matching reminders':'No reminders yet'}</div></div>`; }\n  else {\n    html += list.map(r=>{\n      const isDoneToday = r.repeat==='none' ? r.doneOnce : !!(r.status||{})[today];\n      const repeatLabel = r.repeat==='none' ? new Date(r.date+'T00:00:00').toLocaleDateString(undefined,{day:'2-digit',month:'short',year:'numeric'}) : r.repeat==='daily' ? 'Every day' : 'Weekly · '+r.days.join(', ');\n      return `<div class=\"rem-item\">\n        <div class=\"ri-top\">\n          <div><div class=\"ri-name\">${escapeHtml(r.title)}</div><div class=\"ri-meta\">${repeatLabel} at ${r.time}${r.note?' · '+escapeHtml(r.note):''}</div></div>\n          <div style=\"display:flex;gap:6px;\"><button class=\"btn-outline\" onclick=\"editGeneralReminder('${r.id}')\">✎ Edit</button><button class=\"icon-x\" onclick=\"deleteGeneralRem('${r.id}')\" title=\"Delete\">✕</button></div>\n        </div>\n        <div class=\"rem-actions\">\n          <button class=\"${isDoneToday?'status-off':'status-on'}\" onclick=\"toggleGeneralDone('${r.id}')\">${isDoneToday?'✓ Done':'Mark Done'}</button>\n        </div>\n      </div>`;\n    }).join('');\n  }\n  html += '</div>';\n  document.getElementById('genRemList').innerHTML = html;\n}\nfunction toggleGeneralDone(id){\n  const r = generalReminders.find(x=>x.id===id); if(!r) return;\n  const today = todayStr();\n  if(r.repeat==='none'){ r.doneOnce = !r.doneOnce; }\n  else { r.status = r.status||{}; r.status[today] = !r.status[today]; }\n  saveGeneralRem();\n  drawGeneralRemList();\n  syncAlarmIfMatches(r.repeat==='none' ? `gen:${id}:${r.date}:once` : `gen:${id}:${today}:rep`);\n}\nfunction deleteGeneralRem(id){ generalReminders = generalReminders.filter(x=>x.id!==id); if(editingGeneralId===id) cancelEditGeneral(); saveGeneralRem(); drawGeneralRemList(); }\n\n\n/* ---------- Grocery Expiry Reminder ---------- */\nfunction daysUntil(dateStr){\n  const today = new Date(); today.setHours(0,0,0,0);\n  const d = new Date(dateStr+'T00:00:00');\n  return Math.round((d-today)/86400000);\n}\nfunction expiryStatus(dateStr){\n  const days = daysUntil(dateStr);\n  if(days<0) return {cls:'expired', label:'Expired '+Math.abs(days)+'d ago'};\n  if(days===0) return {cls:'soon', label:'Expires today'};\n  if(days<=3) return {cls:'soon', label:days+'d left'};\n  return {cls:'fresh', label:days+'d left'};\n}\nlet grocerySearchTerm = '';\nfunction renderGroceryRem(){\n  const v = document.getElementById('view-groceryRem');\n  v.innerHTML = `\n    <button class=\"back-btn\" onclick=\"enterReminderDashboard()\">← Back</button>\n    <div class=\"rem-shell\" style=\"max-width:960px;\">\n      <div class=\"sub-title-row row-between\" style=\"display:flex;\">\n        <h1>Grocery Expiry Reminder</h1>\n        <button class=\"primary-btn\" style=\"width:auto;\" onclick=\"openAddGrocery()\">+ Add Grocery Item</button>\n      </div>\n      <div class=\"field\" style=\"margin:0 0 4px;\"><input id=\"grocSearchInput\" type=\"text\" placeholder=\"🔍 Search grocery items…\" oninput=\"grocerySearchTerm=this.value; drawGroceryList();\"></div>\n      <div id=\"groceryList\"></div>\n    </div>\n  `;\n  drawGroceryList();\n}\nfunction drawGroceryList(){\n  const term = (grocerySearchTerm||'').trim().toLowerCase();\n  const items = groceryReminders.slice().filter(it=>!term || it.item.toLowerCase().includes(term) || it.category.toLowerCase().includes(term)).sort((a,b)=>a.expiryDate.localeCompare(b.expiryDate));\n  const container = document.getElementById('groceryList');\n  if(items.length===0){\n    container.innerHTML = `<div class=\"card\"><div class=\"empty-state\"><div class=\"em-icon\">🥦</div><div class=\"em-title\">${term?'No matching items':'No grocery items tracked yet'}</div><div>${term?'':'Click \"+ Add Grocery Item\" to pick a category and set an expiry date.'}</div></div></div>`;\n    return;\n  }\n  const groups = {expired:[], soon:[], fresh:[]};\n  items.forEach(it=>{ groups[expiryStatus(it.expiryDate).cls].push(it); });\n  const sectionLabels = {expired:'Expired', soon:'Expiring Soon', fresh:'Fresh'};\n  let html = '<div class=\"card\">';\n  ['expired','soon','fresh'].forEach(key=>{\n    if(groups[key].length===0) return;\n    html += `<div class=\"groc-section-title\">${sectionLabels[key]} (${groups[key].length})</div>`;\n    groups[key].forEach(it=>{\n      const st = expiryStatus(it.expiryDate);\n      html += `<div class=\"rem-item\" onclick=\"openGroceryDetails('${it.id}')\" style=\"cursor:pointer;\">\n        <div class=\"ri-top\">\n          <div style=\"display:flex;align-items:center;gap:12px;\">\n            <div class=\"cat-circle\" style=\"background:${catColor(it.category)};width:38px;height:38px;font-size:18px;\">${it.icon||'🥦'}</div>\n            <div><div class=\"ri-name\">${escapeHtml(it.item)}</div><div class=\"ri-meta\">${escapeHtml(it.category)}${it.quantity?' · '+escapeHtml(it.quantity):''}</div></div>\n          </div>\n          <div style=\"text-align:right;\">\n            <div class=\"exp-badge ${st.cls}\">${st.label}</div>\n            <div class=\"ri-meta\">${new Date(it.expiryDate+'T00:00:00').toLocaleDateString(undefined,{day:'2-digit',month:'short',year:'numeric'})}</div>\n          </div>\n        </div>\n      </div>`;\n    });\n  });\n  html += '</div>';\n  container.innerHTML = html;\n}\n\nlet groceryCtx = {category:null, item:null, editingId:null};\nfunction openAddGrocery(){\n  groceryCtx = {category:null, item:null, editingId:null};\n  const wrap = openModal('');\n  drawGroceryStep1(wrap);\n}\nfunction drawGroceryStep1(wrap){\n  const dlg = wrap.querySelector('.dialog');\n  dlg.innerHTML = `\n    <div class=\"dialog-header\"><button class=\"txt-btn\" onclick=\"closeTopModal()\">Cancel</button><h2>Select Category</h2><div style=\"width:50px\"></div></div>\n    <div style=\"padding:18px 16px;\">\n      <div class=\"groc-cat-grid\">\n        ${GROCERY_CATEGORIES.map(cat=>`\n          <div class=\"groc-cat-tile\" onclick=\"pickGroceryCategory('${cat.name.replace(/'/g,\"\\\\'\")}')\">\n            <div class=\"gc-img\">${cat.icon}</div>\n            <div class=\"gc-name\">${cat.name}</div>\n            <div class=\"gc-count\">${cat.items.length} items</div>\n          </div>`).join('')}\n        <div class=\"groc-cat-tile\" onclick=\"pickGroceryCategory('${GROCERY_OTHERS.name}')\">\n          <div class=\"gc-img\">${GROCERY_OTHERS.icon}</div>\n          <div class=\"gc-name\">Others</div>\n          <div class=\"gc-count\">custom item</div>\n        </div>\n      </div>\n    </div>\n  `;\n}\nfunction pickGroceryCategory(catName){\n  groceryCtx.category = catName;\n  const wrap = document.querySelector('#modal-root .overlay');\n  if(catName===GROCERY_OTHERS.name){ groceryCtx.item = null; drawGroceryCustomName(wrap); return; }\n  drawGroceryStep2(wrap);\n}\nfunction drawGroceryStep2(wrap){\n  const dlg = wrap.querySelector('.dialog');\n  const cat = GROCERY_CATEGORIES.find(c=>c.name===groceryCtx.category);\n  dlg.innerHTML = `\n    <div class=\"dialog-header\"><button class=\"txt-btn\" onclick=\"drawGroceryStep1(document.querySelector('#modal-root .overlay'))\">‹ Back</button><h2>${cat.name}</h2><div style=\"width:50px\"></div></div>\n    <div class=\"cat-grid\">\n      ${cat.items.map(it=>`<button class=\"cat-cell\" onclick=\"pickGroceryItem('${it.name.replace(/'/g,\"\\\\'\")}','${it.icon}')\"><div class=\"cc-ic\" style=\"background:${catColor(cat.name)}22;\">${it.icon}</div><div class=\"cc-lbl\">${it.name}</div></button>`).join('')}\n      <button class=\"cat-cell\" onclick=\"drawGroceryCustomName(document.querySelector('#modal-root .overlay'))\"><div class=\"cc-ic\">➕</div><div class=\"cc-lbl\">Others</div></button>\n    </div>\n  `;\n}\nfunction pickGroceryItem(name, icon){\n  groceryCtx.item = name; groceryCtx.icon = icon;\n  drawGroceryStep3(document.querySelector('#modal-root .overlay'));\n}\nfunction drawGroceryCustomName(wrap){\n  const dlg = wrap.querySelector('.dialog');\n  const backFn = groceryCtx.category===GROCERY_OTHERS.name ? `drawGroceryStep1(document.querySelector('#modal-root .overlay'))` : `drawGroceryStep2(document.querySelector('#modal-root .overlay'))`;\n  dlg.innerHTML = `\n    <div class=\"dialog-header\"><button class=\"txt-btn\" onclick=\"${backFn}\">‹ Back</button><h2>Custom Item</h2><div style=\"width:50px\"></div></div>\n    <div class=\"field\" style=\"margin:18px 16px;\"><label>Item Name</label><input id=\"grocCustomName\" type=\"text\" placeholder=\"Enter item name\" autofocus></div>\n    <button class=\"save-btn\" onclick=\"confirmGroceryCustomName()\">Continue</button>\n  `;\n}\nfunction confirmGroceryCustomName(){\n  const wrap = document.querySelector('#modal-root .overlay');\n  const name = wrap.querySelector('#grocCustomName').value.trim();\n  if(!name){ showToast('Enter an item name'); return; }\n  groceryCtx.item = name; groceryCtx.icon = '🥡';\n  if(groceryCtx.category===GROCERY_OTHERS.name){ /* keep as Others category */ }\n  drawGroceryStep3(wrap);\n}\nfunction drawGroceryStep3(wrap){\n  const dlg = wrap.querySelector('.dialog');\n  const color = catColor(groceryCtx.category);\n  const mode = groceryCtx.timingMode || 'default';\n  const selOffsets = groceryCtx.customOffsets || config.groceryOffsets;\n  dlg.innerHTML = `\n    <div class=\"dialog-header\"><button class=\"txt-btn\" onclick=\"closeTopModal()\">Cancel</button><h2>Set Expiry</h2><button class=\"txt-btn\" style=\"font-weight:800;\" onclick=\"saveGroceryItem()\">Save</button></div>\n    <div class=\"amount-display\" style=\"padding-top:20px;\">\n      <div class=\"cat-tag\"><span class=\"tag-ic\" style=\"background:${color}\">${groceryCtx.icon||'🥦'}</span>${escapeHtml(groceryCtx.item)} <span style=\"color:var(--muted);font-weight:600;\">· ${escapeHtml(groceryCtx.category)}</span></div>\n    </div>\n    <div class=\"field\" style=\"margin:14px 16px;\"><label>Expiry Date</label><input id=\"grocExpiry\" type=\"date\" value=\"${groceryCtx.expiryDate||todayStr()}\"></div>\n    <div class=\"field\" style=\"margin:14px 16px;\"><label>Quantity (optional)</label><input id=\"grocQty\" type=\"text\" placeholder=\"e.g. 2 kg, 1 pack\" value=\"${escapeHtml(groceryCtx.quantity||'')}\"></div>\n    <div class=\"field\" style=\"margin:14px 16px;\"><label>Note (optional)</label><input id=\"grocNote\" type=\"text\" placeholder=\"Add a note\" value=\"${escapeHtml(groceryCtx.note||'')}\"></div>\n\n    <div style=\"margin:14px 16px;\">\n      <label style=\"display:block;font-size:12px;font-weight:700;color:var(--muted);text-transform:uppercase;margin-bottom:8px;\">Reminder Timing</label>\n      <div class=\"segmented\" style=\"margin-bottom:14px;max-width:280px;\">\n        <button type=\"button\" class=\"mode-btn ${mode==='default'?'active':''}\" data-mode=\"default\" onclick=\"setGrocTimingMode('default')\">Default</button>\n        <button type=\"button\" class=\"mode-btn ${mode==='custom'?'active':''}\" data-mode=\"custom\" onclick=\"setGrocTimingMode('custom')\">Customize</button>\n      </div>\n      <div id=\"grocDefaultHint\" class=\"hint-box ${mode!=='default'?'hidden':''}\">Uses the admin panel's schedule — alerts at ${config.alertTime} on: ${offsetsLabel(config.groceryOffsets,'Expiry day')}.</div>\n      <div id=\"grocCustomFields\" class=\"${mode!=='custom'?'hidden':''}\">\n        <div class=\"field\"><label>Alert Time</label><input id=\"grocCustomTime\" type=\"time\" value=\"${groceryCtx.customAlertTime||config.alertTime}\"></div>\n        <label style=\"display:block;font-size:12px;font-weight:700;color:var(--muted);text-transform:uppercase;margin-bottom:6px;\">Remind Me</label>\n        <div class=\"offset-check-row\">${offsetCheckboxesHtml(selOffsets, 'groc-offset-check', 'Expiry day')}</div>\n        <div class=\"field\"><label>Alarm Duration (seconds, 0 = ring until dismissed)</label><input id=\"grocAlarmDur\" type=\"number\" min=\"0\" value=\"${typeof groceryCtx.alarmDurationSec==='number'?groceryCtx.alarmDurationSec:config.alarmDurationSec}\"></div>\n      </div>\n    </div>\n  `;\n}\nfunction setGrocTimingMode(mode){\n  document.querySelectorAll('#modal-root .overlay .mode-btn').forEach(b=>{ if(b.dataset.mode) b.classList.toggle('active', b.dataset.mode===mode); });\n  document.getElementById('grocDefaultHint').classList.toggle('hidden', mode!=='default');\n  document.getElementById('grocCustomFields').classList.toggle('hidden', mode!=='custom');\n}\nfunction saveGroceryItem(){\n  const wrap = document.querySelector('#modal-root .overlay');\n  const expiryDate = wrap.querySelector('#grocExpiry').value;\n  const quantity = wrap.querySelector('#grocQty').value.trim();\n  const note = wrap.querySelector('#grocNote').value.trim();\n  if(!expiryDate){ showToast('Please pick an expiry date'); return; }\n\n  const timingMode = wrap.querySelector('.mode-btn.active')?.dataset.mode || 'default';\n  let customAlertTime=null, customOffsets=null, alarmDurationSec=null;\n  if(timingMode==='custom'){\n    customAlertTime = document.getElementById('grocCustomTime').value || config.alertTime;\n    customOffsets = Array.from(document.querySelectorAll('.groc-offset-check:checked')).map(c=>parseInt(c.value,10));\n    if(customOffsets.length===0) customOffsets = config.groceryOffsets.slice();\n    alarmDurationSec = parseInt(document.getElementById('grocAlarmDur').value,10) || 0;\n  }\n\n  let it;\n  if(groceryCtx.editingId){\n    it = groceryReminders.find(x=>x.id===groceryCtx.editingId);\n    Object.assign(it, {category:groceryCtx.category, item:groceryCtx.item, icon:groceryCtx.icon, expiryDate, quantity, note, timingMode, customAlertTime, customOffsets, alarmDurationSec});\n  } else {\n    it = {id:uid(), category:groceryCtx.category, item:groceryCtx.item, icon:groceryCtx.icon, expiryDate, quantity, note, timingMode, customAlertTime, customOffsets, alarmDurationSec, addedDate:todayStr(), fromTransactionId:null};\n    groceryReminders.push(it);\n  }\n  saveGroceryRem();\n  closeAllModals();\n  drawGroceryList();\n  showToast('Grocery reminder saved');\n}\nfunction openGroceryDetails(id){\n  const it = groceryReminders.find(x=>x.id===id); if(!it) return;\n  const st = expiryStatus(it.expiryDate);\n  const modeTag = it.timingMode==='custom' ? '<span class=\"mode-tag\">Custom timing</span>' : '<span class=\"mode-tag default\">Default timing</span>';\n  const sourceTxn = it.fromTransactionId ? financeState.transactions.find(t=>t.id===it.fromTransactionId) : null;\n  openModal(`\n    <div class=\"dialog-header\"><button class=\"txt-btn\" onclick=\"closeTopModal()\">‹ Back</button><h2>Item Details</h2><div style=\"width:40px\"></div></div>\n    <div class=\"details-hero\"><div class=\"dh-ic\" style=\"background:${catColor(it.category)}\">${it.icon||'🥦'}</div><div class=\"dh-name\">${escapeHtml(it.item)}</div><div class=\"exp-badge ${st.cls}\" style=\"margin-top:8px;\">${st.label}</div><div style=\"margin-top:6px;\">${modeTag}</div></div>\n    <div class=\"detail-row\"><span class=\"dk\">Category</span><span class=\"dv\">${escapeHtml(it.category)}</span></div>\n    <div class=\"detail-row\"><span class=\"dk\">Expiry Date</span><span class=\"dv\">${new Date(it.expiryDate+'T00:00:00').toLocaleDateString(undefined,{day:'2-digit',month:'short',year:'numeric'})}</span></div>\n    ${it.quantity?`<div class=\"detail-row\"><span class=\"dk\">Quantity</span><span class=\"dv\">${escapeHtml(it.quantity)}</span></div>`:''}\n    ${it.note?`<div class=\"detail-row\"><span class=\"dk\">Note</span><span class=\"dv\">${escapeHtml(it.note)}</span></div>`:''}\n    ${sourceTxn?`<div class=\"detail-row\"><span class=\"dk\">From Transaction</span><span class=\"dv\">🔗 ${escapeHtml(sourceTxn.category)} · ${fmt(sourceTxn.amount)} on ${new Date(sourceTxn.date+'T00:00:00').toLocaleDateString(undefined,{day:'2-digit',month:'short'})}</span></div>`:''}\n    <div class=\"two-btn\"><button class=\"btn-edit\" onclick=\"editGroceryItem('${it.id}')\">Edit</button><button class=\"btn-delete\" onclick=\"deleteGroceryItem('${it.id}')\">Delete</button></div>\n  `);\n}\nfunction editGroceryItem(id){\n  const it = groceryReminders.find(x=>x.id===id); if(!it) return;\n  closeAllModals();\n  groceryCtx = {category:it.category, item:it.item, icon:it.icon, expiryDate:it.expiryDate, quantity:it.quantity, note:it.note, timingMode:it.timingMode, customAlertTime:it.customAlertTime, customOffsets:it.customOffsets, alarmDurationSec:it.alarmDurationSec, editingId:it.id};\n  const wrap = openModal('');\n  drawGroceryStep3(wrap);\n}\nfunction deleteGroceryItem(id){\n  const it = groceryReminders.find(x=>x.id===id);\n  if(it && it.fromTransactionId){\n    const t = financeState.transactions.find(x=>x.id===it.fromTransactionId);\n    if(t){\n      if(Array.isArray(t.groceryItems)){\n        // Keep the item as a plain tag on the transaction (it's still true\n        // the purchase included this item) but drop the now-deleted\n        // reminder link and its expiry date.\n        const tagged = t.groceryItems.find(p=>p.groceryReminderId===id);\n        if(tagged){ tagged.groceryReminderId=null; tagged.expiryDate=''; saveFinance(); }\n      } else if(t.perishableItems){\n        t.perishableItems = t.perishableItems.filter(p=>p.groceryReminderId!==id);\n        saveFinance();\n      }\n    }\n  }\n  if(it && it.linkedShoppingId){\n    const shopItem = shoppingList.find(s=>s.id===it.linkedShoppingId);\n    if(shopItem) shopItem.linkedGroceryId = null;\n    saveShoppingList();\n  }\n  groceryReminders = groceryReminders.filter(x=>x.id!==id);\n  saveGroceryRem();\n  syncAlarmIfType('grocery', id);\n  closeAllModals();\n  drawGroceryList();\n  showToast('Grocery item removed');\n}\n\n/* ============================================================\n   ================  LIST TO BUY (shopping list)  ================\n   ------------------------------------------------------------\n   A shopping list (item / quantity / price / expiry / bought),\n   kept in sync with the Grocery Expiry Reminder: adding an item\n   that's already tracked there (and not expired) prompts the\n   customer before adding a possible duplicate. Items can also be\n   imported from a text/CSV file, or scanned from a photo (OCR),\n   and reflected individually or in bulk into the Personal Finance\n   Tracker and/or the Grocery Expiry Reminder.\n   ============================================================ */\nlet currentImportLabel = 'Imported Items';\nlet importReviewRows = [];\nlet currentScanImageDataUrl = null;\n\nlet shoppingSearchTerm = '';\nfunction renderShoppingList(){\n  const v = document.getElementById('view-shoppingList');\n  v.innerHTML = `\n    <button class=\"back-btn\" onclick=\"goDashboard()\">← Back to Menu</button>\n    <div class=\"sub-title-row\"><h1>📝 List to Buy</h1></div>\n    <div class=\"rem-shell\">\n      <div class=\"card\">\n        <div class=\"shop-add-row\">\n          <div class=\"field\" style=\"margin:0;\"><label>Item Name</label><input id=\"shopName\" type=\"text\" placeholder=\"e.g. Apples\"></div>\n          <div class=\"field\" style=\"margin:0;\"><label>Quantity</label><input id=\"shopQty\" type=\"text\" placeholder=\"e.g. 3, 1/2, 5-7\"></div>\n          <div class=\"field\" style=\"margin:0;\"><label>Unit</label>\n            <select id=\"shopUnit\"><option value=\"pcs\">pcs</option><option value=\"g\">g</option><option value=\"kg\">kg</option><option value=\"ml\">ml</option><option value=\"l\">l</option><option value=\"packet\">packet</option><option value=\"dozen\">dozen</option></select>\n          </div>\n          <div class=\"field\" style=\"margin:0;\"><label>Price (optional)</label><input id=\"shopPrice\" type=\"number\" min=\"0\" step=\"0.01\" placeholder=\"0.00\"></div>\n          <div class=\"field\" style=\"margin:0;\"><label>Expiry (optional)</label><input id=\"shopExpiry\" type=\"date\"></div>\n          <button class=\"primary-btn\" onclick=\"addShoppingItem()\">+ Add</button>\n        </div>\n        <div class=\"admin-actions\" style=\"margin-top:4px;\">\n          <button class=\"btn-outline\" onclick=\"triggerImportFile()\">📄 Import Document</button>\n          <button class=\"btn-outline\" onclick=\"triggerScanFile()\">📷 Scan Document</button>\n        </div>\n        <input type=\"file\" id=\"shopImportInput\" accept=\".txt,.csv,.xlsx,.xls,.pdf,.png,.jpg,.jpeg,.webp\" style=\"display:none\" onchange=\"handleImportFile(this.files[0])\">\n        <input type=\"file\" id=\"shopScanInput\" accept=\"image/*\" capture=\"environment\" style=\"display:none\" onchange=\"handleScanFile(this.files[0])\">\n        <p style=\"font-size:12px;color:var(--muted);margin:10px 0 0;\">Import accepts .txt, .csv, Excel (.xlsx/.xls), PDF, or a photo — item, quantity, and (if handwritten or printed) price are picked up automatically, with a review step before anything is added. Text/CSV/Excel always work offline; PDF, photo scan, and camera scan need internet the first time to load their reading engine.</p>\n      </div>\n      <div class=\"field\" style=\"margin:0 0 4px;\"><input id=\"shopSearchInput\" type=\"text\" placeholder=\"🔍 Search your list…\" oninput=\"shoppingSearchTerm=this.value; drawShoppingList();\"></div>\n      <div id=\"shopListBody\"></div>\n    </div>\n  `;\n  drawShoppingList();\n}\n\n/* Looks for an existing (non-expired) grocery reminder that matches\n   the item name the customer is about to add to the shopping list. */\nfunction findMatchingGroceryReminder(name){\n  const lower = name.trim().toLowerCase();\n  if(!lower) return null;\n  return groceryReminders.find(g => g.item.trim().toLowerCase()===lower && expiryStatus(g.expiryDate).cls!=='expired') || null;\n}\nfunction addShoppingItem(){\n  const name = document.getElementById('shopName').value.trim();\n  const qty = document.getElementById('shopQty').value.trim();\n  const unit = document.getElementById('shopUnit').value;\n  const price = document.getElementById('shopPrice').value.trim();\n  const expiry = document.getElementById('shopExpiry').value;\n  if(!name){ showToast('Enter an item name'); return; }\n  const match = findMatchingGroceryReminder(name);\n  if(match){\n    const st = expiryStatus(match.expiryDate);\n    openModal(`\n      <div class=\"dialog-header\"><h2>Already Tracked</h2><div style=\"width:1px\"></div></div>\n      <div style=\"padding:20px;\">\n        <p style=\"margin:0 0 12px;font-size:14.5px;\">🔔 <b>${escapeHtml(match.item)}</b>${match.quantity?' ('+escapeHtml(match.quantity)+')':''} is already in your <b>Grocery Expiry Reminder</b> list — <span class=\"exp-badge ${st.cls}\">${st.label}</span></div>\n        <p style=\"margin:0;color:var(--muted);font-size:13.5px;\">Do you still want to add it to your shopping list?</p>\n      </div>\n      <div class=\"two-btn\">\n        <button class=\"btn-edit\" onclick=\"closeTopModal(); confirmAddShoppingItem('${escapeHtml(name).replace(/'/g,\"\\\\'\")}','${qty}','${unit}','${price}','${expiry}')\">Yes, Add Anyway</button>\n        <button class=\"btn-delete\" onclick=\"closeTopModal()\">No, Skip It</button>\n      </div>\n    `);\n    return;\n  }\n  confirmAddShoppingItem(name, qty, unit, price, expiry);\n}\nfunction confirmAddShoppingItem(name, qty, unit, price, expiry){\n  shoppingList.push({id:uid(), name, qty, unit, price: parseFloat(price)||0, expiry: expiry||'', bought:false, addedDate:todayStr(), linkedTransactionId:null, linkedGroceryId:null});\n  saveShoppingList();\n  ['shopName','shopQty','shopPrice','shopExpiry'].forEach(fid=>{ const el=document.getElementById(fid); if(el) el.value=''; });\n  drawShoppingList();\n  showToast('Added to your shopping list');\n}\n\nfunction drawShoppingList(){\n  const container = document.getElementById('shopListBody');\n  const term = (shoppingSearchTerm||'').trim().toLowerCase();\n  const filtered = shoppingList.filter(it=>!term || it.name.toLowerCase().includes(term));\n  if(shoppingList.length===0){\n    container.innerHTML = `<div class=\"card\"><div class=\"empty-state\"><div class=\"em-icon\">📝</div><div class=\"em-title\">Your shopping list is empty</div><div>Add items above, or import/scan a list to start planning your next shop.</div></div></div>`;\n    return;\n  }\n  if(filtered.length===0){\n    container.innerHTML = `<div class=\"card\"><div class=\"empty-state\"><div class=\"em-icon\">🔍</div><div class=\"em-title\">No matching items</div></div></div>`;\n    return;\n  }\n  const unitOptions = ['pcs','g','kg','ml','l','packet','dozen'];\n  const sorted = filtered.slice().sort((a,b)=> (a.bought===b.bought) ? 0 : (a.bought?1:-1));\n  const rows = sorted.map(item=>{\n    const linked = findMatchingGroceryReminder(item.name);\n    return `<tr class=\"shop-row ${item.bought?'bought':''}\">\n      <td><input type=\"checkbox\" class=\"shop-select-check\" data-id=\"${item.id}\"></td>\n      <td>\n        <input type=\"text\" class=\"shop-inline-input\" style=\"width:120px;font-weight:700;\" value=\"${escapeHtml(item.name)}\" onchange=\"updateShoppingField('${item.id}','name',this.value)\">\n        ${linked?'<span class=\"shop-linked-tag\" title=\"Also tracked in Grocery Expiry Reminder\">🔗 tracked</span>':''}\n      </td>\n      <td>\n        <input type=\"text\" class=\"shop-inline-input\" style=\"width:64px;\" value=\"${escapeHtml(String(item.qty||''))}\" placeholder=\"qty\" onchange=\"updateShoppingField('${item.id}','qty',this.value)\">\n        <select class=\"shop-inline-input\" style=\"width:76px;\" onchange=\"updateShoppingField('${item.id}','unit',this.value)\">${unitOptions.map(u=>`<option value=\"${u}\" ${item.unit===u?'selected':''}>${u}</option>`).join('')}</select>\n      </td>\n      <td><input type=\"number\" min=\"0\" step=\"0.01\" class=\"shop-inline-input\" style=\"width:70px;\" value=\"${item.price||''}\" placeholder=\"—\" onchange=\"updateShoppingField('${item.id}','price',parseFloat(this.value)||0)\"></td>\n      <td><input type=\"date\" class=\"shop-inline-input\" value=\"${item.expiry||''}\" onchange=\"updateShoppingField('${item.id}','expiry',this.value)\"></td>\n      <td><button class=\"shop-bought-btn\" onclick=\"toggleShoppingBought('${item.id}')\" title=\"Toggle bought\">${item.bought?'✓':''}</button></td>\n      <td><button class=\"shop-act-btn ${item.linkedTransactionId?'done':''}\" onclick=\"reflectToFinance('${item.id}')\" title=\"${item.linkedTransactionId?'Already in Finance Tracker':'Add to Finance Tracker'}\">${item.linkedTransactionId?'✓ 💰':'💰'}</button></td>\n      <td><button class=\"shop-act-btn ${item.linkedGroceryId?'done':''}\" onclick=\"reflectToGrocery('${item.id}')\" title=\"${item.linkedGroceryId?'Already in Grocery Expiry Reminder':'Add to Grocery Expiry Reminder'}\">${item.linkedGroceryId?'✓ 🥦':'🥦'}</button></td>\n      <td><button class=\"icon-x\" onclick=\"deleteShoppingItem('${item.id}')\" title=\"Delete\">✕</button></td>\n    </tr>`;\n  }).join('');\n  container.innerHTML = `<div class=\"card\">\n    <div class=\"admin-actions\" style=\"margin-bottom:12px;\">\n      <button class=\"btn-outline\" onclick=\"bulkReflectToFinance()\">💰 Add Selected to Finance</button>\n      <button class=\"btn-outline\" onclick=\"bulkReflectToGrocery()\">🥦 Add Selected to Grocery</button>\n    </div>\n    <div style=\"overflow-x:auto;\">\n    <table class=\"shop-table\">\n      <thead><tr><th><input type=\"checkbox\" onclick=\"toggleSelectAllShopping(this)\" title=\"Select all\"></th><th>Item</th><th>Quantity</th><th>Price</th><th>Expiry</th><th>Bought</th><th>Finance</th><th>Grocery</th><th></th></tr></thead>\n      <tbody>${rows}</tbody>\n    </table>\n    </div>\n  </div>`;\n}\nfunction updateShoppingField(id, field, val){\n  const item = shoppingList.find(x=>x.id===id); if(!item) return;\n  item[field] = val;\n  saveShoppingList();\n  if(field==='name') drawShoppingList();\n}\nfunction toggleShoppingBought(id){\n  const item = shoppingList.find(x=>x.id===id);\n  if(item){ item.bought = !item.bought; saveShoppingList(); drawShoppingList(); }\n}\nfunction deleteShoppingItem(id){\n  shoppingList = shoppingList.filter(x=>x.id!==id);\n  saveShoppingList();\n  drawShoppingList();\n}\nfunction toggleSelectAllShopping(checkbox){\n  document.querySelectorAll('.shop-select-check').forEach(c=>{ c.checked = checkbox.checked; });\n}\nfunction getSelectedShoppingIds(){\n  return Array.from(document.querySelectorAll('.shop-select-check:checked')).map(c=>c.dataset.id);\n}\n\n/* ---------- Reflect into Personal Finance Tracker ---------- */\nfunction reflectToFinance(id){\n  const item = shoppingList.find(x=>x.id===id); if(!item) return;\n  if(item.linkedTransactionId){ showToast('Already added to Finance Tracker'); return; }\n  if(!item.price || parseFloat(item.price)<=0){\n    openModal(`\n      <div class=\"dialog-header\"><button class=\"txt-btn\" onclick=\"closeTopModal()\">Cancel</button><h2>Enter Price</h2><button class=\"txt-btn\" style=\"font-weight:800;\" onclick=\"confirmReflectFinance('${id}')\">Add</button></div>\n      <div class=\"field\" style=\"margin:18px 16px;\"><label>Price (${currencySymbol()})</label><input id=\"reflectPriceInput\" type=\"number\" step=\"0.01\" placeholder=\"0.00\" autofocus></div>\n    `);\n    return;\n  }\n  doReflectToFinance(item);\n}\nfunction confirmReflectFinance(id){\n  const wrap = document.querySelector('#modal-root .overlay');\n  const price = parseFloat(wrap.querySelector('#reflectPriceInput').value)||0;\n  if(price<=0){ showToast('Enter a price greater than 0'); return; }\n  const item = shoppingList.find(x=>x.id===id); if(!item) return;\n  item.price = price;\n  closeAllModals();\n  doReflectToFinance(item);\n}\nfunction doReflectToFinance(item){\n  const accountId = financeState.accounts[0]?.id;\n  const note = item.name + (item.qty ? ' ('+item.qty+' '+item.unit+')' : '');\n  const detected = findGroceryCategoryForItem(item.name);\n  const txn = {id:uid(), kind:'expense', category:'Groceries', amount:parseFloat(item.price)||0, date:todayStr(), time:new Date().toTimeString().slice(0,8), note, accountId, linkedShoppingId:item.id, groceryCategory: detected.category!==GROCERY_OTHERS.name?detected.category:null, groceryItem: detected.category!==GROCERY_OTHERS.name?item.name:null};\n  financeState.transactions.push(txn);\n  const acc = financeState.accounts.find(a=>a.id===accountId);\n  if(acc) acc.amount -= txn.amount;\n  item.linkedTransactionId = txn.id;\n  saveFinance(); saveShoppingList();\n  drawShoppingList();\n  showToast('Added to Finance Tracker');\n}\nfunction bulkReflectToFinance(){\n  const ids = getSelectedShoppingIds();\n  if(ids.length===0){ showToast('Select at least one item first'); return; }\n  let added=0, skipped=0;\n  ids.forEach(id=>{\n    const item = shoppingList.find(x=>x.id===id);\n    if(!item || item.linkedTransactionId || !item.price || parseFloat(item.price)<=0){ skipped++; return; }\n    doReflectToFinance(item); added++;\n  });\n  drawShoppingList();\n  showToast(`${added} added to Finance Tracker${skipped?`, ${skipped} skipped (needs a price, or already added)`:''}`);\n}\n\n/* ---------- Reflect into Grocery Expiry Reminder ---------- */\nfunction findGroceryCategoryForItem(name){\n  const lower = name.trim().toLowerCase();\n  for(const cat of GROCERY_CATEGORIES){\n    const found = cat.items.find(it=>it.name.toLowerCase()===lower);\n    if(found) return {category:cat.name, icon:found.icon};\n  }\n  return {category:GROCERY_OTHERS.name, icon:'🥡'};\n}\nfunction reflectToGrocery(id){\n  const item = shoppingList.find(x=>x.id===id); if(!item) return;\n  if(item.linkedGroceryId){ showToast('Already added to Grocery Expiry Reminder'); return; }\n  if(!item.expiry){\n    openModal(`\n      <div class=\"dialog-header\"><button class=\"txt-btn\" onclick=\"closeTopModal()\">Cancel</button><h2>Enter Expiry Date</h2><button class=\"txt-btn\" style=\"font-weight:800;\" onclick=\"confirmReflectGrocery('${id}')\">Add</button></div>\n      <div class=\"field\" style=\"margin:18px 16px;\"><label>Expiry Date</label><input id=\"reflectExpiryInput\" type=\"date\" value=\"${todayStr()}\" autofocus></div>\n    `);\n    return;\n  }\n  doReflectToGrocery(item);\n}\nfunction confirmReflectGrocery(id){\n  const wrap = document.querySelector('#modal-root .overlay');\n  const expiry = wrap.querySelector('#reflectExpiryInput').value;\n  if(!expiry){ showToast('Pick an expiry date'); return; }\n  const item = shoppingList.find(x=>x.id===id); if(!item) return;\n  item.expiry = expiry;\n  closeAllModals();\n  doReflectToGrocery(item);\n}\nfunction doReflectToGrocery(item){\n  const found = findGroceryCategoryForItem(item.name);\n  const groc = {id:uid(), category:found.category, item:item.name, icon:found.icon, expiryDate:item.expiry, quantity: item.qty?(item.qty+' '+item.unit):'', note:'', timingMode:'default', customAlertTime:null, customOffsets:null, alarmDurationSec:null, addedDate:todayStr(), fromTransactionId:null, linkedShoppingId:item.id};\n  groceryReminders.push(groc);\n  item.linkedGroceryId = groc.id;\n  saveGroceryRem(); saveShoppingList();\n  drawShoppingList();\n  showToast('Added to Grocery Expiry Reminder');\n}\nfunction bulkReflectToGrocery(){\n  const ids = getSelectedShoppingIds();\n  if(ids.length===0){ showToast('Select at least one item first'); return; }\n  let added=0, skipped=0;\n  ids.forEach(id=>{\n    const item = shoppingList.find(x=>x.id===id);\n    if(!item || item.linkedGroceryId || !item.expiry){ skipped++; return; }\n    doReflectToGrocery(item); added++;\n  });\n  drawShoppingList();\n  showToast(`${added} added to Grocery Reminder${skipped?`, ${skipped} skipped (needs an expiry date, or already added)`:''}`);\n}\n\n/* ---------- Import from a document (txt, csv, Excel, PDF, or an image) ---------- */\nfunction triggerImportFile(){ document.getElementById('shopImportInput').click(); }\n\n/* Pulls a handwritten/printed price out of a line, e.g. \"Rice 5kg Rs.250\"\n   or \"Turmeric 100gm ₹40\", and returns the remaining text to parse further. */\nfunction extractPrice(line){\n  let m = line.match(/(?:₹|rs\\.?|inr\\.?|\\$)\\s*(\\d+(\\.\\d+)?)/i);\n  if(!m) m = line.match(/(\\d+(\\.\\d+)?)\\s*(?:₹|rs\\.?|inr\\.?|\\$)/i);\n  if(m) return {price: m[1], rest: line.replace(m[0],'').trim()};\n  return {price:'', rest: line};\n}\nfunction normalizeUnitWord(u){\n  u = (u||'').toLowerCase().trim();\n  if(/^(kgs?|kilograms?)$/.test(u)) return 'kg';\n  if(/^(gms?|grams?|g)$/.test(u)) return 'g';\n  if(/^mls?$/.test(u)) return 'ml';\n  if(/^(ltrs?|litres?|liters?|l)$/.test(u)) return 'l';\n  if(/^(packets?|pkts?)$/.test(u)) return 'packet';\n  if(/^dozens?$/.test(u)) return 'dozen';\n  return 'pcs';\n}\nconst UNIT_WORD_RE = '(?:kgs?|kilograms?|gms?|grams?|g|mls?|ltrs?|litres?|liters?|l|pcs?|pieces?|pc|packets?|pkts?|dozens?)';\n/* Extracts a quantity (kept as free text — handles \"1/2\", \"5-7\", plain\n   numbers, etc.) and a normalized unit from a string like \"100 gm\". */\nfunction extractQtyUnit(str){\n  str = (str||'').trim();\n  if(!str) return {qty:'', unit:'pcs'};\n  const re = new RegExp('^([\\\\d.\\\\/\\\\-\\\\s]+)\\\\s*(' + UNIT_WORD_RE + ')?\\\\b', 'i');\n  const m = str.match(re);\n  if(m && m[1] && m[1].trim()){\n    return {qty: m[1].trim(), unit: normalizeUnitWord(m[2])};\n  }\n  return {qty:'', unit:'pcs'};\n}\n/* Best-effort line parser shared by text/CSV import, PDF text, and OCR\n   output. Skips obvious section-header lines (all caps, no digits). */\nfunction parseListText(text){\n  const lines = text.split(/\\r?\\n/).map(l=>l.trim()).filter(Boolean);\n  const rows = lines.map(line=>{\n    if(/^[A-Z\\s\\/&(),.-]+$/.test(line) && !/\\d/.test(line) && line.replace(/\\s/g,'').length>3) return null;\n    if(/^(item|name)s?$/i.test(line) || /^quantity$/i.test(line)) return null;\n\n    const priceInfo = extractPrice(line);\n    let working = priceInfo.rest;\n\n    if(working.includes(',')){\n      const parts = working.split(',').map(p=>p.trim());\n      const qu = extractQtyUnit(parts[1]||'');\n      return {\n        name: parts[0]||'',\n        qty: qu.qty || parts[1] || '',\n        unit: parts[2] ? normalizeUnitWord(parts[2]) : (qu.unit||'pcs'),\n        price: priceInfo.price || parts[3] || '',\n        expiry: parts[4] || ''\n      };\n    }\n    if(working.includes('\\t') || working.includes('|')){\n      const parts = working.split(/\\t+|\\|+/).map(p=>p.trim()).filter(Boolean);\n      if(parts.length>=2){\n        const qu = extractQtyUnit(parts[1]);\n        return {name:parts[0], qty:qu.qty||parts[1], unit:qu.unit, price:priceInfo.price, expiry:''};\n      }\n    }\n    const trailRe = new RegExp('^(.*?)[\\\\s,-]+([\\\\d.\\\\/\\\\-]+\\\\s*' + UNIT_WORD_RE + ')\\\\s*$', 'i');\n    const trailMatch = working.match(trailRe);\n    if(trailMatch){\n      const qu = extractQtyUnit(trailMatch[2]);\n      return {name:trailMatch[1].trim(), qty:qu.qty, unit:qu.unit, price:priceInfo.price, expiry:''};\n    }\n    return {name:working.trim(), qty:'', unit:'pcs', price:priceInfo.price, expiry:''};\n  });\n  return rows.filter(r=>r && r.name && r.name.length>1);\n}\nfunction handleImportFile(file){\n  if(!file) return;\n  const name = (file.name||'').toLowerCase();\n  const type = file.type||'';\n  document.getElementById('shopImportInput').value = '';\n  currentImportLabel = 'Imported Items';\n\n  if(type.startsWith('image/') || /\\.(png|jpe?g|webp)$/i.test(name)){\n    const reader = new FileReader();\n    reader.onload = (e)=>{ currentScanImageDataUrl = e.target.result; openScanPreviewModal(); };\n    reader.readAsDataURL(file);\n    return;\n  }\n  if(/\\.(xlsx|xls)$/i.test(name)){\n    showToast('Reading spreadsheet…');\n    parseExcelFile(file).then(rows=>{\n      if(rows.length===0){ showToast('No items found in that spreadsheet'); return; }\n      openImportReviewModal(rows);\n    }).catch(()=> showToast('Could not read the spreadsheet — needs internet the first time. Try again, or use a text/CSV file instead.'));\n    return;\n  }\n  if(/\\.pdf$/i.test(name)){\n    showToast('Reading PDF…');\n    parsePdfFile(file).then(rows=>{\n      if(rows.length===0){ showToast('No items found in that PDF'); return; }\n      openImportReviewModal(rows);\n    }).catch(()=> showToast('Could not read the PDF — needs internet the first time. Try again, or use a text/CSV file instead.'));\n    return;\n  }\n  const reader = new FileReader();\n  reader.onload = (e)=>{\n    const rows = parseListText(String(e.target.result||''));\n    if(rows.length===0){ showToast('No items found in that file'); return; }\n    openImportReviewModal(rows);\n  };\n  reader.readAsText(file);\n}\n\n/* ---------- Excel (.xlsx/.xls) — lazy-loaded, needs internet the first time ---------- */\nfunction ensureXlsxLibLoaded(){\n  return new Promise((resolve, reject)=>{\n    if(typeof XLSX!=='undefined'){ resolve(); return; }\n    const script = document.createElement('script');\n    script.src = 'https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js';\n    script.onload = ()=>resolve();\n    script.onerror = ()=>reject(new Error('Failed to load spreadsheet library'));\n    document.head.appendChild(script);\n  });\n}\nasync function parseExcelFile(file){\n  await ensureXlsxLibLoaded();\n  const buf = await file.arrayBuffer();\n  const wb = XLSX.read(buf, {type:'array'});\n  const sheet = wb.Sheets[wb.SheetNames[0]];\n  const rawRows = XLSX.utils.sheet_to_json(sheet, {header:1, defval:''});\n  const results = [];\n  rawRows.forEach(row=>{\n    const first = String(row[0]||'').trim();\n    const second = String(row[1]||'').trim();\n    const third = String(row[2]||'').trim();\n    if(!first) return;\n    if(/^(item|name)s?$/i.test(first) && /^quant/i.test(second)) return;\n    if(!second && !/\\d/.test(first)) return; // section header row (e.g. \"GRAINS/FLOURS\") — skip\n    const combined = second + (third?(' '+third):'');\n    const priceInfo = extractPrice(combined || first);\n    const qu = extractQtyUnit(priceInfo.rest || second);\n    results.push({ name:first, qty: qu.qty || second || '', unit: qu.unit||'pcs', price: priceInfo.price||'', expiry:'' });\n  });\n  return results;\n}\n\n/* ---------- PDF — lazy-loaded, needs internet the first time ---------- */\nfunction ensurePdfLibLoaded(){\n  return new Promise((resolve, reject)=>{\n    if(typeof pdfjsLib!=='undefined'){ resolve(); return; }\n    const script = document.createElement('script');\n    script.src = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.min.js';\n    script.onload = ()=>{\n      try{ pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js'; }catch(e){}\n      resolve();\n    };\n    script.onerror = ()=>reject(new Error('Failed to load PDF library'));\n    document.head.appendChild(script);\n  });\n}\nasync function parsePdfFile(file){\n  await ensurePdfLibLoaded();\n  const buf = await file.arrayBuffer();\n  const doc = await pdfjsLib.getDocument({data:buf}).promise;\n  let allLines = [];\n  for(let i=1;i<=doc.numPages;i++){\n    const page = await doc.getPage(i);\n    const content = await page.getTextContent();\n    const items = content.items.map(it=>({str:it.str, x:it.transform[4], y:it.transform[5]}));\n    items.sort((a,b)=> b.y-a.y || a.x-b.x);\n    let lines = [], currentY = null, currentLine = [];\n    items.forEach(it=>{\n      if(currentY===null || Math.abs(it.y-currentY)>3){\n        if(currentLine.length) lines.push(currentLine.map(s=>s.str).join(' '));\n        currentLine = [it]; currentY = it.y;\n      } else {\n        currentLine.push(it);\n      }\n    });\n    if(currentLine.length) lines.push(currentLine.map(s=>s.str).join(' '));\n    allLines = allLines.concat(lines);\n  }\n  return parseListText(allLines.join('\\n'));\n}\n\n/* ---------- Scan a document photo (OCR, needs internet the first time) ---------- */\nfunction triggerScanFile(){ document.getElementById('shopScanInput').click(); }\nfunction handleScanFile(file){\n  if(!file) return;\n  const reader = new FileReader();\n  reader.onload = (e)=>{ currentScanImageDataUrl = e.target.result; document.getElementById('shopScanInput').value=''; openScanPreviewModal(); };\n  reader.readAsDataURL(file);\n}\nfunction openScanPreviewModal(){\n  openModal(`\n    <div class=\"dialog-header\"><button class=\"txt-btn\" onclick=\"closeTopModal()\">Cancel</button><h2>Scan Document</h2><div style=\"width:40px\"></div></div>\n    <div style=\"padding:16px;\">\n      <img src=\"${currentScanImageDataUrl}\" style=\"width:100%;max-height:280px;object-fit:contain;background:#000;border-radius:10px;margin-bottom:12px;\" />\n      <p style=\"font-size:12.5px;color:var(--muted);margin:0 0 12px;\">Text recognition downloads a small engine the first time this is used (needs internet). Handwritten or printed prices are picked up automatically where possible. If you're offline, cancel and use \"Import Document\" with a text/CSV file instead — that always works offline.</p>\n      <div id=\"scanStatus\" style=\"font-size:13px;color:var(--muted);margin-bottom:10px;min-height:18px;\"></div>\n      <button class=\"save-btn\" style=\"margin:0;width:100%;\" id=\"scanExtractBtn\" onclick=\"runOcrOnImage()\">🔎 Extract Items</button>\n    </div>\n  `);\n}\nfunction ensureOcrLibLoaded(){\n  return new Promise((resolve, reject)=>{\n    if(typeof Tesseract!=='undefined'){ resolve(); return; }\n    const script = document.createElement('script');\n    script.src = 'https://cdnjs.cloudflare.com/ajax/libs/tesseract.js/5.0.4/tesseract.min.js';\n    script.onload = ()=>resolve();\n    script.onerror = ()=>reject(new Error('Failed to load OCR library'));\n    document.head.appendChild(script);\n  });\n}\nasync function runOcrOnImage(){\n  const statusEl = document.getElementById('scanStatus');\n  const btn = document.getElementById('scanExtractBtn');\n  if(btn) btn.disabled = true;\n  if(statusEl) statusEl.textContent = 'Loading recognition engine…';\n  try{\n    await ensureOcrLibLoaded();\n    if(statusEl) statusEl.textContent = 'Reading text from the image… this can take a moment.';\n    const result = await Tesseract.recognize(currentScanImageDataUrl, 'eng');\n    const text = (result && result.data && result.data.text) ? result.data.text : '';\n    const rows = parseListText(text);\n    closeAllModals();\n    if(rows.length===0){ showToast('No items recognized — try Import Document instead, or add manually'); return; }\n    currentImportLabel = 'Scanned Items';\n    openImportReviewModal(rows);\n  }catch(err){\n    if(statusEl) statusEl.textContent = '';\n    showToast('Could not load text recognition (no internet?) — try Import Document instead.');\n    if(btn) btn.disabled = false;\n  }\n}\n\n/* ---------- Shared review step for Import & Scan ---------- */\nfunction openImportReviewModal(rows){\n  importReviewRows = rows.map(r=>({ id:uid(), name:r.name||'', qty:r.qty||'', unit:r.unit||'pcs', price:r.price||'', expiry:r.expiry||'' }));\n  const wrap = document.querySelector('#modal-root .overlay') || openModal('');\n  drawImportReviewModal(wrap);\n}\nfunction drawImportReviewModal(wrap){\n  wrap = wrap || document.querySelector('#modal-root .overlay');\n  const dlg = wrap.querySelector('.dialog');\n  const rowsHtml = importReviewRows.map(r=>{\n    const match = findMatchingGroceryReminder(r.name);\n    return `<tr>\n      <td><input type=\"text\" value=\"${escapeHtml(r.name)}\" oninput=\"updateImportRow('${r.id}','name',this.value)\" style=\"width:110px;\"></td>\n      <td><input type=\"number\" value=\"${escapeHtml(String(r.qty))}\" oninput=\"updateImportRow('${r.id}','qty',this.value)\" style=\"width:60px;\"></td>\n      <td><select onchange=\"updateImportRow('${r.id}','unit',this.value)\">\n        <option value=\"pcs\" ${r.unit==='pcs'?'selected':''}>pcs</option>\n        <option value=\"g\" ${r.unit==='g'?'selected':''}>g</option>\n        <option value=\"kg\" ${r.unit==='kg'?'selected':''}>kg</option>\n      </select></td>\n      <td><input type=\"number\" step=\"0.01\" value=\"${escapeHtml(String(r.price))}\" oninput=\"updateImportRow('${r.id}','price',this.value)\" style=\"width:70px;\" placeholder=\"optional\"></td>\n      <td><input type=\"date\" value=\"${r.expiry||''}\" oninput=\"updateImportRow('${r.id}','expiry',this.value)\"></td>\n      <td>${match?'<span class=\"exp-badge soon\">tracked</span>':''}</td>\n      <td><button class=\"icon-x\" onclick=\"removeImportRow('${r.id}')\">✕</button></td>\n    </tr>`;\n  }).join('');\n  dlg.innerHTML = `\n    <div class=\"dialog-header\"><button class=\"txt-btn\" onclick=\"closeTopModal()\">Cancel</button><h2>Review ${escapeHtml(currentImportLabel)}</h2><button class=\"txt-btn\" style=\"font-weight:800;\" onclick=\"confirmImportRows()\">Add All (${importReviewRows.length})</button></div>\n    <div style=\"padding:14px 16px;overflow-x:auto;\">\n      <p style=\"font-size:12.5px;color:var(--muted);margin:0 0 10px;\">Review and edit before adding — price and expiry are optional. Items already tracked in Grocery Expiry Reminder are flagged.</p>\n      <table class=\"shop-table\" style=\"min-width:560px;\">\n        <thead><tr><th>Item</th><th>Qty</th><th>Unit</th><th>Price</th><th>Expiry</th><th></th><th></th></tr></thead>\n        <tbody>${rowsHtml || '<tr><td colspan=\"7\" style=\"text-align:center;color:var(--muted);padding:20px;\">No rows left</td></tr>'}</tbody>\n      </table>\n    </div>\n  `;\n}\nfunction updateImportRow(id, field, val){ const r=importReviewRows.find(x=>x.id===id); if(r) r[field]=val; }\nfunction removeImportRow(id){ importReviewRows = importReviewRows.filter(x=>x.id!==id); drawImportReviewModal(); }\nfunction confirmImportRows(){\n  let count = 0;\n  importReviewRows.forEach(r=>{\n    if(!r.name || !r.name.trim()) return;\n    shoppingList.push({id:uid(), name:r.name.trim(), qty:r.qty||'', unit:r.unit||'pcs', price:parseFloat(r.price)||0, expiry:r.expiry||'', bought:false, addedDate:todayStr(), linkedTransactionId:null, linkedGroceryId:null});\n    count++;\n  });\n  saveShoppingList();\n  closeAllModals();\n  drawShoppingList();\n  showToast(count+' item(s) added to your shopping list');\n}\n\n/* ============================================================\n   ================  ALARM & NOTIFICATION SYSTEM  ================\n   ------------------------------------------------------------\n   Runs entirely in the browser while this page is open (there is\n   no server / push service behind this file), checking every 20\n   seconds whether any medicine, expense, or grocery reminder has\n   reached its scheduled alert time. When one is due it plays a\n   looping alarm sound, shows a banner (and a system notification\n   if permission was granted), and waits for the user to resolve\n   it. Marking it done/paid/acknowledged stops the alarm and is\n   saved immediately.\n   ============================================================ */\nfunction pad2(n){ return String(n).padStart(2,'0'); }\nfunction hhmmNow(){ const d=new Date(); return pad2(d.getHours())+':'+pad2(d.getMinutes()); }\nfunction dateAtTime(dateStr, hhmm){ return new Date(dateStr+'T'+(hhmm||'09:00')+':00'); }\nfunction addDays(dateStr, n){ const d=new Date(dateStr+'T00:00:00'); d.setDate(d.getDate()+n); return d.toISOString().slice(0,10); }\nfunction weekdayAbbrev(d){ return ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'][d.getDay()]; }\n\nfunction enableAlerts(){\n  unlockAudio();\n  try{\n    if(typeof Notification!=='undefined' && Notification.permission!=='granted' && Notification.permission!=='denied'){\n      Notification.requestPermission().then(p=>{ notifyPermissionGranted = (p==='granted'); updateBellBtn(); showToast(notifyPermissionGranted?'Alerts enabled':'Notifications blocked — sound alarms will still work'); }).catch(()=>{ showToast('Notifications unavailable — sound alarms will still work'); });\n    } else {\n      notifyPermissionGranted = (typeof Notification!=='undefined' && Notification.permission==='granted');\n      showToast(audioUnlocked ? 'Alarm sound is enabled' : 'Click again after interacting with the page to unlock sound');\n    }\n  }catch(e){\n    showToast('Notifications unavailable — sound alarms will still work');\n  }\n  updateBellBtn();\n}\nfunction updateBellBtn(){\n  const b = document.getElementById('bellBtn');\n  if(!b) return;\n  b.classList.toggle('on', audioUnlocked || notifyPermissionGranted);\n}\nfunction unlockAudio(){\n  const audio = document.getElementById('alarmAudio');\n  if(!audio || audioUnlocked) return;\n  audio.play().then(()=>{ audio.pause(); audio.currentTime=0; audioUnlocked=true; updateBellBtn(); }).catch(()=>{});\n}\nfunction playQuickBeep(){\n  try{\n    const src = document.getElementById('alarmAudio') && document.getElementById('alarmAudio').src;\n    if(!src) return;\n    const a = new Audio(src);\n    a.volume = 0.6;\n    a.play().catch(()=>{});\n    setTimeout(()=>{ try{ a.pause(); }catch(e){} }, 500);\n  }catch(e){}\n}\ndocument.addEventListener('click', function firstClickUnlock(){ unlockAudio(); }, {once:false});\n\nfunction pruneDismissed(){\n  const cutoff = addDays(todayStr(), -14);\n  dismissedAlarms = dismissedAlarms.filter(k=>{\n    const m = k.match(/(\\d{4}-\\d{2}-\\d{2})/);\n    return !m || m[1] >= cutoff;\n  });\n  saveDismissed();\n}\n\n/* Build the list of currently-due alarm instances across all three\n   reminder types, skipping anything already dismissed, snoozed, or\n   already resolved by the user. Each reminder can either use the\n   admin panel's defaults or its own \"Customize\" overrides (time,\n   how many days before, and how long the alarm rings for). */\nfunction buildDueAlarms(){\n  if(!config.alarmsEnabled) return [];\n  const due = [];\n  const now = new Date();\n  const today = todayStr();\n\n  if(config.features.medicineReminder){\n    medReminders.forEach(m=>{\n      const applies = m.freq==='weekly' ? (m.days||[]).includes(weekdayAbbrev(now)) : true;\n      if(!applies) return;\n      const useCustom = m.timingMode==='custom';\n      const ringDurationSec = (useCustom && typeof m.alarmDurationSec==='number') ? m.alarmDurationSec : config.alarmDurationSec;\n      (m.times||[]).forEach(slot=>{\n        const key = `med:${m.id}:${today}:${slot}`;\n        const already = (m.status[today]||{})[slot];\n        if(already || dismissedAlarms.includes(key)) return;\n        if(snoozeMap[key] && Date.now()<snoozeMap[key]) return;\n        const timeStr = (useCustom && m.customTimes && m.customTimes[slot]) ? m.customTimes[slot] : (config.medicineTimes[slot]||'08:00');\n        const target = dateAtTime(today, timeStr);\n        if(now>=target) due.push({key, type:'medicine', id:m.id, slot, title:'💊 Time to take: '+m.name, sub:slot+' dose · tap Mark Done once taken', time:target, ringDurationSec});\n      });\n    });\n  }\n  if(config.features.expenseReminder){\n    expenseReminders.forEach(r=>{\n      if(r.paid) return;\n      const useCustom = r.timingMode==='custom';\n      const offsets = (useCustom && Array.isArray(r.customOffsets) && r.customOffsets.length) ? r.customOffsets : config.expenseOffsets;\n      const alertTime = (useCustom && r.customAlertTime) ? r.customAlertTime : config.alertTime;\n      const ringDurationSec = (useCustom && typeof r.alarmDurationSec==='number') ? r.alarmDurationSec : config.alarmDurationSec;\n      const sorted = offsets.slice().sort((a,b)=>a-b); // most urgent (closest to due date) first\n      for(const off of sorted){\n        const triggerDate = addDays(r.date, -off);\n        const key = `exp:${r.id}:${r.date}:${off}`;\n        if(dismissedAlarms.includes(key)) continue;\n        if(snoozeMap[key] && Date.now()<snoozeMap[key]) continue;\n        const target = dateAtTime(triggerDate, alertTime);\n        if(now>=target){\n          const label = off===0 ? 'due today' : (off===1 ? 'due tomorrow' : `due in ${off} days`);\n          due.push({key, type:'expense', id:r.id, title:'💳 '+r.name+' is '+label, sub:fmt(r.amount)+' · '+label, time:target, ringDurationSec});\n          break;\n        }\n      }\n    });\n  }\n  if(config.features.groceryExpiryReminder){\n    groceryReminders.forEach(g=>{\n      const useCustom = g.timingMode==='custom';\n      const offsets = (useCustom && Array.isArray(g.customOffsets) && g.customOffsets.length) ? g.customOffsets : config.groceryOffsets;\n      const alertTime = (useCustom && g.customAlertTime) ? g.customAlertTime : config.alertTime;\n      const ringDurationSec = (useCustom && typeof g.alarmDurationSec==='number') ? g.alarmDurationSec : config.alarmDurationSec;\n      const sorted = offsets.slice().sort((a,b)=>a-b);\n      for(const off of sorted){\n        const triggerDate = addDays(g.expiryDate, -off);\n        const key = `groc:${g.id}:${g.expiryDate}:${off}`;\n        if(dismissedAlarms.includes(key)) continue;\n        if(snoozeMap[key] && Date.now()<snoozeMap[key]) continue;\n        const target = dateAtTime(triggerDate, alertTime);\n        if(now>=target){\n          const label = off===0 ? 'expires today' : (off===1 ? 'expires tomorrow' : `expires in ${off} days`);\n          due.push({key, type:'grocery', id:g.id, title:'🥦 '+g.item+' '+label, sub:g.category+(g.quantity?' · '+g.quantity:''), time:target, ringDurationSec});\n          break;\n        }\n      }\n    });\n  }\n  if(config.features.generalReminder){\n    generalReminders.forEach(r=>{\n      const ringDurationSec = typeof r.alarmDurationSec==='number' ? r.alarmDurationSec : config.alarmDurationSec;\n      if(r.repeat==='none'){\n        if(r.doneOnce) return;\n        const key = `gen:${r.id}:${r.date}:once`;\n        if(dismissedAlarms.includes(key)) return;\n        if(snoozeMap[key] && Date.now()<snoozeMap[key]) return;\n        const target = dateAtTime(r.date, r.time);\n        if(now>=target) due.push({key, type:'general', id:r.id, title:'⏰ '+r.title, sub:r.note||'Tap Mark Done once handled', time:target, ringDurationSec});\n      } else {\n        const applies = r.repeat==='weekly' ? (r.days||[]).includes(weekdayAbbrev(now)) : true;\n        if(!applies) return;\n        if((r.status||{})[today]) return;\n        const key = `gen:${r.id}:${today}:rep`;\n        if(dismissedAlarms.includes(key)) return;\n        if(snoozeMap[key] && Date.now()<snoozeMap[key]) return;\n        const target = dateAtTime(today, r.time);\n        if(now>=target) due.push({key, type:'general', id:r.id, title:'⏰ '+r.title, sub:r.note||'Tap Mark Done once handled', time:target, ringDurationSec});\n      }\n    });\n  }\n  due.sort((a,b)=>a.time-b.time);\n  return due;\n}\n\nfunction checkReminders(){\n  if(currentAlarm) return; // one at a time — resolve the active one first\n  const due = buildDueAlarms();\n  const next = due.find(d=>!alarmQueue.some(q=>q.key===d.key));\n  if(next){ alarmQueue = due; showAlarm(next); }\n}\nlet currentAlarmTimeoutId = null;\nfunction showAlarm(alarm){\n  currentAlarm = alarm;\n  const audio = document.getElementById('alarmAudio');\n  if(audio){ audio.currentTime=0; audio.play().catch(()=>{}); }\n  if(notifyPermissionGranted){\n    try{ new Notification(alarm.title, {body:alarm.sub, icon:'🔔'}); }catch(e){}\n  }\n  const actions = alarm.type==='medicine'\n    ? `<button class=\"ab-btn-done\" onclick=\"resolveAlarm('done')\">✓ Mark Done</button><button class=\"ab-btn-snooze\" onclick=\"resolveAlarm('snooze')\">Snooze 10m</button>`\n    : alarm.type==='expense'\n    ? `<button class=\"ab-btn-done\" onclick=\"resolveAlarm('done')\">✓ Mark Paid</button><button class=\"ab-btn-snooze\" onclick=\"resolveAlarm('snooze')\">Snooze 10m</button>`\n    : alarm.type==='general'\n    ? `<button class=\"ab-btn-done\" onclick=\"resolveAlarm('done')\">✓ Mark Done</button><button class=\"ab-btn-snooze\" onclick=\"resolveAlarm('snooze')\">Snooze 10m</button>`\n    : `<button class=\"ab-btn-done\" onclick=\"resolveAlarm('done')\">✓ Got it</button><button class=\"ab-btn-used\" onclick=\"resolveAlarm('remove')\">Mark Used</button><button class=\"ab-btn-snooze\" onclick=\"resolveAlarm('snooze')\">Snooze 10m</button>`;\n  document.getElementById('alarm-banner-root').innerHTML = `\n    <div class=\"alarm-banner\">\n      <div class=\"ab-ic\">🔔</div>\n      <div class=\"ab-body\"><div class=\"ab-title\">${escapeHtml(alarm.title)}</div><div class=\"ab-sub\">${escapeHtml(alarm.sub)}</div></div>\n      <div class=\"ab-actions\">${actions}</div>\n    </div>`;\n  clearTimeout(currentAlarmTimeoutId);\n  if(alarm.ringDurationSec>0){\n    // If the customer set a ring duration and nobody responds in time,\n    // stop the noise and quietly retry in 15 minutes instead of\n    // ringing forever.\n    currentAlarmTimeoutId = setTimeout(()=>{\n      if(currentAlarm && currentAlarm.key===alarm.key){\n        snoozeMap[alarm.key] = Date.now() + 15*60*1000;\n        alarmQueue = alarmQueue.filter(q=>q.key!==alarm.key);\n        currentAlarm = null;\n        hideAlarmBanner();\n        setTimeout(checkReminders, 500);\n      }\n    }, alarm.ringDurationSec*1000);\n  }\n}\nfunction hideAlarmBanner(){\n  const audio = document.getElementById('alarmAudio');\n  if(audio){ audio.pause(); audio.currentTime=0; }\n  document.getElementById('alarm-banner-root').innerHTML = '';\n}\nfunction resolveAlarm(action){\n  if(!currentAlarm) return;\n  const alarm = currentAlarm;\n  clearTimeout(currentAlarmTimeoutId);\n  if(action==='snooze'){\n    snoozeMap[alarm.key] = Date.now() + 10*60*1000;\n  } else if(action==='done'){\n    dismissedAlarms.push(alarm.key); saveDismissed();\n    if(alarm.type==='medicine'){\n      const m = medReminders.find(x=>x.id===alarm.id);\n      if(m){ const today=todayStr(); m.status[today]=m.status[today]||{}; m.status[today][alarm.slot]=true; saveMedRemState(); if(document.getElementById('view-medicineRem').classList.contains('active')) drawMedList(); }\n    } else if(alarm.type==='expense'){\n      const r = expenseReminders.find(x=>x.id===alarm.id);\n      if(r){ r.paid=true; saveExpRem(); if(document.getElementById('view-expenseRem').classList.contains('active')) drawExpenseRemList(); }\n    } else if(alarm.type==='grocery'){\n      if(document.getElementById('view-groceryRem').classList.contains('active')) drawGroceryList();\n    } else if(alarm.type==='general'){\n      const r = generalReminders.find(x=>x.id===alarm.id);\n      if(r){\n        if(r.repeat==='none'){ r.doneOnce = true; } else { const today=todayStr(); r.status=r.status||{}; r.status[today]=true; }\n        saveGeneralRem();\n        if(document.getElementById('view-generalRem').classList.contains('active')) drawGeneralRemList();\n      }\n    }\n  } else if(action==='remove' && alarm.type==='grocery'){\n    dismissedAlarms.push(alarm.key); saveDismissed();\n    deleteGroceryItem(alarm.id);\n  }\n  alarmQueue = alarmQueue.filter(q=>q.key!==alarm.key);\n  currentAlarm = null;\n  hideAlarmBanner();\n  setTimeout(checkReminders, 400);\n}\nfunction startAlarmScheduler(){\n  pruneDismissed();\n  checkReminders();\n  setInterval(checkReminders, 20000);\n}\n/* Called when a reminder is marked done/paid from its own screen\n   (rather than from the alarm banner) — if that exact instance is\n   the one currently alarming, stop the alarm immediately too. */\nfunction syncAlarmIfMatches(key){\n  dismissedAlarms.push(key); saveDismissed();\n  if(currentAlarm && currentAlarm.key===key){\n    clearTimeout(currentAlarmTimeoutId);\n    alarmQueue = alarmQueue.filter(q=>q.key!==key);\n    currentAlarm = null;\n    hideAlarmBanner();\n    setTimeout(checkReminders, 400);\n  }\n}\n/* Like syncAlarmIfMatches, but matches by reminder type+id instead of\n   an exact key — needed for expense/grocery reminders since their\n   offsets (and therefore alarm keys) can now be customized per item,\n   so we can't predict the exact key that might be showing. */\nfunction syncAlarmIfType(type, id){\n  if(currentAlarm && currentAlarm.type===type && currentAlarm.id===id){\n    clearTimeout(currentAlarmTimeoutId);\n    alarmQueue = alarmQueue.filter(q=>!(q.type===type && q.id===id));\n    currentAlarm = null;\n    hideAlarmBanner();\n    setTimeout(checkReminders, 400);\n  }\n}\n\n/* ============================================================\n   ================  VOICE ASSISTANT  ============================\n   ------------------------------------------------------------\n   Uses the browser's built-in Web Speech API (SpeechRecognition) —\n   no external library needed. Note: on most browsers this still\n   sends audio to the browser vendor's speech-to-text servers to\n   work at all, so it generally requires an internet connection\n   even though no extra code is loaded for it. Understanding is\n   simple keyword/pattern matching (not a full AI assistant): it\n   recognizes short direct phrases and pre-fills the matching form\n   for the customer to review and confirm, rather than silently\n   auto-saving anything it might have misheard.\n   ============================================================ */\nlet voiceRecognition = null;\nlet voiceListening = false;\nfunction initVoiceAssistant(){\n  const btn = document.getElementById('voiceFab');\n  if(!btn) return;\n  const SpeechRecognitionCtor = window.SpeechRecognition || window.webkitSpeechRecognition;\n  if(!config.features.voiceAssistant || !SpeechRecognitionCtor){\n    btn.style.display = 'none';\n    return;\n  }\n  btn.style.display = 'flex';\n  if(voiceRecognition) return; // already initialized\n  try{\n    voiceRecognition = new SpeechRecognitionCtor();\n    voiceRecognition.lang = 'en-US';\n    voiceRecognition.continuous = false;\n    voiceRecognition.interimResults = false;\n    voiceRecognition.maxAlternatives = 1;\n    voiceRecognition.onresult = (e)=>{ handleVoiceCommand(e.results[0][0].transcript); };\n    voiceRecognition.onerror = (e)=>{\n      setVoiceListening(false);\n      showToast('Voice: '+(e.error==='not-allowed' ? 'microphone permission denied' : 'could not hear you, try again'));\n    };\n    voiceRecognition.onend = ()=>{ setVoiceListening(false); };\n  }catch(e){\n    btn.style.display = 'none';\n  }\n}\nfunction toggleVoiceListening(){\n  if(!voiceRecognition){ showToast('Voice assistant is not supported in this browser'); return; }\n  if(voiceListening){ voiceRecognition.stop(); return; }\n  try{\n    voiceRecognition.start();\n    setVoiceListening(true);\n    showVoiceTranscript('Listening… try \"add expense 200 for food\", \"add milk 2 kg to shopping list\", or \"remind me to call mom at 5 pm\"');\n  }catch(e){\n    showToast('Could not start listening — try again');\n  }\n}\nfunction setVoiceListening(on){\n  voiceListening = on;\n  const btn = document.getElementById('voiceFab');\n  if(btn) btn.classList.toggle('listening', on);\n  if(!on) setTimeout(hideVoiceTranscript, 3500);\n}\nfunction showVoiceTranscript(text){\n  const el = document.getElementById('voiceTranscriptBubble');\n  if(!el) return;\n  el.textContent = text;\n  el.classList.remove('hidden');\n}\nfunction hideVoiceTranscript(){\n  const el = document.getElementById('voiceTranscriptBubble');\n  if(el) el.classList.add('hidden');\n}\nfunction handleVoiceCommand(rawText){\n  const text = (rawText||'').trim();\n  const lower = text.toLowerCase();\n  showVoiceTranscript('Heard: \"'+text+'\"');\n\n  const amountMatch = lower.match(/(\\d+(\\.\\d+)?)/);\n  const isExpenseIntent = /\\b(expense|spent|paid|bought|purchase|purchased)\\b/.test(lower);\n  const isIncomeIntent = /\\b(income|received|earned|salary|got paid)\\b/.test(lower);\n  const isReminderIntent = /\\b(remind me|reminder|alarm|wake me|meeting)\\b/.test(lower);\n  const isShoppingIntent = /\\b(shopping list|to buy|add to( the| my)? list)\\b/.test(lower);\n\n  // 1) Expense / Income transaction\n  if((isExpenseIntent || isIncomeIntent) && amountMatch){\n    const amount = amountMatch[1];\n    const kind = isIncomeIntent ? 'income' : 'expense';\n    const cats = kind==='expense' ? EXPENSE_CATS : INCOME_CATS;\n    const category = cats.find(c=>lower.includes(c.name.toLowerCase()));\n    let note = text.replace(amountMatch[0],'')\n      .replace(/\\b(expense|spent|paid|bought|purchase|purchased|income|received|earned|salary|got paid|for|of|add|rupees?|dollars?|₹|\\$)\\b/gi,'')\n      .replace(/\\s+/g,' ').trim();\n    if(!config.features.finance){ showToast('Personal Finance Tracker is turned off in Admin Panel'); return; }\n    enterFinance();\n    openAddTransaction(kind);\n    pickCategory(category ? category.name : cats[cats.length-1].name);\n    addCtx.amountStr = amount;\n    addCtx.note = note;\n    const numEl = document.getElementById('amountNum'); if(numEl) numEl.textContent = currencySymbol()+amount;\n    const noteEl = document.getElementById('txnNote'); if(noteEl) noteEl.value = note;\n    showToast('Review the amount & category, then tap Save');\n    return;\n  }\n\n  // 2) Shopping list item\n  if(isShoppingIntent || (!isExpenseIntent && !isIncomeIntent && !isReminderIntent && /\\b(add|buy)\\b/.test(lower))){\n    if(!config.features.shoppingList){ showToast('List to Buy is turned off in Admin Panel'); return; }\n    let clean = text.replace(/\\b(add|to|the|my|shopping list|list|buy)\\b/gi,'').replace(/\\s+/g,' ').trim();\n    const qtyMatch = clean.match(/(\\d+(\\.\\d+)?)\\s*(kg|g|grams?|kilograms?|pcs|pieces|pc)?/i);\n    let qty='', unit='pcs', name=clean;\n    if(qtyMatch){\n      qty = qtyMatch[1];\n      let u = (qtyMatch[3]||'pcs').toLowerCase();\n      if(u.startsWith('kilo')) unit='kg'; else if(u.startsWith('gram')) unit='g'; else if(u.startsWith('pc')||u.startsWith('piece')) unit='pcs'; else if(u) unit=u;\n      name = clean.replace(qtyMatch[0],'').trim();\n    }\n    if(!name){ showToast(\"Didn't catch the item name — please try again\"); return; }\n    enterShoppingList();\n    const nameEl = document.getElementById('shopName'); if(nameEl) nameEl.value = name;\n    const qtyEl = document.getElementById('shopQty'); if(qtyEl) qtyEl.value = qty;\n    const unitEl = document.getElementById('shopUnit'); if(unitEl) unitEl.value = unit;\n    showToast('Review the item, then tap \"+ Add\" to confirm');\n    return;\n  }\n\n  // 3) General reminder (alarms, meetings, wake-ups, etc.)\n  if(isReminderIntent){\n    if(!config.features.generalReminder){ showToast('General Reminder is turned off in Admin Panel'); return; }\n    let timeStr = '08:00';\n    const timeMatch = lower.match(/\\b(?:at|for)\\s+(\\d{1,2})(:(\\d{2}))?\\s*(am|pm)?\\b/);\n    let working = text;\n    if(timeMatch){\n      let hour = parseInt(timeMatch[1],10);\n      const min = timeMatch[3] ? parseInt(timeMatch[3],10) : 0;\n      const ampm = timeMatch[4];\n      if(ampm==='pm' && hour<12) hour+=12;\n      if(ampm==='am' && hour===12) hour=0;\n      timeStr = pad2(hour)+':'+pad2(min);\n      const re = new RegExp(timeMatch[0].replace(/[.*+?^${}()|[\\]\\\\]/g,'\\\\$&'), 'i');\n      working = working.replace(re, '');\n    }\n    let title = working.replace(/\\b(remind me to|remind me|reminder|set an? alarm|wake me( up)?|meeting)\\b/gi,'').trim();\n    title = title.replace(/^[\\s,.\\-]+|[\\s,.\\-]+$/g,'').trim();\n    if(!title) title = 'Reminder';\n    enterGeneralRem();\n    const titleEl = document.getElementById('genTitle'); if(titleEl) titleEl.value = title;\n    const timeEl = document.getElementById('genTime'); if(timeEl) timeEl.value = timeStr;\n    showToast('Review and tap \"+ Save Reminder\" to confirm');\n    return;\n  }\n\n  showToast('Didn\\'t understand — try \"add expense 200 for food\", \"add milk 2 kg to shopping list\", or \"remind me to call mom at 5 pm\"');\n}\n\n/* ============================================================\n   ================  ADMIN PANEL  ================================\n   ============================================================ */\nfunction renderAdmin(){\n  const v = document.getElementById('view-admin');\n  v.innerHTML = `\n    <button class=\"back-btn\" onclick=\"goDashboard()\">← Back to Menu</button>\n    <div class=\"sub-title-row\"><h1>⚙ Admin Panel</h1></div>\n    <div class=\"admin-shell\">\n      <div class=\"admin-grid\">\n\n        <div class=\"card\">\n          <div class=\"card-head\"><h3>Features</h3></div>\n          ${toggleRow('finance','Personal Finance Tracker','Show or hide the finance workspace')}\n          ${toggleRow('financeCharts','· Charts','Spending charts inside Finance')}\n          ${toggleRow('financeReports','· Reports','Monthly reports & budget inside Finance')}\n          ${toggleRow('financeAccounts','· Accounts','Multiple accounts inside Finance')}\n          ${toggleRow('reminders','Reminder & Tracking','Show or hide the reminders workspace')}\n          ${toggleRow('expenseReminder','· Expense Reminder','Bill / expense due-date reminders')}\n          ${toggleRow('medicineReminder','· Medicine Reminder','Daily / weekly medicine schedule')}\n          ${toggleRow('groceryExpiryReminder','· Grocery Expiry Reminder','Track grocery items by category and expiry date')}\n          ${toggleRow('generalReminder','· General Reminder','Alarms, wake-ups, meetings, and anything else')}\n          ${toggleRow('shoppingList','List to Buy','Shopping list, synced with Grocery Expiry Reminder')}\n          ${toggleRow('voiceAssistant','Voice Assistant','Speak to add transactions, shopping items, or reminders')}\n        </div>\n\n        <div class=\"card\">\n          <div class=\"card-head\"><h3>Appearance</h3></div>\n          <div class=\"field\"><label>App Name</label><input id=\"adminAppName\" type=\"text\" value=\"${escapeHtml(config.appName)}\"></div>\n          <button class=\"btn-outline\" onclick=\"saveAppName()\">Save Name</button>\n          <div style=\"height:16px\"></div>\n          <label style=\"display:block;font-size:12px;font-weight:700;color:var(--muted);text-transform:uppercase;margin-bottom:8px;\">Theme</label>\n          <div class=\"theme-swatches\">\n            ${Object.keys(THEMES).map(key=>`<div class=\"swatch ${config.theme===key?'selected':''}\" style=\"background:${THEMES[key].primary};\" onclick=\"setTheme('${key}')\">${THEMES[key].label}</div>`).join('')}\n          </div>\n        </div>\n\n        <div class=\"card\">\n          <div class=\"card-head\"><h3>Finance Settings</h3></div>\n          <div class=\"field\"><label>Default Currency</label>\n            <select id=\"adminCurrency\">${CURRENCIES.map(c=>`<option value=\"${c.code}\" ${c.code===config.currency?'selected':''}>${c.code} ( ${c.sym} ) ${c.name}</option>`).join('')}</select>\n          </div>\n          <button class=\"btn-outline\" onclick=\"saveCurrency()\">Save Currency</button>\n        </div>\n\n        <div class=\"card\" style=\"grid-column:1 / -1;\">\n          <div class=\"card-head\"><h3>Alarms & Notifications</h3></div>\n          <div class=\"toggle-row\">\n            <div><div class=\"tr-txt\">Enable Alarms</div><div class=\"tr-sub\">Turns all reminder alarm sounds & banners on or off</div></div>\n            <button class=\"toggle ${config.alarmsEnabled?'on':''}\" onclick=\"toggleAlarmsEnabled()\"></button>\n          </div>\n          <p style=\"font-size:12.5px;color:var(--muted);margin:14px 0 10px;\">Alarms only fire while this page is open in a browser tab — there's no background server behind this file. Click \"🔔 Alerts\" in the top bar once to unlock sound playback and allow system notifications. These are the defaults used whenever a reminder is left on \"Default\" — each reminder can also be set to \"Customize\" with its own time, schedule, and ring duration.</p>\n          <div class=\"admin-actions\" style=\"margin-bottom:16px;\">\n            <button class=\"btn-outline\" onclick=\"enableAlerts()\">🔔 Enable Sound & Notifications</button>\n            <button class=\"btn-outline\" onclick=\"testAlarmSound()\">▶ Test Alarm Sound</button>\n          </div>\n          <div class=\"grid-2\">\n            <div>\n              <label style=\"display:block;font-size:12px;font-weight:700;color:var(--muted);text-transform:uppercase;margin-bottom:8px;\">Medicine Reminder Times</label>\n              <div class=\"field\"><label>Morning</label><input id=\"timeMorning\" type=\"time\" value=\"${config.medicineTimes.Morning}\"></div>\n              <div class=\"field\"><label>Afternoon</label><input id=\"timeAfternoon\" type=\"time\" value=\"${config.medicineTimes.Afternoon}\"></div>\n              <div class=\"field\"><label>Evening</label><input id=\"timeEvening\" type=\"time\" value=\"${config.medicineTimes.Evening}\"></div>\n            </div>\n            <div>\n              <label style=\"display:block;font-size:12px;font-weight:700;color:var(--muted);text-transform:uppercase;margin-bottom:8px;\">Expense & Grocery Alerts</label>\n              <div class=\"field\"><label>Daily Alert Time</label><input id=\"timeAlert\" type=\"time\" value=\"${config.alertTime}\"></div>\n              <div class=\"field\"><label>Remind Me For Expenses</label><div class=\"offset-check-row\">${offsetCheckboxesHtml(config.expenseOffsets, 'admin-exp-offset')}</div></div>\n              <div class=\"field\"><label>Remind Me For Groceries</label><div class=\"offset-check-row\">${offsetCheckboxesHtml(config.groceryOffsets, 'admin-groc-offset', 'Expiry day')}</div></div>\n            </div>\n          </div>\n          <div class=\"field\" style=\"max-width:340px;\"><label>Default Alarm Duration (seconds, 0 = ring until dismissed)</label><input id=\"adminAlarmDur\" type=\"number\" min=\"0\" value=\"${config.alarmDurationSec}\"></div>\n          <button class=\"btn-outline\" style=\"margin-top:6px;\" onclick=\"saveAlarmTimes()\">Save Alarm Settings</button>\n        </div>\n\n        <div class=\"card\">\n          <div class=\"card-head\"><h3>Security</h3></div>\n          <div class=\"field\"><label>New Admin Password</label><input id=\"adminNewPw\" type=\"password\" placeholder=\"Enter new password\"></div>\n          <div class=\"field\"><label>Confirm Password</label><input id=\"adminNewPw2\" type=\"password\" placeholder=\"Confirm new password\"></div>\n          <button class=\"btn-outline\" onclick=\"changeAdminPassword()\">Update Password</button>\n        </div>\n\n        <div class=\"card\" style=\"grid-column:1 / -1;\">\n          <div class=\"card-head\"><h3>Data Management</h3></div>\n          <div class=\"admin-actions\">\n            <button class=\"btn-outline\" onclick=\"exportAllData()\">⬇ Export All Data (JSON)</button>\n            <label class=\"btn-outline\" style=\"display:inline-flex;align-items:center;cursor:pointer;\">⬆ Import Data<input type=\"file\" accept=\"application/json\" style=\"display:none;\" onchange=\"importAllData(this.files[0])\"></label>\n          </div>\n          <div style=\"height:18px\"></div>\n          <div class=\"admin-danger\">\n            <h4>Danger Zone</h4>\n            <p style=\"font-size:13px;color:var(--muted);margin:0 0 10px 0;\">Permanently deletes all transactions, accounts, and reminders on this device.</p>\n            <button class=\"btn-danger-outline\" onclick=\"confirmResetAll()\">Delete All Data</button>\n          </div>\n        </div>\n\n      </div>\n    </div>\n  `;\n}\nfunction toggleRow(key,label,sub){\n  return `<div class=\"toggle-row\"><div><div class=\"tr-txt\">${label}</div><div class=\"tr-sub\">${sub}</div></div><button class=\"toggle ${config.features[key]?'on':''}\" onclick=\"toggleFeature('${key}')\"></button></div>`;\n}\nfunction toggleFeature(key){\n  config.features[key] = !config.features[key];\n  saveConfig();\n  renderAdmin();\n  if(key==='voiceAssistant') initVoiceAssistant();\n  showToast((config.features[key]?'Enabled: ':'Disabled: ')+key);\n}\nfunction setTheme(key){ config.theme=key; saveConfig(); applyTheme(key); renderAdmin(); showToast('Theme applied: '+THEMES[key].label); }\nfunction saveAppName(){ config.appName = document.getElementById('adminAppName').value.trim() || 'All-in-One Dashboard'; saveConfig(); document.getElementById('appNameLabel').textContent=config.appName; document.title=config.appName; showToast('App name saved'); }\nfunction saveCurrency(){ config.currency = document.getElementById('adminCurrency').value; saveConfig(); showToast('Default currency saved'); }\nfunction toggleAlarmsEnabled(){ config.alarmsEnabled = !config.alarmsEnabled; saveConfig(); renderAdmin(); showToast(config.alarmsEnabled?'Alarms enabled':'Alarms disabled'); if(!config.alarmsEnabled) hideAlarmBanner(); currentAlarm=null; }\nfunction saveAlarmTimes(){\n  config.medicineTimes = {\n    Morning: document.getElementById('timeMorning').value || '08:00',\n    Afternoon: document.getElementById('timeAfternoon').value || '13:00',\n    Evening: document.getElementById('timeEvening').value || '19:00'\n  };\n  config.alertTime = document.getElementById('timeAlert').value || '09:00';\n  const expOffsets = Array.from(document.querySelectorAll('.admin-exp-offset:checked')).map(c=>parseInt(c.value,10));\n  const grocOffsets = Array.from(document.querySelectorAll('.admin-groc-offset:checked')).map(c=>parseInt(c.value,10));\n  config.expenseOffsets = expOffsets.length ? expOffsets : DEFAULT_CONFIG.expenseOffsets.slice();\n  config.groceryOffsets = grocOffsets.length ? grocOffsets : DEFAULT_CONFIG.groceryOffsets.slice();\n  config.alarmDurationSec = parseInt(document.getElementById('adminAlarmDur').value,10) || 0;\n  saveConfig();\n  renderAdmin();\n  showToast('Alarm settings saved');\n}\nfunction testAlarmSound(){\n  unlockAudio();\n  const audio = document.getElementById('alarmAudio');\n  if(audio){ audio.currentTime=0; audio.play().catch(()=>showToast('Click anywhere on the page first, then try again')); setTimeout(()=>{ audio.pause(); audio.currentTime=0; }, 2500); }\n}\nfunction changeAdminPassword(){\n  const p1 = document.getElementById('adminNewPw').value;\n  const p2 = document.getElementById('adminNewPw2').value;\n  if(!p1 || p1.length<4){ showToast('Password must be at least 4 characters'); return; }\n  if(p1!==p2){ showToast('Passwords do not match'); return; }\n  config.adminPassword = p1; saveConfig();\n  document.getElementById('adminNewPw').value=''; document.getElementById('adminNewPw2').value='';\n  showToast('Admin password updated');\n}\nfunction exportAllData(){\n  const data = {config, financeState, expenseReminders, medReminders, groceryReminders, shoppingList, generalReminders, dismissedAlarms, exportedAt:new Date().toISOString()};\n  const blob = new Blob([JSON.stringify(data,null,2)], {type:'application/json'});\n  const url = URL.createObjectURL(blob);\n  const a = document.createElement('a'); a.href=url; a.download='all-in-one-dashboard-backup.json';\n  document.body.appendChild(a); a.click(); a.remove(); URL.revokeObjectURL(url);\n  showToast('Data exported');\n}\nfunction importAllData(file){\n  if(!file) return;\n  const reader = new FileReader();\n  reader.onload = (e)=>{\n    try{\n      const data = JSON.parse(e.target.result);\n      if(data.config) config = mergeConfig(data.config);\n      if(data.financeState){\n        financeState = data.financeState;\n        financeState.accounts = asArray(financeState.accounts);\n        if(financeState.accounts.length===0) financeState.accounts.push({id:uid(), name:'Cash', type:'Default', currency:config.currency, amount:0, icon:'💵', excluded:false});\n        financeState.transactions = asArray(financeState.transactions);\n        if(typeof financeState.budget!=='number' || isNaN(financeState.budget)) financeState.budget = 0;\n      }\n      if(data.expenseReminders) expenseReminders = asArray(data.expenseReminders);\n      if(data.medReminders) medReminders = asArray(data.medReminders);\n      if(data.groceryReminders) groceryReminders = asArray(data.groceryReminders);\n      if(data.shoppingList) shoppingList = asArray(data.shoppingList);\n      if(data.generalReminders) generalReminders = asArray(data.generalReminders);\n      if(data.dismissedAlarms) dismissedAlarms = asArray(data.dismissedAlarms);\n      saveConfig(); saveFinance(); saveExpRem(); saveMedRemState(); saveGroceryRem(); saveShoppingList(); saveGeneralRem(); saveDismissed();\n      applyTheme(config.theme);\n      renderAdmin();\n      showToast('Data imported successfully');\n    }catch(err){ showToast('Invalid file — import failed'); }\n  };\n  reader.readAsText(file);\n}\nfunction confirmResetAll(){\n  openModal(`\n    <div class=\"dialog-header\"><button class=\"txt-btn\" onclick=\"closeTopModal()\">Cancel</button><h2>Delete All Data</h2><div style=\"width:40px\"></div></div>\n    <div style=\"padding:20px;color:var(--muted);font-size:14px;\">This permanently deletes all transactions, accounts, reminders, and your shopping list on this device. This cannot be undone.</div>\n    <div class=\"two-btn\"><button class=\"btn-edit\" onclick=\"closeTopModal()\">Cancel</button><button class=\"btn-delete\" onclick=\"resetAllData()\">Delete Everything</button></div>\n  `);\n}\nfunction resetAllData(){\n  financeState = {accounts:[{id:uid(), name:'Cash', type:'Default', currency:config.currency, amount:0, icon:'💵', excluded:false}], transactions:[], budget:0};\n  expenseReminders = []; medReminders = []; groceryReminders = []; shoppingList = []; generalReminders = []; dismissedAlarms = []; snoozeMap = {};\n  saveFinance(); saveExpRem(); saveMedRemState(); saveGroceryRem(); saveShoppingList(); saveGeneralRem(); saveDismissed();\n  closeAllModals();\n  renderAdmin();\n  showToast('All data deleted');\n}\n\n/* ============================================================\n   MODAL SYSTEM (centered dialog)\n   ============================================================ */\nfunction openModal(html){\n  const root = document.getElementById('modal-root');\n  const wrap = document.createElement('div');\n  wrap.className = 'overlay';\n  wrap.innerHTML = `<div class=\"dialog\">${html}</div>`;\n  wrap.addEventListener('click', e=>{ if(e.target===wrap) closeModal(wrap); });\n  root.appendChild(wrap);\n  requestAnimationFrame(()=>wrap.classList.add('show'));\n  return wrap;\n}\nfunction closeModal(wrap){ wrap.classList.remove('show'); document.removeEventListener('keydown', kpKeyHandler); setTimeout(()=>wrap.remove(),180); }\nfunction closeTopModal(){ const root=document.getElementById('modal-root'); const last=root.lastElementChild; if(last) closeModal(last); }\nfunction closeAllModals(){ document.removeEventListener('keydown', kpKeyHandler); document.getElementById('modal-root').innerHTML=''; }\ndocument.addEventListener('keydown', e=>{ if(e.key==='Escape') closeTopModal(); });\n\n/* ============================================================\n   SUPABASE AUTH (Login / Sign up / Logout)\n   Uses Supabase Auth REST API so it works inside Android WebView.\n   ============================================================ */\nconst SUPABASE_URL = 'https://egbcgwqhwubiasiuxekr.supabase.co';\nconst SUPABASE_ANON_KEY = 'sb_publishable_vFw0kUPqUu6LO-yrVX7gmg_FGd4UefX';\nconst ADMIN_EMAILS = ['g.ramkumar3127@gmail.com','lakshmankumar586@gmail.com'].map(e=>e.toLowerCase());\nconst AUTH_STORAGE_KEY = 'ft_supabase_session';\n\nlet authMode = 'login';\nlet authState = { session:null, user:null, profile:null, isAdmin:false };\nlet appBooted = false;\n\nfunction authHeaders(extra){\n  return Object.assign({\n    'Content-Type':'application/json',\n    'apikey': SUPABASE_ANON_KEY,\n    'Authorization': 'Bearer ' + (authState.session && authState.session.access_token ? authState.session.access_token : SUPABASE_ANON_KEY)\n  }, extra||{});\n}\nfunction loadStoredSession(){\n  try{ return JSON.parse(localStorage.getItem(AUTH_STORAGE_KEY)||'null'); }catch(e){ return null; }\n}\nfunction saveStoredSession(session){\n  if(session) localStorage.setItem(AUTH_STORAGE_KEY, JSON.stringify(session));\n  else localStorage.removeItem(AUTH_STORAGE_KEY);\n}\nfunction setAuthMode(mode){\n  authMode = mode;\n  document.getElementById('tabLogin').classList.toggle('active', mode==='login');\n  document.getElementById('tabSignup').classList.toggle('active', mode==='signup');\n  document.getElementById('authNameField').style.display = mode==='signup' ? '' : 'none';\n  document.getElementById('authTitle').textContent = mode==='login' ? 'Welcome back' : 'Create account';\n  document.getElementById('authSub').textContent = mode==='login' ? 'Sign in to open your dashboard' : 'Sign up to start tracking money and reminders';\n  document.getElementById('authSubmitBtn').textContent = mode==='login' ? 'Login' : 'Create account';\n  document.getElementById('authError').classList.add('hidden');\n  document.getElementById('authInfo').classList.add('hidden');\n}\nfunction showAuthError(msg){\n  const el = document.getElementById('authError');\n  el.textContent = msg||'Something went wrong';\n  el.classList.remove('hidden');\n  document.getElementById('authInfo').classList.add('hidden');\n}\nfunction showAuthInfo(msg){\n  const el = document.getElementById('authInfo');\n  el.textContent = msg||'';\n  el.classList.remove('hidden');\n  document.getElementById('authError').classList.add('hidden');\n}\nasync function submitAuth(){\n  const email = (document.getElementById('authEmail').value||'').trim();\n  const password = document.getElementById('authPassword').value||'';\n  const fullName = (document.getElementById('authName').value||'').trim() || email.split('@')[0];\n  document.getElementById('authError').classList.add('hidden');\n  document.getElementById('authInfo').classList.add('hidden');\n  if(!email || !password){ showAuthError('Email and password are required.'); return; }\n  const btn = document.getElementById('authSubmitBtn');\n  btn.disabled = true; btn.textContent = 'Please wait…';\n  try{\n    if(authMode==='login'){\n      const res = await fetch(SUPABASE_URL + '/auth/v1/token?grant_type=password', {\n        method:'POST', headers:authHeaders(), body:JSON.stringify({email, password})\n      });\n      const data = await res.json();\n      if(!res.ok) throw new Error(data.error_description || data.msg || data.error || 'Login failed');\n      await applySession(data);\n      await bootAppIfReady();\n    } else {\n      if(password.length < 6) throw new Error('Password must be at least 6 characters.');\n      const res = await fetch(SUPABASE_URL + '/auth/v1/signup', {\n        method:'POST', headers:authHeaders(),\n        body:JSON.stringify({email, password, data:{full_name: fullName}})\n      });\n      const data = await res.json();\n      if(!res.ok) throw new Error(data.error_description || data.msg || data.error || 'Sign up failed');\n      if(data.access_token){\n        await applySession(data);\n        await bootAppIfReady();\n      } else {\n        setAuthMode('login');\n        showAuthInfo('Account created. If email confirmation is on, check your inbox, then log in.');\n      }\n    }\n  }catch(err){\n    showAuthError(err.message || String(err));\n  }finally{\n    btn.disabled = false;\n    btn.textContent = authMode==='login' ? 'Login' : 'Create account';\n  }\n}\nasync function applySession(session){\n  authState.session = session;\n  saveStoredSession(session);\n  const userRes = await fetch(SUPABASE_URL + '/auth/v1/user', { headers:authHeaders() });\n  const user = await userRes.json();\n  if(!userRes.ok) throw new Error(user.msg || user.error || 'Could not load user');\n  authState.user = user;\n  authState.profile = await fetchProfile(user.id);\n  const email = (user.email||'').toLowerCase();\n  authState.isAdmin = (authState.profile && authState.profile.role==='admin') || ADMIN_EMAILS.includes(email);\n  updateAuthChrome();\n}\nasync function fetchProfile(userId){\n  try{\n    const res = await fetch(SUPABASE_URL + '/rest/v1/profiles?id=eq.' + encodeURIComponent(userId) + '&select=id,email,full_name,role', {\n      headers: Object.assign(authHeaders(), { 'Accept':'application/json' })\n    });\n    if(!res.ok) return null;\n    const rows = await res.json();\n    return Array.isArray(rows) && rows[0] ? rows[0] : null;\n  }catch(e){ return null; }\n}\nfunction updateAuthChrome(){\n  const chip = document.getElementById('userChip');\n  const adminBtn = document.getElementById('adminBtn');\n  if(authState.user){\n    const label = (authState.profile && authState.profile.full_name) || authState.user.email || '';\n    chip.textContent = authState.isAdmin ? (label + ' · Admin') : label;\n    adminBtn.style.display = authState.isAdmin ? '' : 'none';\n  } else {\n    chip.textContent = '';\n    adminBtn.style.display = 'none';\n  }\n}\nfunction showAuthScreen(){\n  document.getElementById('auth-screen').classList.remove('hidden');\n  document.getElementById('topbar').style.display = 'none';\n  document.getElementById('app-root').style.display = 'none';\n  const fab = document.getElementById('voiceFab');\n  if(fab) fab.style.display = 'none';\n}\nfunction hideAuthScreen(){\n  document.getElementById('auth-screen').classList.add('hidden');\n  document.getElementById('topbar').style.display = '';\n  document.getElementById('app-root').style.display = '';\n  const fab = document.getElementById('voiceFab');\n  if(fab) fab.style.display = '';\n}\nasync function logoutAuth(){\n  try{\n    if(authState.session && authState.session.access_token){\n      await fetch(SUPABASE_URL + '/auth/v1/logout', { method:'POST', headers:authHeaders() });\n    }\n  }catch(e){}\n  authState = { session:null, user:null, profile:null, isAdmin:false };\n  adminAuthed = false;\n  saveStoredSession(null);\n  updateAuthChrome();\n  showAuthScreen();\n  setAuthMode('login');\n}\nasync function restoreAuthSession(){\n  const stored = loadStoredSession();\n  if(!stored || !stored.access_token) return false;\n  try{\n    await applySession(stored);\n    return true;\n  }catch(e){\n    saveStoredSession(null);\n    authState = { session:null, user:null, profile:null, isAdmin:false };\n    return false;\n  }\n}\nfunction bootAppCore(){\n  applyTheme(config.theme);\n  renderDashboard();\n  updateBellBtn();\n  startAlarmScheduler();\n  initVoiceAssistant();\n  updateAuthChrome();\n}\nasync function bootAppIfReady(){\n  if(!authState.user){ showAuthScreen(); return; }\n  hideAuthScreen();\n  if(!appBooted){\n    appBooted = true;\n    bootAppCore();\n  } else {\n    updateAuthChrome();\n  }\n}\n\n/* ============================================================\n   INIT\n   ============================================================ */\ntry{\n  showAuthScreen();\n  setAuthMode('login');\n  restoreAuthSession().then(ok=>{\n    if(ok) bootAppIfReady();\n    else showAuthScreen();\n  }).catch(()=>showAuthScreen());\n}catch(e){\n  console.error('Init error:', e);\n  showAuthScreen();\n  showAuthError((e && e.message) ? e.message : 'Startup error');\n}\n</script>\n</body>\n</html>\n";
